/// `__dom_append(parent, child)` → did it mutate? Returns `false` WITHOUT
/// mutating when `child` is a host-including inclusive ancestor of `parent`
/// (WHATWG DOM §4.2.3 pre-insertion validity); the prelude turns that into a
/// `HierarchyRequestError`. Folding the check into the append the prelude
/// already makes keeps the hot insertion path at ONE syscall — no separate
/// validity call — and the check itself is O(1) for the dominant case (a
/// freshly created leaf node, see `is_host_including_inclusive_ancestor`).
fn sys_append(_: &JsValue, args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let dom = page_dom(ctx);
    let mut d = dom.borrow_mut();
    if let (Some(p), Some(c)) = (arg_node(&d, args, 0), arg_node(&d, args, 1)) {
        if d.is_host_including_inclusive_ancestor(c, p) {
            return Ok(JsValue::from(false));
        }
        d.append(p, c);
    }
    Ok(JsValue::from(true))
}

/// `__dom_insert_before(parent, child, ref)` → did it mutate? Same pre-insertion
/// validity gate as `sys_append` (returns `false`, unmutated, on a cycle).
fn sys_insert_before(_: &JsValue, args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let dom = page_dom(ctx);
    let mut d = dom.borrow_mut();
    if let (Some(p), Some(c)) = (arg_node(&d, args, 0), arg_node(&d, args, 1)) {
        if d.is_host_including_inclusive_ancestor(c, p) {
            return Ok(JsValue::from(false));
        }
        let r = arg_node(&d, args, 2);
        d.insert_before(p, c, r);
    }
    Ok(JsValue::from(true))
}

fn sys_detach(_: &JsValue, args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let dom = page_dom(ctx);
    let mut d = dom.borrow_mut();
    if let Some(id) = arg_node(&d, args, 0) {
        d.detach(id);
    }
    Ok(JsValue::undefined())
}

fn sys_parent(_: &JsValue, args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let dom = page_dom(ctx);
    let d = dom.borrow();
    Ok(id_value(
        arg_node(&d, args, 0).and_then(|id| d.node(id).parent),
    ))
}

/// `__dom_contains(a, b)` → is `a` a STRICT ancestor of `b`? The subtree
/// match for MutationObserver: walking `b`'s parent chain here (one Rust
/// pointer walk) replaces a JS `parentNode` loop that would syscall+wrap per
/// hop — the trap #9 lesson (a body-rooted `subtree:true` observer tests this
/// on every mutation). Does not cross shadow boundaries (parent is null at a
/// shadow root), matching the default non-composed observation scope.
fn sys_contains(_: &JsValue, args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let dom = page_dom(ctx);
    let d = dom.borrow();
    let found = match (arg_node(&d, args, 0), arg_node(&d, args, 1)) {
        (Some(anc), Some(node)) => {
            let mut cur = d.node(node).parent;
            loop {
                match cur {
                    Some(p) if p == anc => break true,
                    Some(p) => cur = d.node(p).parent,
                    None => break false,
                }
            }
        }
        _ => false,
    };
    Ok(JsValue::from(found))
}

/// `__dom_set_hover(id | -1)` → move the cascade's live `:hover` chain to the
/// element (+ its composed ancestors), or clear it (-1 / stale id). Returns
/// whether the move can change the RENDER (`Dom::set_hover_chain` — the
/// affected-check), in which case it already marked the page dirty, so the
/// dispatch's normal dirty-check re-renders. Called by `trust.hover` after
/// the pointer/mouse event sequence: ONE hover command drives both halves.
fn sys_set_hover(_: &JsValue, args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let dom = page_dom(ctx);
    let target = args
        .first()
        .and_then(boa_engine::JsValue::as_number)
        .filter(|n| *n >= 0.0)
        .map(|n| n as usize);
    let affected = dom.borrow_mut().set_hover_chain(target);
    Ok(JsValue::from(affected))
}

