/// `(rootId, name)` → the composed-tree element ids (shadow-piercing, document
/// order) whose tag is `name`. Backs `customElements.define`'s catch-up upgrade
/// without the per-node JS tree walk it used to do.
fn sys_upgrade_candidates(_: &JsValue, args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let name = arg_str(args, 1, ctx).to_ascii_lowercase();
    let dom = page_dom(ctx);
    let ids = {
        let d = dom.borrow();
        match arg_node(&d, args, 0) {
            Some(root) => d.elements_by_tag_composed(root, &name),
            None => Vec::new(),
        }
    };
    Ok(ids_array(ids, ctx))
}

/// `(rootId)` → the composed-subtree element ids (root included, shadow-
/// piercing) whose tag is a custom-element name (contains a hyphen). Backs
/// `ceScan`'s insertion-time upgrade/connect pass without the per-node JS walk.
fn sys_ce_candidates(_: &JsValue, args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let dom = page_dom(ctx);
    let ids = {
        let d = dom.borrow();
        match arg_node(&d, args, 0) {
            Some(root) => d.custom_elements_composed(root),
            None => Vec::new(),
        }
    };
    Ok(ids_array(ids, ctx))
}

fn sys_clone(_: &JsValue, args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let dom = page_dom(ctx);
    let mut d = dom.borrow_mut();
    let deep = args.get(1).is_some_and(JsValue::to_boolean);
    Ok(id_value(
        arg_node(&d, args, 0).map(|id| d.clone_subtree(id, deep)),
    ))
}

fn sys_attach_shadow(_: &JsValue, args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let dom = page_dom(ctx);
    let mut d = dom.borrow_mut();
    Ok(id_value(
        arg_node(&d, args, 0).map(|id| d.attach_shadow(id)),
    ))
}

fn sys_shadow_root(_: &JsValue, args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let dom = page_dom(ctx);
    let d = dom.borrow();
    Ok(id_value(
        arg_node(&d, args, 0).and_then(|id| d.shadow_root(id)),
    ))
}

/// `__dom_adopt_styles(scope, cssText)`: the prelude pushes a scope's
/// joined adoptedStyleSheets text into the visibility cascade.
fn sys_adopt_styles(_: &JsValue, args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let css = arg_str(args, 1, ctx);
    let dom = page_dom(ctx);
    let mut d = dom.borrow_mut();
    if let Some(scope) = arg_node(&d, args, 0) {
        d.set_adopted_styles(scope, &css);
    }
    Ok(JsValue::undefined())
}

/// `__css_parse(text)` → the CSSOM rule tree as a JSON string (the prelude
/// `JSON.parse`s it into CSSStyleRule/CSSMediaRule/… for `<style>.sheet`).
/// Uses the same CSS tokenizing as the cascade, so what CSSOM reports and
/// what the cascade honors stay one source of truth.
fn sys_css_parse(_: &JsValue, args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let css = arg_str(args, 0, ctx);
    Ok(str_value(&crate::dom::parse_cssom_json(&css)))
}

/// `__css_supports_selector(selector)` → whether the selector engine can
/// parse it. Backs `CSS.supports("selector(…)")` — honest about the subset
/// we actually evaluate.
fn sys_css_supports_selector(
    _: &JsValue,
    args: &[JsValue],
    ctx: &mut Context,
) -> JsResult<JsValue> {
    let sel = arg_str(args, 0, ctx);
    Ok(JsValue::from(crate::dom::selector_parses(&sel)))
}

fn sys_template_content(_: &JsValue, args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let dom = page_dom(ctx);
    let d = dom.borrow();
    Ok(id_value(
        arg_node(&d, args, 0).map(|id| d.content_target(id)),
    ))
}

fn sys_doc_element(_: &JsValue, _: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let dom = page_dom(ctx);
    let d = dom.borrow();
    Ok(id_value(
        d.children(DOCUMENT)
            .into_iter()
            .find(|&c| d.tag_name(c) == Some("html")),
    ))
}

/// The `[[IsHTMLDDA]]` exotic object behind `document.all` (ECMAScript Annex
/// B.3.6). The web platform relies on its special semantics — falsy, `typeof
/// "undefined"`, and `== null`/`== undefined`, but a distinct object for `===`.
/// YouTube's `polymer_resin` XSS sanitizer is the case that needs it: its
/// pass-through guard is `if (value || value === document.all) return value`, so
/// without a real `document.all` an `undefined` binding value (e.g. a Polymer
/// `hidden="[[…]]"` whose source is undefined) matched the guard and got
/// replaced with the sentinel string `"zClosurez"` — silently hiding whole
/// subtrees (the YouTube search-results container). Only the engine can mint
/// this object; the prelude caches it on `document.all`.
fn sys_html_dda(_: &JsValue, _: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    Ok(boa_engine::JsObject::html_dda(ctx.intrinsics()).into())
}

/// `__url_parse(href, base|null)` → array of
/// [href, protocol, host, hostname, port, pathname, search, hash, origin,
/// username, password] or null — the workhorse behind both the URL class and
/// absolutized href/src getters.
fn sys_url_parse(_: &JsValue, args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let href = arg_str(args, 0, ctx);
    let base = args
        .get(1)
        .filter(|v| !v.is_null_or_undefined())
        .map(|_| arg_str(args, 1, ctx));
    let parsed = match base {
        Some(b) => url::Url::parse(&b).and_then(|b| b.join(&href)),
        None => url::Url::parse(&href),
    };
    let Ok(u) = parsed else {
        return Ok(JsValue::null());
    };
    Ok(url_parts_array(&u, ctx).into())
}

/// Serialize a parsed URL into the 11-part array the prelude `URL` class reads:
/// `[href, protocol, host, hostname, port, pathname, search, hash, origin,
/// username, password]`. The single source of truth for both `__url_parse` and
/// `__url_set`, so a URL built by the constructor and one mutated by a setter
/// serialize identically.
fn url_parts_array(u: &url::Url, ctx: &mut Context) -> JsArray {
    let host = match (u.host_str(), u.port()) {
        (Some(h), Some(p)) => format!("{h}:{p}"),
        (Some(h), None) => h.to_string(),
        _ => String::new(),
    };
    let parts = [
        u.as_str().to_string(),
        format!("{}:", u.scheme()),
        host,
        u.host_str().unwrap_or("").to_string(),
        u.port().map(|p| p.to_string()).unwrap_or_default(),
        u.path().to_string(),
        u.query().map(|q| format!("?{q}")).unwrap_or_default(),
        u.fragment().map(|f| format!("#{f}")).unwrap_or_default(),
        u.origin().ascii_serialization(),
        u.username().to_string(),
        u.password().unwrap_or("").to_string(),
    ];
    let vals: Vec<JsValue> = parts.iter().map(|p| str_value(p)).collect();
    JsArray::from_iter(vals, ctx)
}

/// `__url_set(href, which, value)` — apply a WHATWG URL component setter to
/// `href` and return the re-serialized 11-part array (same shape as
/// `__url_parse`), so a live `URL` object reflows `href`/all components when any
/// one is assigned. Delegates to the `url` crate's setters (which implement the
/// WHATWG "URL setter" algorithms), so `u.pathname = "c%20d"` re-serializes
/// `href` to `http://a/c%20d` exactly as a browser does — the check the
/// webcomponents/core-js URL polyfills gate on before force-replacing native
/// URL. A setter whose basic-parse fails is a spec no-op (the URL is left
/// unchanged); we still return the parts so the JS setter is a silent no-op too.
/// Returns null only when `href` itself doesn't parse (can't happen from a live
/// URL) or `which` is unknown.
fn sys_url_set(_: &JsValue, args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let href = arg_str(args, 0, ctx);
    let which = arg_str(args, 1, ctx);
    let value = arg_str(args, 2, ctx);
    let Ok(mut u) = url::Url::parse(&href) else {
        return Ok(JsValue::null());
    };
    match which.as_str() {
        // The scheme setter's value may or may not carry the trailing ':'.
        "protocol" => {
            let s = value.strip_suffix(':').unwrap_or(&value);
            let _ = u.set_scheme(s);
        }
        "username" => {
            let _ = u.set_username(&value);
        }
        "password" => {
            let _ = u.set_password(if value.is_empty() { None } else { Some(&value) });
        }
        // `.host` carries an optional `:port`; `.hostname` never does. `set_host`
        // parses the "host[:port]" form, so route hostname through it after
        // stripping any port the caller wrongly included (keeping the existing
        // port), and host directly.
        "host" => {
            let _ = u.set_host(if value.is_empty() { None } else { Some(&value) });
        }
        "hostname" => {
            let bare = host_without_port(&value);
            let _ = u.set_host(if bare.is_empty() { None } else { Some(bare) });
        }
        "port" => {
            if value.is_empty() {
                let _ = u.set_port(None);
            } else if let Ok(p) = value.parse::<u16>() {
                let _ = u.set_port(Some(p));
            }
        }
        "pathname" => u.set_path(&value),
        // `.search`/`.hash` accept the value with or without the leading `?`/`#`;
        // an empty value clears the component.
        "search" => {
            let q = value.strip_prefix('?').unwrap_or(&value);
            u.set_query(if q.is_empty() { None } else { Some(q) });
        }
        "hash" => {
            let f = value.strip_prefix('#').unwrap_or(&value);
            u.set_fragment(if f.is_empty() { None } else { Some(f) });
        }
        _ => return Ok(JsValue::null()),
    }
    Ok(url_parts_array(&u, ctx).into())
}

/// The host portion of a `host[:port]` string, respecting IPv6 `[..]` brackets
/// (a `:` inside brackets is part of the address, not a port separator).
fn host_without_port(s: &str) -> &str {
    if let Some(rest) = s.strip_prefix('[') {
        // IPv6 literal: the host ends at the closing bracket.
        return match rest.find(']') {
            Some(i) => &s[..i + 2],
            None => s,
        };
    }
    match s.rfind(':') {
        Some(i) => &s[..i],
        None => s,
    }
}

/// Run the synchronous half of a page fetch: resolve against the page
/// URL, enforce the scheme/private-space checks, the per-page cap, and
/// the budget, count it, and hand back what's needed to do the request.
/// None = blocked, capped, past budget, or no net grant at all. Touches
/// the network not at all — the actual request is awaited by the caller.
fn page_net_prepare(
    ctx: &mut Context,
    target: &str,
    method: String,
    body: Option<(String, Vec<u8>)>,
    headers: Vec<(String, String)>,
) -> Option<(tokio::runtime::Handle, crate::http::Request)> {
    let host = ctx.realm().host_defined();
    let net = host.get::<PageNet>()?;
    let resolved = net.page.join(target).ok()?;
    if !matches!(resolved.scheme(), "http" | "https")
        || !crate::http::subresource_allowed(&net.page, &resolved)
        || net.fetched.get() >= MAX_PAGE_FETCHES
        || net.budget.exhausted()
    {
        return None;
    }
    net.fetched.set(net.fetched.get() + 1);
    // A fetch fired during an interactive dispatch extends the tight (1s,
    // compute-sized) dispatch deadline up to the network-inclusive wall budget,
    // so a slow wire — an LLM streaming a reply — can finish instead of being
    // cancelled. The job-drainer re-reads the deadline, so this takes effect
    // mid-drain. Load fetches don't extend (the load already runs on the wall
    // budget), so this never loosens a load.
    if net.dispatch.get() {
        net.budget.extend_at_least(DISPATCH_NET_GRACE);
    }
    let mut request = crate::http::Request {
        method,
        url: resolved,
        body,
        headers,
    };
    // A document-initiated request carries the page's Referer (browser
    // default policy) unless the page set one itself.
    crate::http::set_referrer(&mut request, &net.page);
    Some((net.handle.clone(), request))
}

/// Synchronous fetch — for the one caller that genuinely must block:
/// legacy synchronous XHR (`open(..., false)`). Blocks the page thread
/// while the app runtime does the request. Everything else goes through
/// the async path so requests overlap.
fn page_net_fetch(
    ctx: &mut Context,
    target: &str,
    method: String,
    body: Option<(String, Vec<u8>)>,
    headers: Vec<(String, String)>,
) -> Option<crate::http::Response> {
    let (handle, request) = page_net_prepare(ctx, target, method, body, headers)?;
    phase(&format!("src: PAGE-SYNC {}", request.url));
    // A synchronous fetch must block the page thread, but it can be reached from
    // INSIDE the job loop — an iframe-hydrate sweep or a sync XHR running as a
    // microtask — which is itself driven by `handle.block_on`. Nesting a second
    // `block_on` there aborts ("Cannot start a runtime from within a runtime"),
    // killing the engine. So drive the request on the runtime via `spawn` and
    // wait on a plain channel: the same no-nested-`block_on` shape that
    // `PageCache::block_on_fetch` uses. Outside the job loop (a top-level sync
    // XHR) this behaves identically — the spawned task runs on the app runtime
    // and the page thread blocks on the channel until it lands.
    let (tx, rx) = std::sync::mpsc::channel();
    handle.spawn(async move {
        let _ = tx.send(crate::http::fetch(&request).await);
    });
    rx.recv().ok().and_then(|r| r.ok())
}

/// Get a module body for `resolved` THROUGH the shared cache, BLOCKING
/// the page thread. This is the ENTRY-module bootstrap path only: it runs
/// once, before the job loop, where there are no sibling jobs to overlap
/// with — so blocking here costs nothing. The in-graph loader uses
/// `module_fetch` + `.await` instead (concurrent). A hit — the initial
/// prefetch seeded it, or a speculative prefetch is already fetching it —
/// skips the network entirely (and costs no cap). A miss starts a fresh,
/// cap-/`subresource_allowed`-gated request.
fn load_module_body(
    ctx: &mut Context,
    cache: &std::sync::Arc<crate::http::PageCache>,
    resolved: &url::Url,
) -> Option<std::sync::Arc<crate::http::CachedResp>> {
    if let Some(f) = cache.peek(resolved) {
        // Ready (seeded) needs no runtime; in-flight is driven via the
        // handle. No-net pages only ever have ready entries.
        let handle = ctx
            .realm()
            .host_defined()
            .get::<PageNet>()
            .map(|n| n.handle.clone());
        return crate::http::PageCache::block_on_fetch(handle.as_ref(), f);
    }
    let (handle, request) = page_net_prepare(
        ctx,
        resolved.as_str(),
        String::from("GET"),
        None,
        Vec::new(),
    )?;
    let f = cache.fetch(&handle, request.url);
    crate::http::PageCache::block_on_fetch(Some(&handle), f)
}

/// The shared fetch for a module url, acquired under a brief context
/// borrow so the in-graph loader can `.await` it WITHOUT holding the
/// borrow — letting the spec's concurrently-enqueued sibling imports
/// overlap. A cache hit (seeded / speculatively prefetched / already in
/// flight) joins the existing request; a miss starts a fresh,
/// cap-/`subresource_allowed`-gated one. Returns the `Shared` future to
/// await; `None` only when a brand-new fetch is blocked (cap/private).
fn module_fetch(
    ctx: &mut Context,
    cache: &std::sync::Arc<crate::http::PageCache>,
    resolved: &url::Url,
) -> Option<crate::http::SharedFetch> {
    if let Some(f) = cache.peek(resolved) {
        return Some(f);
    }
    let (handle, request) = page_net_prepare(
        ctx,
        resolved.as_str(),
        String::from("GET"),
        None,
        Vec::new(),
    )?;
    Some(cache.fetch(&handle, request.url))
}

/// `__http_fetch(url, method, body|null, content_type|null)` →
/// `[status, content_type, body_text]` or null (blocked/failed/no net).
/// Synchronous from the page's view; the request runs on the tokio
/// runtime while the JS thread blocks. The one blocking caller is legacy
/// synchronous XHR — async fetch/XHR go through `sys_http_fetch_async`.
fn sys_http_fetch(_: &JsValue, args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let (url_arg, method, body, headers) = fetch_args(args, ctx);
    Ok(match page_net_fetch(ctx, &url_arg, method, body, headers) {
        Some(resp) => response_to_array(&resp, ctx),
        None => JsValue::null(),
    })
}

/// `__http_fetch_async(url, method, body|null, content_type|null)` →
/// a Promise resolving to `[status, content_type, body_text]`, or null
/// (blocked/capped/failed/no net). The request is dispatched as a Boa
/// async job: it fires immediately and is awaited on the tokio runtime
/// WITHOUT blocking the JS thread, so many in-flight requests overlap
/// (Boa's job executor polls them concurrently). This is the whole
/// reason `Promise.all([fetch(a), fetch(b)])` now runs in parallel.
/// If this `fetch()` should run as a BACKGROUND task — past load, on the
/// resident actor (`net.dispatch` set AND a `fetch_events` sender present) —
/// allocate its promise id and hand back the channel + runtime to spawn the
/// request off the JS thread. `None` ⇒ run it as an awaited Boa job (during
/// load, or in the one-shot `transform`, where the result must be in hand
/// before serialize).
fn bg_fetch_ctx(ctx: &Context) -> Option<(usize, FetchSender, tokio::runtime::Handle)> {
    let host = ctx.realm().host_defined();
    let net = host.get::<PageNet>()?;
    if !net.dispatch.get() {
        return None;
    }
    let tx = net.fetch_events.clone()?;
    let id = net.next_fetch_id.get();
    net.next_fetch_id.set(id + 1);
    Some((id, tx, net.handle.clone()))
}

fn sys_http_fetch_async(_: &JsValue, args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let (url_arg, method, body, headers) = fetch_args(args, ctx);
    // BACKGROUND path: past load, on the resident actor, the request runs OFF
    // the JS thread, so a slow wire (an LLM reply) can't freeze the live engine
    // — the dispatch returns immediately and the result posts back as
    // `(id, result)`, which the actor settles + re-renders (see
    // `dispatch_fetch_done`). The promise is created by `__trust.bgFetch(id)`,
    // resolved later by `settleFetch`.
    if let Some((id, tx, handle)) = bg_fetch_ctx(ctx) {
        // GET dedup: join the cache's single in-flight/done request (no cap spend).
        if method == "GET"
            && body.is_none()
            && let Some(shared) = peek_page_cache(ctx, &url_arg)
        {
            phase(&format!("src: PAGE-CACHE-BG {url_arg}"));
            handle.spawn(async move {
                let out = shared.await.ok().map(|c| {
                    (
                        c.status,
                        c.content_type.clone(),
                        c.body.clone(),
                        headers_to_blob(&c.headers),
                    )
                });
                let _ = tx.send((id, out)).await;
            });
            return ctx.eval(Source::from_bytes(
                format!("__trust.bgFetch({id})").as_bytes(),
            ));
        }
        match page_net_prepare(ctx, &url_arg, method, body, headers) {
            // Blocked/capped/no net: resolve null NOW (a settled promise),
            // matching the awaited path's contract.
            None => {
                let p = ctx.eval(Source::from_bytes(
                    format!("__trust.bgFetch({id})").as_bytes(),
                ))?;
                settle_bg_fetch(ctx, id, JsValue::null());
                return Ok(p);
            }
            Some((_handle, request)) => {
                phase(&format!("src: PAGE-ASYNC-BG {}", request.url));
                handle.spawn(async move {
                    let out = crate::http::fetch(&request).await.ok().map(|r| {
                        (
                            r.status,
                            r.content_type,
                            r.body,
                            headers_to_blob(&r.headers),
                        )
                    });
                    let _ = tx.send((id, out)).await;
                });
                return ctx.eval(Source::from_bytes(
                    format!("__trust.bgFetch({id})").as_bytes(),
                ));
            }
        }
    }
    let (promise, resolvers) = JsPromise::new_pending(ctx);
    // GET dedup: a chunk the page re-`fetch()`es (the bundler warms up its
    // own modulepreloads this way) JOINS the cache's single request for
    // it instead of re-downloading. No new request, no cap spend. Misses
    // — arbitrary API GETs — fall through to a normal, uncached fetch.
    if method == "GET"
        && body.is_none()
        && let Some(shared) = peek_page_cache(ctx, &url_arg)
    {
        phase(&format!("src: PAGE-CACHE {url_arg}"));
        let realm = ctx.realm().clone();
        let job = NativeAsyncJob::with_realm(
            async move |ctx_cell: &RefCell<&mut Context>| {
                let outcome = shared.await;
                let mut guard = ctx_cell.borrow_mut();
                let value = match outcome {
                    Ok(c) => cached_to_array(&c, &mut guard),
                    Err(_) => JsValue::null(),
                };
                let _ = resolvers
                    .resolve
                    .call(&JsValue::undefined(), &[value], &mut guard);
                Ok(JsValue::undefined())
            },
            realm,
        );
        ctx.enqueue_job(job.into());
        return Ok(promise.into());
    }
    match page_net_prepare(ctx, &url_arg, method, body, headers) {
        None => {
            // Blocked/capped/no net: settle to null now, matching the
            // sync syscall's contract (the prelude turns null into a
            // rejected fetch / failed XHR).
            let _ = resolvers
                .resolve
                .call(&JsValue::undefined(), &[JsValue::null()], ctx);
        }
        Some((_handle, request)) => {
            phase(&format!("src: PAGE-ASYNC {}", request.url));
            let realm = ctx.realm().clone();
            let job = NativeAsyncJob::with_realm(
                async move |ctx_cell: &RefCell<&mut Context>| {
                    // Await the request WITHOUT borrowing the context —
                    // holding the borrow across the await would serialize
                    // every fetch again. The executor polls all of these
                    // concurrently; we touch the context only to settle
                    // the promise once the bytes are in.
                    let result = crate::http::fetch(&request).await;
                    let mut guard = ctx_cell.borrow_mut();
                    let value = match result {
                        Ok(resp) => response_to_array(&resp, &mut guard),
                        Err(_) => JsValue::null(),
                    };
                    let _ = resolvers
                        .resolve
                        .call(&JsValue::undefined(), &[value], &mut guard);
                    Ok(JsValue::undefined())
                },
                realm,
            );
            ctx.enqueue_job(job.into());
        }
    }
    Ok(promise.into())
}

/// `__dom_popover(nodeId, open)` — set/clear an element's popover SHOWING
/// state (HTML §the popover attribute). The prelude's `showPopover`/
/// `hidePopover` call it after the (cancelable) `beforetoggle` fires; the
/// arena's UA hide rule and `:popover-open` matching read it, so an open
/// popover renders and a closed one drops from layout.
fn sys_dom_popover(_: &JsValue, args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let open = args.get(1).is_some_and(JsValue::to_boolean);
    let dom = page_dom(ctx);
    let mut d = dom.borrow_mut();
    if let Some(id) = arg_node(&d, args, 0) {
        d.set_popover_open(id, open);
    }
    Ok(JsValue::undefined())
}

/// `__blob_mirror(url, bytes, type)` — mirror a freshly minted `blob:` URL's
/// bytes into the Rust-side `BlobMap` so the app's image pipeline can decode
/// an `<img src="blob:…">` (the authoritative store stays in the JS realm —
/// see `PageBlobs`). `bytes` is a latin1 byte string, like every binary
/// syscall argument. No-op without a `PageBlobs` host (workers).
fn sys_blob_mirror(_: &JsValue, args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let url = arg_str(args, 0, ctx);
    let bytes = args
        .get(1)
        .map(|v| arg_bytes_latin1(v, ctx))
        .unwrap_or_default();
    let mime = arg_str(args, 2, ctx);
    if !url.is_empty()
        && let Some(blobs) = ctx.realm().host_defined().get::<PageBlobs>()
    {
        blobs.0.lock().unwrap().insert(url, (bytes, mime));
    }
    Ok(JsValue::undefined())
}

/// `__ws_open(url, protocols)` → a socket id (>0), or -1 if WebSockets aren't
/// available here / the URL is bad / the target is blocked. Spawns the
/// connection task (`ws::connect`); inbound frames + open/close arrive as
/// `PageCmd::Ws`. The page's bundled socket.io-client runs the protocol on top.
fn sys_ws_open(_: &JsValue, args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let url_arg = match args.first() {
        Some(v) => v.to_string(ctx)?.to_std_string_lossy(),
        None => return Ok(JsValue::new(-1)),
    };
    let host = ctx.realm().host_defined();
    let Some(wsh) = host.get::<PageWs>() else {
        return Ok(JsValue::new(-1)); // no-net page / one-shot transform
    };
    let Ok(resolved) = wsh.page.join(&url_arg) else {
        return Ok(JsValue::new(-1));
    };
    if !matches!(resolved.scheme(), "ws" | "wss") {
        return Ok(JsValue::new(-1));
    }
    // Same private-address-pivot guard as fetch, with ws(s) mapped to http(s).
    let mut http_equiv = resolved.clone();
    let _ = http_equiv.set_scheme(if resolved.scheme() == "wss" {
        "https"
    } else {
        "http"
    });
    if !crate::http::subresource_allowed(&wsh.page, &http_equiv) {
        return Ok(JsValue::new(-1));
    }
    let id = wsh.next_id.get();
    wsh.next_id.set(id + 1);
    let origin = wsh.page.origin().ascii_serialization();
    let cookie = {
        let c = crate::http::cookies_for_request(&http_equiv);
        (!c.is_empty()).then_some(c)
    };
    let out_tx = crate::ws::connect(
        resolved,
        origin,
        cookie,
        &wsh.handle,
        id,
        wsh.events.clone(),
    );
    wsh.sockets.borrow_mut().insert(id, out_tx);
    Ok(JsValue::new(id as i32))
}

/// `__ws_send(id, data, isBinary)` — queue a message on a socket. `data` is a
/// string: UTF-8 text, or (isBinary) a latin1 byte string (each char a byte).
fn sys_ws_send(_: &JsValue, args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let id = args.first().map_or(Ok(-1.0), |v| v.to_number(ctx))? as i64;
    let data = match args.get(1) {
        Some(v) => v.to_string(ctx)?.to_std_string_lossy(),
        None => String::new(),
    };
    let is_binary = args.get(2).is_some_and(JsValue::to_boolean);
    let host = ctx.realm().host_defined();
    let Some(wsh) = host.get::<PageWs>() else {
        return Ok(JsValue::new(false));
    };
    if id < 0 {
        return Ok(JsValue::new(false));
    }
    if let Some(tx) = wsh.sockets.borrow().get(&(id as usize)) {
        let msg = if is_binary {
            crate::ws::WsOut::Binary(data.chars().map(|c| c as u8).collect())
        } else {
            crate::ws::WsOut::Text(data)
        };
        // Non-blocking: the channel is generous; chat sends are low-rate.
        let _ = tx.try_send(msg);
        return Ok(JsValue::new(true));
    }
    Ok(JsValue::new(false))
}

/// `__ws_close(id, code, reason)` — close a socket.
fn sys_ws_close(_: &JsValue, args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let id = args.first().map_or(Ok(-1.0), |v| v.to_number(ctx))? as i64;
    let code = args.get(1).map_or(Ok(1000.0), |v| v.to_number(ctx))? as u16;
    let reason = match args.get(2) {
        Some(v) if !v.is_null_or_undefined() => v.to_string(ctx)?.to_std_string_lossy(),
        _ => String::new(),
    };
    let host = ctx.realm().host_defined();
    let Some(wsh) = host.get::<PageWs>() else {
        return Ok(JsValue::undefined());
    };
    if id >= 0
        && let Some(tx) = wsh.sockets.borrow().get(&(id as usize))
    {
        let _ = tx.try_send(crate::ws::WsOut::Close(code, reason));
    }
    Ok(JsValue::undefined())
}

// ---- Web Workers ------------------------------------------------------
//
// The page side. `new Worker(url)` calls `__worker_spawn`; `postMessage`/
// `terminate` call `__worker_post`/`__worker_terminate`. A worker's own
// `self.postMessage`/`close` (running on the worker thread) call
// `__worker_self_post`/`__worker_self_close` against its `WorkerSelf` host.

/// `__worker_spawn(scriptURL, type, name)` → a worker id (>0), or -1 if workers
/// aren't available here (no-net / one-shot transform), the URL is bad/blocked,
/// or the per-page cap is reached. Spawns a dedicated `trust-worker-N` thread.
fn sys_worker_spawn(_: &JsValue, args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let url_arg = match args.first() {
        Some(v) => v.to_string(ctx)?.to_std_string_lossy(),
        None => return Ok(JsValue::new(-1)),
    };
    let kind = match args.get(1).map(|v| v.to_string(ctx)) {
        Some(Ok(s)) if s.to_std_string_lossy() == "module" => WorkerKind::Module,
        _ => WorkerKind::Classic,
    };
    let name = match args.get(2) {
        Some(v) if !v.is_null_or_undefined() => v.to_string(ctx)?.to_std_string_lossy(),
        _ => String::new(),
    };
    let host = ctx.realm().host_defined();
    let Some(workers) = host.get::<PageWorkers>() else {
        return Ok(JsValue::new(-1)); // no-net page / one-shot transform / nested worker
    };
    let Ok(resolved) = workers.page.join(&url_arg) else {
        return Ok(JsValue::new(-1));
    };
    if !matches!(resolved.scheme(), "http" | "https") {
        return Ok(JsValue::new(-1)); // blob:/data: worker scripts not supported in v1
    }
    if !crate::http::subresource_allowed(&workers.page, &resolved) {
        return Ok(JsValue::new(-1)); // SSRF guard, same as fetch
    }
    if workers.workers.borrow().len() >= MAX_WORKERS {
        return Ok(JsValue::new(-1));
    }
    let id = workers.next_id.get();
    workers.next_id.set(id + 1);
    let (ctl_tx, ctl_rx) = tokio::sync::mpsc::channel::<WorkerCtl>(64);
    let handle = workers.handle.clone();
    let to_page = workers.events.clone();
    // The worker runs on its OWN 64MB-stack OS thread (Boa's parser recurses on
    // the native stack; same reason the page thread is wide). Named `trust-*` so
    // the panic hook swallows a Boa VM panic into a graceful per-worker degrade.
    let spawned = std::thread::Builder::new()
        .name(format!("trust-worker-{id}"))
        .stack_size(PAGE_STACK)
        .spawn(move || run_worker(id, resolved, kind, name, handle, to_page, ctl_rx));
    if spawned.is_err() {
        return Ok(JsValue::new(-1));
    }
    workers
        .workers
        .borrow_mut()
        .insert(id, WorkerHandle { ctl: ctl_tx });
    Ok(JsValue::new(id as i32))
}

/// `__worker_post(id, serialized)` — deliver a structured-clone wire string to a
/// worker as a `message`. Non-blocking (the channel is generous).
fn sys_worker_post(_: &JsValue, args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let id = args.first().map_or(Ok(-1.0), |v| v.to_number(ctx))? as i64;
    let data = match args.get(1) {
        Some(v) => v.to_string(ctx)?.to_std_string_lossy(),
        None => String::new(),
    };
    let host = ctx.realm().host_defined();
    let Some(workers) = host.get::<PageWorkers>() else {
        return Ok(JsValue::new(false));
    };
    if id >= 0
        && let Some(w) = workers.workers.borrow().get(&(id as usize))
    {
        let _ = w.ctl.try_send(WorkerCtl::Message(data));
        return Ok(JsValue::new(true));
    }
    Ok(JsValue::new(false))
}

/// `__worker_terminate(id)` — stop a worker. Removing its handle drops the
/// control sender, which closes the worker's command channel; the worker's loop
/// sees `None` and exits (a `Terminate` is also sent so it stops promptly even
/// mid-park). Idempotent.
fn sys_worker_terminate(_: &JsValue, args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let id = args.first().map_or(Ok(-1.0), |v| v.to_number(ctx))? as i64;
    let host = ctx.realm().host_defined();
    let Some(workers) = host.get::<PageWorkers>() else {
        return Ok(JsValue::undefined());
    };
    if id >= 0
        && let Some(w) = workers.workers.borrow_mut().remove(&(id as usize))
    {
        let _ = w.ctl.try_send(WorkerCtl::Terminate);
    }
    Ok(JsValue::undefined())
}

/// `__worker_self_post(serialized)` — a worker posting a message back to its
/// page (`self.postMessage`). Runs on the worker thread, against its own
/// `WorkerSelf` host. No-op on the page context (no `WorkerSelf`).
fn sys_worker_self_post(_: &JsValue, args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let data = match args.first() {
        Some(v) => v.to_string(ctx)?.to_std_string_lossy(),
        None => String::new(),
    };
    let host = ctx.realm().host_defined();
    if let Some(slf) = host.get::<WorkerSelf>() {
        let _ = slf.to_page.try_send((slf.id, WorkerOut::Message(data)));
    }
    Ok(JsValue::undefined())
}

/// `__worker_self_close()` — a worker requesting its own shutdown (`self.close`).
/// Sets the `closed` flag; the worker's event loop checks it after the current
/// turn and exits.
fn sys_worker_self_close(_: &JsValue, _args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let host = ctx.realm().host_defined();
    if let Some(slf) = host.get::<WorkerSelf>() {
        slf.closed.set(true);
    }
    Ok(JsValue::undefined())
}

// ============================ WebAssembly =============================
// The `WebAssembly.*` JS API (js-api/web-api specs) over the pure-Rust `wasmi`
// interpreter. The platform surface itself is PRELUDE JS (the `WebAssembly`
// namespace + the five classes + the three error subclasses); these syscalls
// are the integer boundary. wasmi work is wrapped in `catch_unwind` because
// wasmi `panic!`s on the unsupported exception-handling proposal — a panic must
// degrade to a clean error, never unwind through Boa as an abort.

/// `__wasm_validate(arrayBuffer)` → boolean. Decodes + validates without
/// keeping the module (js-api `validate`).
fn sys_wasm_validate(_: &JsValue, args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let Some(bytes) = arg_wasm_bytes(args, 0) else {
        return Ok(JsValue::from(false));
    };
    let host = ctx.realm().host_defined();
    let ok = host
        .get::<PageWasm>()
        .map(|pw| {
            pw.with(|st| {
                let engine = st.engine.clone();
                std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
                    wasmi::Module::validate(&engine, &bytes).is_ok()
                }))
                .unwrap_or(false)
            })
        })
        .unwrap_or(false);
    Ok(JsValue::from(ok))
}

/// `__wasm_compile(arrayBuffer)` → a module id (Number ≥ 0) on success, or an
/// error message (String) the prelude turns into a `WebAssembly.CompileError`
/// (js-api `Module` decode/validate).
fn sys_wasm_compile(_: &JsValue, args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let Some(bytes) = arg_wasm_bytes(args, 0) else {
        return Ok(str_value("WebAssembly: expected a BufferSource"));
    };
    let host = ctx.realm().host_defined();
    let Some(pw) = host.get::<PageWasm>() else {
        return Ok(str_value("WebAssembly is unavailable on this page"));
    };
    Ok(pw.with(|st| {
        let engine = st.engine.clone();
        match std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
            wasmi::Module::new(&engine, &bytes)
        })) {
            Ok(Ok(module)) => {
                let id = st.modules.len();
                st.modules.push(module);
                JsValue::from(id as f64)
            }
            Ok(Err(e)) => str_value(&format!("{e}")),
            Err(_) => str_value("WebAssembly module uses an unsupported feature"),
        }
    }))
}

/// `__wasm_module_imports(moduleId)` → flat array `[module, name, kind, …]`;
/// the prelude reshapes it into `{module, name, kind}` descriptors (js-api
/// `Module.imports`). `kind` ∈ function|table|memory|global.
fn sys_wasm_module_imports(_: &JsValue, args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let out: Vec<JsValue> = {
        let host = ctx.realm().host_defined();
        host.get::<PageWasm>()
            .map(|pw| {
                pw.with(|st| {
                    let mut v = Vec::new();
                    if let Some(m) = arg_id(args, 0).and_then(|id| st.modules.get(id)) {
                        for imp in m.imports() {
                            v.push(str_value(imp.module()));
                            v.push(str_value(imp.name()));
                            v.push(str_value(wasm_extern_kind(imp.ty())));
                        }
                    }
                    v
                })
            })
            .unwrap_or_default()
    };
    Ok(JsArray::from_iter(out, ctx).into())
}

/// `__wasm_module_exports(moduleId)` → flat array `[name, kind, …]`; the prelude
/// reshapes it into `{name, kind}` descriptors (js-api `Module.exports`).
fn sys_wasm_module_exports(_: &JsValue, args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let out: Vec<JsValue> = {
        let host = ctx.realm().host_defined();
        host.get::<PageWasm>()
            .map(|pw| {
                pw.with(|st| {
                    let mut v = Vec::new();
                    if let Some(m) = arg_id(args, 0).and_then(|id| st.modules.get(id)) {
                        for exp in m.exports() {
                            v.push(str_value(exp.name()));
                            v.push(str_value(wasm_extern_kind(exp.ty())));
                        }
                    }
                    v
                })
            })
            .unwrap_or_default()
    };
    Ok(JsArray::from_iter(out, ctx).into())
}

/// `__wasm_module_custom_sections(moduleId, name)` → array of `ArrayBuffer`
/// copies of every custom section whose name === `name`, in module order
/// (js-api `Module.customSections`).
fn sys_wasm_module_custom_sections(
    _: &JsValue,
    args: &[JsValue],
    ctx: &mut Context,
) -> JsResult<JsValue> {
    let want = arg_str(args, 1, ctx);
    let datas: Vec<Vec<u8>> = {
        let host = ctx.realm().host_defined();
        host.get::<PageWasm>()
            .map(|pw| {
                pw.with(|st| {
                    arg_id(args, 0)
                        .and_then(|id| st.modules.get(id))
                        .map(|m| {
                            m.custom_sections()
                                .filter(|c| c.name() == want)
                                .map(|c| c.data().to_vec())
                                .collect()
                        })
                        .unwrap_or_default()
                })
            })
            .unwrap_or_default()
    };
    let mut bufs = Vec::with_capacity(datas.len());
    for d in datas {
        let block = boa_engine::object::builtins::AlignedVec::from_iter(0, d);
        let ab = boa_engine::object::builtins::JsArrayBuffer::from_byte_block(block, ctx)?;
        bufs.push(JsValue::from(ab));
    }
    Ok(JsArray::from_iter(bufs, ctx).into())
}

/// Read a JS array of small non-negative integers (the import descriptor) into
/// `Vec<u32>`, with `ctx` available. Used before entering the wasm borrow.
/// One resolved import binding (positional with `module.imports()`). The prelude
/// emits a tagged `[tag, payload]` per import; Rust resolves it against the
/// import's declared type. Memory/table refs are added in their stages.
enum ImportBinding {
    /// A JS function import: the index into the instantiation's import-function
    /// array (`__wasm_invoke_import` looks it up by `(token, index)`).
    Func(u32),
    /// A `WebAssembly.Global` passed as an import: its global registry id.
    GlobalRef(u32),
    /// A bare Number/BigInt imported into a global: pre-coerced to the import's
    /// content type (js-api wraps it in a fresh Global of the declared type).
    GlobalValue(wasmi::Val),
    /// A `WebAssembly.Memory` passed as an import: its memory registry id.
    MemoryRef(u32),
    /// A `WebAssembly.Table` passed as an import: its table registry id.
    TableRef(u32),
}

/// Parse the prelude's tagged import descriptor into `ImportBinding`s, converting
/// global-value imports against the declared content type (with `ctx` available,
/// before the wasm borrow). A value incompatible with an i64/etc. global is a
/// LinkError (js-api).
fn parse_import_descriptor(
    descriptor: Option<&JsValue>,
    import_types: &[wasmi::ExternType],
    ctx: &mut Context,
) -> Result<Vec<ImportBinding>, (&'static str, String)> {
    let arr = descriptor
        .and_then(|v| v.as_object())
        .and_then(|o| JsArray::from_object(o).ok());
    let mut out = Vec::with_capacity(import_types.len());
    for (i, ty) in import_types.iter().enumerate() {
        let entry = arr
            .as_ref()
            .and_then(|a| a.at(i as i64, ctx).ok())
            .and_then(|v| v.as_object())
            .and_then(|o| JsArray::from_object(o).ok());
        let Some(entry) = entry else {
            return Err(("Link", format!("import {i}: missing binding")));
        };
        let tag = entry
            .at(0_i64, ctx)
            .ok()
            .and_then(|v| v.to_string(ctx).ok())
            .map(|s| s.to_std_string_escaped())
            .unwrap_or_default();
        let payload = entry
            .at(1_i64, ctx)
            .unwrap_or_else(|_| JsValue::undefined());
        match tag.as_str() {
            "f" => out.push(ImportBinding::Func(
                payload.as_number().unwrap_or(0.0) as u32
            )),
            "g" => out.push(ImportBinding::GlobalRef(
                payload.as_number().unwrap_or(0.0) as u32
            )),
            "m" => out.push(ImportBinding::MemoryRef(
                payload.as_number().unwrap_or(0.0) as u32
            )),
            "t" => out.push(ImportBinding::TableRef(
                payload.as_number().unwrap_or(0.0) as u32
            )),
            "gv" => {
                let Some(gt) = ty.global() else {
                    return Err((
                        "Link",
                        format!("import {i}: a value was given for a non-global import"),
                    ));
                };
                let val = js_to_wasm(ctx, &payload, gt.content()).map_err(|_| {
                    (
                        "Link",
                        format!("import {i}: the value is incompatible with the global type"),
                    )
                })?;
                out.push(ImportBinding::GlobalValue(val));
            }
            other => return Err(("Link", format!("import {i}: unknown binding '{other}'"))),
        }
    }
    Ok(out)
}

/// Build the linker from the resolved import bindings and instantiate, running
/// the start function. Stages 3–4 bind function and global imports; other kinds
/// arrive in their stages (the prelude rejects them earlier in practice).
fn build_and_instantiate(
    st: &mut WasmState,
    module: &wasmi::Module,
    token: u32,
    bindings: &[ImportBinding],
) -> Result<usize, (&'static str, String)> {
    let engine = st.engine.clone();
    let mut linker = wasmi::Linker::new(&engine);
    let imports: Vec<wasmi::ImportType> = module.imports().collect();
    for (i, imp) in imports.iter().enumerate() {
        let binding = bindings.get(i);
        match imp.ty() {
            wasmi::ExternType::Func(ft) => {
                let Some(ImportBinding::Func(j)) = binding else {
                    return Err((
                        "Link",
                        format!(
                            "import {}.{}: expected a function",
                            imp.module(),
                            imp.name()
                        ),
                    ));
                };
                let func = make_import_func(&mut st.store, ft.clone(), token, *j);
                linker
                    .define(imp.module(), imp.name(), func)
                    .map_err(|e| ("Link", format!("{e}")))?;
            }
            wasmi::ExternType::Global(gt) => {
                let global = match binding {
                    Some(ImportBinding::GlobalRef(gid)) => {
                        match st.globals.get(*gid as usize).copied() {
                            Some(g) => g,
                            None => {
                                return Err((
                                    "Link",
                                    format!(
                                        "import {}.{}: unknown global",
                                        imp.module(),
                                        imp.name()
                                    ),
                                ));
                            }
                        }
                    }
                    Some(ImportBinding::GlobalValue(val)) => {
                        let g = wasmi::Global::new(&mut st.store, val.clone(), gt.mutability());
                        st.globals.push(g);
                        g
                    }
                    _ => {
                        return Err((
                            "Link",
                            format!("import {}.{}: expected a global", imp.module(), imp.name()),
                        ));
                    }
                };
                linker
                    .define(imp.module(), imp.name(), global)
                    .map_err(|e| ("Link", format!("{e}")))?;
            }
            wasmi::ExternType::Memory(_) => {
                let Some(ImportBinding::MemoryRef(mid)) = binding else {
                    return Err((
                        "Link",
                        format!("import {}.{}: expected a memory", imp.module(), imp.name()),
                    ));
                };
                let Some(mem) = st.memories.get(*mid as usize).map(|s| s.mem) else {
                    return Err((
                        "Link",
                        format!("import {}.{}: unknown memory", imp.module(), imp.name()),
                    ));
                };
                linker
                    .define(imp.module(), imp.name(), mem)
                    .map_err(|e| ("Link", format!("{e}")))?;
            }
            wasmi::ExternType::Table(_) => {
                let Some(ImportBinding::TableRef(tid)) = binding else {
                    return Err((
                        "Link",
                        format!("import {}.{}: expected a table", imp.module(), imp.name()),
                    ));
                };
                let Some(table) = st.tables.get(*tid as usize).copied() else {
                    return Err((
                        "Link",
                        format!("import {}.{}: unknown table", imp.module(), imp.name()),
                    ));
                };
                linker
                    .define(imp.module(), imp.name(), table)
                    .map_err(|e| ("Link", format!("{e}")))?;
            }
            #[allow(unreachable_patterns)]
            _ => {
                return Err((
                    "Link",
                    format!(
                        "import {}.{}: this import kind is not supported yet",
                        imp.module(),
                        imp.name()
                    ),
                ));
            }
        }
    }
    match std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
        linker.instantiate_and_start(&mut st.store, module)
    })) {
        Ok(Ok(instance)) => {
            let id = st.instances.len();
            st.instances.push(instance);
            Ok(id)
        }
        Ok(Err(e)) => Err((wasm_error_kind(&e), format!("{e}"))),
        Err(_) => Err((
            "Link",
            String::from("WebAssembly instantiation failed (unsupported feature)"),
        )),
    }
}

/// `__wasm_instantiate(moduleId, importToken, descriptor)` → the envelope
/// `[0, instanceId]`, else `[kind, message]`. Resolves the importObject
/// (functions + globals), runs the start function (a trap there → RuntimeError;
/// js-api `Instance`); a host import that throws during start re-throws the
/// original JS exception.
fn sys_wasm_instantiate(_: &JsValue, args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let Some(cell) = page_wasm_cell(ctx) else {
        return Ok(wasm_err(
            "Link",
            "WebAssembly is unavailable on this page",
            ctx,
        ));
    };
    let module_id = arg_id(args, 0);
    let token = args
        .get(1)
        .and_then(|v| v.as_number())
        .map(|n| n as u32)
        .unwrap_or(0);
    // The module's import extern-types (short borrow) drive the descriptor parse.
    let import_types: Option<Vec<wasmi::ExternType>> = {
        let slot = cell.borrow();
        slot.as_ref().and_then(|st| {
            module_id
                .and_then(|id| st.modules.get(id))
                .map(|m| m.imports().map(|imp| imp.ty().clone()).collect())
        })
    };
    let Some(import_types) = import_types else {
        return Ok(wasm_err(
            "Link",
            "WebAssembly.instantiate: unknown module",
            ctx,
        ));
    };
    // Resolve the bindings with ctx available (coerces global-value imports),
    // before entering the wasm borrow.
    let bindings = match parse_import_descriptor(args.get(2), &import_types, ctx) {
        Ok(b) => b,
        Err((kind, msg)) => return Ok(wasm_err(kind, &msg, ctx)),
    };
    let result: Result<usize, (&'static str, String)> = {
        // The start function may call host imports back into JS — set the live
        // context and hold no `ctx`/`host_defined` borrow across the call.
        let _guard = WasmCtxGuard::set(ctx);
        let mut slot = cell.borrow_mut();
        let st = slot.get_or_insert_with(WasmState::new);
        match module_id.and_then(|id| st.modules.get(id)).cloned() {
            Some(module) => build_and_instantiate(st, &module, token, &bindings),
            None => Err((
                "Link",
                String::from("WebAssembly.instantiate: unknown module"),
            )),
        }
    };
    // The start function may have grown a memory — detach stale buffers.
    detach_grown_memories(ctx);
    // A host import that threw during start: re-throw the original JS value.
    if let Some(e) = WASM_PENDING.with(|c| c.borrow_mut().take()) {
        return Err(e);
    }
    Ok(match result {
        Ok(id) => wasm_ok(JsValue::from(id as f64), ctx),
        Err((kind, msg)) => wasm_err(kind, &msg, ctx),
    })
}

/// `__wasm_instance_exports(instanceId, moduleId)` → flat array
/// `[name, kind, subId, …]`; the prelude builds the (frozen) exports object.
/// wasmi has no per-instance export listing, so names/kinds come from the
/// module and each export is fetched by name. Stage 2 wraps FUNCTION exports
/// (each registered into `funcs`, its index returned as `subId`); memory/table/
/// global exports are added in their stages.
fn sys_wasm_instance_exports(
    _: &JsValue,
    args: &[JsValue],
    ctx: &mut Context,
) -> JsResult<JsValue> {
    let out: Vec<JsValue> = {
        let host = ctx.realm().host_defined();
        host.get::<PageWasm>()
            .map(|pw| {
                pw.with(|st| {
                    let mut v = Vec::new();
                    let (Some(inst), Some(mid)) = (
                        arg_id(args, 0).and_then(|id| st.instances.get(id)).copied(),
                        arg_id(args, 1),
                    ) else {
                        return v;
                    };
                    let descs: Vec<(String, &'static str)> = match st.modules.get(mid) {
                        Some(m) => m
                            .exports()
                            .map(|e| (e.name().to_string(), wasm_extern_kind(e.ty())))
                            .collect(),
                        None => return v,
                    };
                    for (name, kind) in descs {
                        match kind {
                            "function" => {
                                if let Some(f) = inst.get_func(&st.store, &name) {
                                    let sub = st.funcs.len();
                                    st.funcs.push(f);
                                    v.push(str_value(&name));
                                    v.push(str_value("function"));
                                    v.push(JsValue::from(sub as f64));
                                }
                            }
                            "global" => {
                                if let Some(g) = inst.get_global(&st.store, &name) {
                                    let sub = st.globals.len();
                                    st.globals.push(g);
                                    v.push(str_value(&name));
                                    v.push(str_value("global"));
                                    v.push(JsValue::from(sub as f64));
                                }
                            }
                            "memory" => {
                                if let Some(m) = inst.get_memory(&st.store, &name) {
                                    let last_pages = m.size(&st.store);
                                    let sub = st.memories.len();
                                    st.memories.push(MemorySlot { mem: m, last_pages });
                                    v.push(str_value(&name));
                                    v.push(str_value("memory"));
                                    v.push(JsValue::from(sub as f64));
                                }
                            }
                            "table" => {
                                if let Some(t) = inst.get_table(&st.store, &name) {
                                    let sub = st.tables.len();
                                    st.tables.push(t);
                                    v.push(str_value(&name));
                                    v.push(str_value("table"));
                                    v.push(JsValue::from(sub as f64));
                                }
                            }
                            _ => {}
                        }
                    }
                    v
                })
            })
            .unwrap_or_default()
    };
    Ok(JsArray::from_iter(out, ctx).into())
}

/// `__wasm_call_export(funcId, argsArray)` → the envelope `[0, value]` or
/// `["Runtime", msg]`. Implements the Exported Function `[[Call]]` (js-api):
/// v128-in-signature → TypeError; missing args → undefined; each arg coerced by
/// `ToWebAssemblyValue`; the results turned into undefined / one value / an
/// Array by `ToJSValue`; a trap → RuntimeError; a host import that throws
/// re-throws the original JS exception. The wasm state is reached through its
/// `Rc` (no `ctx` borrow held across execution) so a host import can re-enter
/// JS; a JS attempt to re-enter wasm WHILE a call is on the stack (one shared
/// store) is rejected with a clean RuntimeError rather than a double-borrow.
fn sys_wasm_call_export(_: &JsValue, args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let Some(cell) = page_wasm_cell(ctx) else {
        return Err(boa_engine::JsNativeError::typ()
            .with_message("WebAssembly is unavailable")
            .into());
    };

    // (1) The function signature, under a short immutable borrow. A failed
    // borrow means we are nested inside an in-flight wasm call (a host import's
    // JS re-entered wasm) — not supported on one shared store.
    let sig: Option<(Vec<wasmi::ValType>, Vec<wasmi::ValType>)> = match cell.try_borrow() {
        Ok(slot) => slot.as_ref().and_then(|st| {
            arg_id(args, 0).and_then(|i| st.funcs.get(i)).map(|f| {
                let ty = f.ty(&st.store);
                (ty.params().to_vec(), ty.results().to_vec())
            })
        }),
        Err(_) => {
            return Ok(wasm_err(
                "Runtime",
                "re-entrant WebAssembly call from a host import is not supported",
                ctx,
            ));
        }
    };
    let Some((params, results)) = sig else {
        return Err(boa_engine::JsNativeError::typ()
            .with_message("WebAssembly: call to an unknown exported function")
            .into());
    };
    if params
        .iter()
        .chain(&results)
        .any(|t| matches!(t, wasmi::ValType::V128))
    {
        return Err(boa_engine::JsNativeError::typ()
            .with_message("WebAssembly: cannot call a function whose signature contains v128")
            .into());
    }

    // (2) Prepare arg conversions, no state borrow held (an externref arg is
    // interned, a funcref validated; user `valueOf` may even re-enter wasm —
    // legal, no call on the stack yet). Refs are built inside the borrow below.
    let arg_list = args
        .get(1)
        .and_then(|v| v.as_object())
        .and_then(|o| JsArray::from_object(o).ok());
    let mut arg_convs: Vec<ArgConv> = Vec::with_capacity(params.len());
    for (i, ty) in params.iter().enumerate() {
        let v = match &arg_list {
            Some(a) => a.at(i as i64, ctx).unwrap_or_else(|_| JsValue::undefined()),
            None => JsValue::undefined(),
        };
        arg_convs.push(prepare_arg(ctx, &v, *ty)?);
    }

    // (3) Build inputs, call, and extract result tokens — all under one borrow.
    // Set the live context (host imports re-enter JS through it); hold no `ctx`
    // borrow across `f.call`.
    let func_id = arg_id(args, 0);
    let call: Result<Vec<OutTok>, (&'static str, String)> = {
        let _guard = WasmCtxGuard::set(ctx);
        match cell.try_borrow_mut() {
            Ok(mut slot) => {
                let st = slot.get_or_insert_with(WasmState::new);
                let mut inputs = Vec::with_capacity(arg_convs.len());
                let mut built = true;
                for a in arg_convs {
                    match build_arg(st, a) {
                        Ok(val) => inputs.push(val),
                        Err(()) => {
                            built = false;
                            break;
                        }
                    }
                }
                if !built {
                    Err((
                        "Runtime",
                        String::from("WebAssembly: invalid reference argument"),
                    ))
                } else {
                    match func_id.and_then(|i| st.funcs.get(i)).copied() {
                        None => Err(("Runtime", String::from("WebAssembly: function went away"))),
                        Some(f) => {
                            let mut outputs: Vec<wasmi::Val> =
                                results.iter().map(|t| wasmi::Val::default(*t)).collect();
                            match std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
                                f.call(&mut st.store, &inputs, &mut outputs)
                            })) {
                                Ok(Ok(())) => {
                                    let mut toks = Vec::with_capacity(outputs.len());
                                    for v in &outputs {
                                        toks.push(extract_out_token(st, v));
                                    }
                                    Ok(toks)
                                }
                                Ok(Err(e)) => Err((wasm_error_kind(&e), format!("{e}"))),
                                Err(_) => Err(("Runtime", String::from("WebAssembly trap"))),
                            }
                        }
                    }
                }
            }
            Err(_) => Err((
                "Runtime",
                String::from("re-entrant WebAssembly call from a host import is not supported"),
            )),
        }
    };

    // The module may have grown a memory internally — detach stale buffers.
    detach_grown_memories(ctx);
    // A host import that threw: re-throw the original JS value (js-api).
    if let Some(e) = WASM_PENDING.with(|c| c.borrow_mut().take()) {
        return Err(e);
    }
    let toks = match call {
        Ok(t) => t,
        Err((kind, msg)) => return Ok(wasm_err(kind, &msg, ctx)),
    };

    // (4) Resolve result tokens to JS (refs via the prelude), then the envelope
    // (arity 0 → undefined, 1 → the value, N → an Array).
    let mut vals = Vec::with_capacity(toks.len());
    for t in toks {
        vals.push(match t {
            OutTok::Js(v) => v,
            OutTok::Func(id) => wasm_make_func(ctx, id)?,
            OutTok::Extern(id) => wasm_extern_get(ctx, id)?,
        });
    }
    let value = match vals.as_slice() {
        [] => JsValue::undefined(),
        [one] => one.clone(),
        _ => JsArray::from_iter(vals, ctx).into(),
    };
    Ok(wasm_ok(value, ctx))
}

/// `__wasm_global_new(typeStr, mutable, value)` → a global id (Number) on
/// success, or throws a `TypeError` (js-api `Global` constructor): bad type,
/// v128 (not constructible from JS), or a value that won't coerce. A missing
/// value uses the type's default. Stage 4 supports numeric globals; reference-
/// typed globals (externref/funcref) coerce in Stage 6.
fn sys_wasm_global_new(_: &JsValue, args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let type_str = arg_str(args, 0, ctx);
    let mutable = args.get(1).map(|v| v.to_boolean()).unwrap_or(false);
    let Some(ty) = valtype_from_str(&type_str) else {
        return Err(boa_engine::JsNativeError::typ()
            .with_message("WebAssembly.Global: invalid value type")
            .into());
    };
    if matches!(ty, wasmi::ValType::V128) {
        return Err(boa_engine::JsNativeError::typ()
            .with_message("WebAssembly.Global: a v128 global cannot be constructed from JS")
            .into());
    }
    // Coerce the initial value (or the type default) BEFORE the wasm borrow.
    let init = match args.get(2) {
        Some(v) if !v.is_undefined() => js_to_wasm(ctx, v, ty)?,
        _ => wasmi::Val::default(ty),
    };
    let mutability = if mutable {
        wasmi::Mutability::Var
    } else {
        wasmi::Mutability::Const
    };
    let Some(cell) = page_wasm_cell(ctx) else {
        return Err(boa_engine::JsNativeError::typ()
            .with_message("WebAssembly is unavailable")
            .into());
    };
    let mut slot = cell.borrow_mut();
    let st = slot.get_or_insert_with(WasmState::new);
    let g = wasmi::Global::new(&mut st.store, init, mutability);
    let id = st.globals.len();
    st.globals.push(g);
    Ok(JsValue::from(id as f64))
}

/// `__wasm_global_get(globalId)` → the global's value as a JS value
/// (`ToJSValue`); `undefined` for an unknown id.
fn sys_wasm_global_get(_: &JsValue, args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let Some(cell) = page_wasm_cell(ctx) else {
        return Ok(JsValue::undefined());
    };
    let val = {
        let slot = cell.borrow();
        slot.as_ref().and_then(|st| {
            arg_id(args, 0)
                .and_then(|i| st.globals.get(i))
                .map(|g| g.get(&st.store))
        })
    };
    match val {
        Some(v) => wasm_to_js(&v),
        None => Ok(JsValue::undefined()),
    }
}

/// `__wasm_global_set(globalId, value)` → `undefined`; throws `TypeError` if the
/// global is immutable or the value won't coerce (js-api `Global.value` setter).
fn sys_wasm_global_set(_: &JsValue, args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let Some(cell) = page_wasm_cell(ctx) else {
        return Ok(JsValue::undefined());
    };
    let info = {
        let slot = cell.borrow();
        slot.as_ref().and_then(|st| {
            arg_id(args, 0).and_then(|i| st.globals.get(i)).map(|g| {
                let t = g.ty(&st.store);
                (
                    t.content(),
                    matches!(t.mutability(), wasmi::Mutability::Var),
                )
            })
        })
    };
    let Some((content, mutable)) = info else {
        return Ok(JsValue::undefined());
    };
    if !mutable {
        return Err(boa_engine::JsNativeError::typ()
            .with_message("WebAssembly.Global: cannot set the value of an immutable global")
            .into());
    }
    let val = js_to_wasm(ctx, args.get(1).unwrap_or(&JsValue::undefined()), content)?;
    let mut slot = cell.borrow_mut();
    if let Some(st) = slot.as_mut()
        && let Some(g) = arg_id(args, 0).and_then(|i| st.globals.get(i)).copied()
    {
        g.set(&mut st.store, val).map_err(|e| {
            boa_engine::JsNativeError::typ().with_message(format!("WebAssembly.Global: {e}"))
        })?;
    }
    Ok(JsValue::undefined())
}

fn wasm_range_err(msg: impl Into<String>) -> boa_engine::JsError {
    boa_engine::JsNativeError::range()
        .with_message(msg.into())
        .into()
}

/// `__wasm_memory_new(initialPages, maxPagesOrNeg)` → a memory id (Number), or
/// throws a RangeError (js-api `Memory` constructor): bad/oversized dimensions.
/// A negative `maxPagesOrNeg` means "no maximum".
fn sys_wasm_memory_new(_: &JsValue, args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let initial = args.first().and_then(|v| v.as_number()).unwrap_or(0.0);
    let max = args.get(1).and_then(|v| v.as_number()).unwrap_or(-1.0);
    if !(0.0..=u32::MAX as f64).contains(&initial) {
        return Err(wasm_range_err(
            "WebAssembly.Memory: 'initial' is out of range",
        ));
    }
    let initial = initial as u64;
    let maximum: Option<u64> = (max >= 0.0).then_some(max as u64);
    if let Some(m) = maximum
        && initial > m
    {
        return Err(wasm_range_err(
            "WebAssembly.Memory: 'initial' must not exceed 'maximum'",
        ));
    }
    let mut b = wasmi::MemoryType::builder();
    b.min(initial);
    b.max(maximum);
    let ty = b
        .build()
        .map_err(|e| wasm_range_err(format!("WebAssembly.Memory: {e}")))?;
    let Some(cell) = page_wasm_cell(ctx) else {
        return Err(wasm_range_err("WebAssembly is unavailable"));
    };
    let mut slot = cell.borrow_mut();
    let st = slot.get_or_insert_with(WasmState::new);
    let mem = wasmi::Memory::new(&mut st.store, ty)
        .map_err(|e| wasm_range_err(format!("WebAssembly.Memory: {e}")))?;
    let last_pages = mem.size(&st.store);
    let id = st.memories.len();
    st.memories.push(MemorySlot { mem, last_pages });
    Ok(JsValue::from(id as f64))
}

/// `__wasm_memory_size(memId)` → current size in pages (Number).
fn sys_wasm_memory_size(_: &JsValue, args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let Some(cell) = page_wasm_cell(ctx) else {
        return Ok(JsValue::from(0.0));
    };
    let slot = cell.borrow();
    let pages = slot
        .as_ref()
        .and_then(|st| {
            arg_id(args, 0)
                .and_then(|i| st.memories.get(i))
                .map(|m| m.mem.size(&st.store))
        })
        .unwrap_or(0);
    Ok(JsValue::from(pages as f64))
}

/// `__wasm_memory_grow(memId, deltaPages)` → previous size in pages (Number);
/// throws a RangeError if the grow fails (js-api `Memory.grow`). The current
/// buffer is detached afterward (the memory may have moved).
fn sys_wasm_memory_grow(_: &JsValue, args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let delta = args.get(1).and_then(|v| v.as_number());
    let Some(delta) = delta.filter(|d| (0.0..=u32::MAX as f64).contains(d)) else {
        return Err(wasm_range_err("WebAssembly.Memory.grow: invalid delta"));
    };
    let delta = delta as u64;
    let mem_id = arg_id(args, 0);
    let Some(cell) = page_wasm_cell(ctx) else {
        return Err(wasm_range_err("WebAssembly is unavailable"));
    };
    let grow_result: Option<Result<u64, String>> = {
        let mut slot = cell.borrow_mut();
        slot.as_mut().and_then(|st| {
            let i = mem_id?;
            if i >= st.memories.len() {
                return None;
            }
            let mem = st.memories[i].mem;
            Some(match mem.grow(&mut st.store, delta) {
                Ok(old_pages) => {
                    st.memories[i].last_pages = mem.size(&st.store);
                    Ok(old_pages)
                }
                Err(e) => Err(format!("{e}")),
            })
        })
    };
    // The old buffer now views moved/resized memory — detach it (state borrow
    // released above) so JS re-fetches a fresh one.
    if let Some(i) = mem_id {
        detach_memory_buffer(ctx, i);
    }
    match grow_result {
        Some(Ok(old)) => Ok(JsValue::from(old as f64)),
        Some(Err(msg)) => Err(wasm_range_err(format!("WebAssembly.Memory.grow: {msg}"))),
        None => Ok(JsValue::from(0.0)),
    }
}

/// `__wasm_memory_buffer(memId)` → the live `ArrayBuffer` over the memory's
/// linear bytes (js-api `Memory.buffer`). Identity-cached per memory: the same
/// object is returned until the memory grows, when it is detached and rebuilt.
fn sys_wasm_memory_buffer(_: &JsValue, args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let Some(mem_id) = arg_id(args, 0) else {
        return Ok(JsValue::undefined());
    };
    let Some(cell) = page_wasm_cell(ctx) else {
        return Ok(JsValue::undefined());
    };
    let geom: Option<(*mut u8, usize, u64)> = {
        let slot = cell.borrow();
        slot.as_ref().and_then(|st| {
            st.memories.get(mem_id).map(|m| {
                (
                    m.mem.data_ptr(&st.store),
                    m.mem.data_size(&st.store),
                    m.mem.size(&st.store),
                )
            })
        })
    };
    let Some((ptr, byte_len, pages)) = geom else {
        return Ok(JsValue::undefined());
    };
    let Some(buffers) = page_wasm_buffers(ctx) else {
        return Ok(JsValue::undefined());
    };
    let cached = buffers.borrow().get(mem_id).and_then(|b| b.clone());
    // A cached buffer is reusable if it is not detached and reflects the current
    // size (a non-detached external buffer reports its live `byteLength`).
    if let Some(buf) = &cached
        && let Ok(ab) = boa_engine::object::builtins::JsArrayBuffer::from_object(buf.clone())
        && ab.byte_length() == byte_len
        && byte_len != 0
    {
        return Ok(JsValue::from(buf.clone()));
    }
    // Stale or absent: detach the old one and build a fresh external buffer.
    if let Some(buf) = cached
        && let Ok(ab) = boa_engine::object::builtins::JsArrayBuffer::from_object(buf)
    {
        let _ = ab.detach(&JsValue::undefined());
    }
    // SAFETY: ptr/byte_len are the memory's current backing; the detach
    // discipline (grow detaches this buffer before the memory can move) keeps the
    // region valid while the buffer is live, and access is single-threaded.
    let ab = unsafe {
        boa_engine::object::builtins::JsArrayBuffer::from_external(
            ptr,
            byte_len,
            JsValue::undefined(),
            ctx,
        )?
    };
    let obj = boa_engine::JsObject::from(ab);
    {
        let mut b = buffers.borrow_mut();
        if b.len() <= mem_id {
            b.resize(mem_id + 1, None);
        }
        b[mem_id] = Some(obj.clone());
    }
    {
        let mut slot = cell.borrow_mut();
        if let Some(st) = slot.as_mut()
            && let Some(m) = st.memories.get_mut(mem_id)
        {
            m.last_pages = pages;
        }
    }
    Ok(JsValue::from(obj))
}

/// Detach memory `mem_id`'s current `Memory.buffer` object (its `byteLength`
/// becomes 0, so JS — wasm-bindgen `getUint8Memory0`, emscripten — re-fetches a
/// fresh one). Clears the cached handle. No-op if there is none.
fn detach_memory_buffer(ctx: &mut Context, mem_id: usize) {
    let Some(buffers) = page_wasm_buffers(ctx) else {
        return;
    };
    let buf = {
        let mut b = buffers.borrow_mut();
        b.get_mut(mem_id).and_then(|slot| slot.take())
    };
    if let Some(buf) = buf
        && let Ok(ab) = boa_engine::object::builtins::JsArrayBuffer::from_object(buf)
    {
        let _ = ab.detach(&JsValue::undefined());
    }
}

/// After wasm executes, detach the buffer of any memory whose size grew (a
/// module may run the `memory.grow` instruction internally — emscripten sbrk,
/// wasm-bindgen). Their previously-handed-out buffers would otherwise view
/// freed/short memory. Cheap: one size read per memory.
fn detach_grown_memories(ctx: &mut Context) {
    let Some(cell) = page_wasm_cell(ctx) else {
        return;
    };
    let grown: Vec<usize> = {
        let mut slot = cell.borrow_mut();
        match slot.as_mut() {
            Some(st) => {
                let mut grown = Vec::new();
                for i in 0..st.memories.len() {
                    let cur = st.memories[i].mem.size(&st.store);
                    if cur > st.memories[i].last_pages {
                        st.memories[i].last_pages = cur;
                        grown.push(i);
                    }
                }
                grown
            }
            None => Vec::new(),
        }
    };
    for i in grown {
        detach_memory_buffer(ctx, i);
    }
}

fn wasm_type_err(msg: impl Into<String>) -> boa_engine::JsError {
    boa_engine::JsNativeError::typ()
        .with_message(msg.into())
        .into()
}

/// Call the prelude `__wasm_extern_intern(value)` → an externref id. The JS value
/// is kept alive in JS-land (the intern map), so identity is preserved on
/// read-back.
fn wasm_extern_intern(ctx: &mut Context, value: &JsValue) -> JsResult<usize> {
    let f = ctx
        .global_object()
        .get(boa_engine::js_string!("__wasm_extern_intern"), ctx)?;
    let Some(callable) = f.as_callable() else {
        return Err(wasm_type_err(
            "WebAssembly: externref support is unavailable",
        ));
    };
    let id = callable.call(&JsValue::undefined(), std::slice::from_ref(value), ctx)?;
    Ok(id.as_number().unwrap_or(0.0).max(0.0) as usize)
}

/// Call the prelude `__wasm_extern_get(id)` → the interned JS value.
fn wasm_extern_get(ctx: &mut Context, id: usize) -> JsResult<JsValue> {
    let f = ctx
        .global_object()
        .get(boa_engine::js_string!("__wasm_extern_get"), ctx)?;
    let Some(callable) = f.as_callable() else {
        return Ok(JsValue::null());
    };
    callable.call(&JsValue::undefined(), &[JsValue::from(id as f64)], ctx)
}

/// Call the prelude `__wasm_make_func(funcId)` → the Exported Function wrapper.
fn wasm_make_func(ctx: &mut Context, func_id: usize) -> JsResult<JsValue> {
    let f = ctx
        .global_object()
        .get(boa_engine::js_string!("__wasm_make_func"), ctx)?;
    let Some(callable) = f.as_callable() else {
        return Ok(JsValue::null());
    };
    callable.call(&JsValue::undefined(), &[JsValue::from(func_id as f64)], ctx)
}

/// A reference value prepared for a table/global slot, WITHOUT a state borrow.
#[derive(Clone, Copy)]
enum RefArg {
    Null(wasmi::ValType),
    Func(usize),
    Extern(usize),
}

/// `ToWebAssemblyValue` for a reference-typed slot, with `ctx` but no state
/// borrow (it may intern an externref via the prelude). null/undefined → the
/// null reference; a funcref value must be an Exported Function (js-api).
fn prepare_ref(ctx: &mut Context, value: &JsValue, elem: wasmi::ValType) -> JsResult<RefArg> {
    if value.is_null() || value.is_undefined() {
        return Ok(RefArg::Null(elem));
    }
    match elem {
        wasmi::ValType::FuncRef => {
            let func_id = value
                .as_object()
                .and_then(|o| o.get(boa_engine::js_string!("__wasmFunc"), ctx).ok())
                .and_then(|v| v.as_number())
                .filter(|n| *n >= 0.0);
            match func_id {
                Some(n) => Ok(RefArg::Func(n as usize)),
                None => Err(wasm_type_err(
                    "WebAssembly: a funcref must be an exported function or null",
                )),
            }
        }
        wasmi::ValType::ExternRef => Ok(RefArg::Extern(wasm_extern_intern(ctx, value)?)),
        _ => Err(wasm_type_err("WebAssembly: unsupported reference type")),
    }
}

/// Build the wasm `Val` for a prepared ref (inside the state borrow).
fn build_ref(st: &mut WasmState, arg: RefArg) -> Result<wasmi::Val, ()> {
    Ok(match arg {
        RefArg::Null(wasmi::ValType::FuncRef) => wasmi::Val::FuncRef(wasmi::Ref::Null),
        RefArg::Null(_) => wasmi::Val::ExternRef(wasmi::Ref::Null),
        RefArg::Func(i) => {
            wasmi::Val::FuncRef(wasmi::Ref::Val(st.funcs.get(i).copied().ok_or(())?))
        }
        RefArg::Extern(id) => {
            wasmi::Val::ExternRef(wasmi::Ref::Val(wasmi::ExternRef::new(&mut st.store, id)))
        }
    })
}

/// A call argument prepared without a state borrow (numerics convert directly;
/// refs are prepared — an externref may be interned).
enum ArgConv {
    Val(wasmi::Val),
    Ref(RefArg),
}

fn prepare_arg(ctx: &mut Context, v: &JsValue, ty: wasmi::ValType) -> JsResult<ArgConv> {
    match ty {
        wasmi::ValType::FuncRef | wasmi::ValType::ExternRef => {
            Ok(ArgConv::Ref(prepare_ref(ctx, v, ty)?))
        }
        _ => Ok(ArgConv::Val(js_to_wasm(ctx, v, ty)?)),
    }
}

fn build_arg(st: &mut WasmState, a: ArgConv) -> Result<wasmi::Val, ()> {
    match a {
        ArgConv::Val(v) => Ok(v),
        ArgConv::Ref(r) => build_ref(st, r),
    }
}

/// A call result extracted under the state borrow, resolved to a JS value (refs
/// through the prelude) only AFTER the borrow is released.
enum OutTok {
    Js(JsValue),
    Func(usize),
    Extern(usize),
}

fn extract_out_token(st: &mut WasmState, v: &wasmi::Val) -> OutTok {
    match v {
        wasmi::Val::FuncRef(wasmi::Ref::Null) | wasmi::Val::ExternRef(wasmi::Ref::Null) => {
            OutTok::Js(JsValue::null())
        }
        wasmi::Val::FuncRef(wasmi::Ref::Val(f)) => {
            let id = st.funcs.len();
            st.funcs.push(*f);
            OutTok::Func(id)
        }
        wasmi::Val::ExternRef(wasmi::Ref::Val(er)) => {
            let id = er
                .data(&st.store)
                .downcast_ref::<usize>()
                .copied()
                .unwrap_or(0);
            OutTok::Extern(id)
        }
        other => OutTok::Js(wasm_to_js(other).unwrap_or(JsValue::undefined())),
    }
}

/// `__wasm_table_new(elementStr, initialLen, maxLenOrNeg, initValue)` → a table
/// id (Number), or throws (js-api `Table` constructor). element ∈
/// anyfunc|externref; new cells are filled with `initValue` (default null).
fn sys_wasm_table_new(_: &JsValue, args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let elem_str = arg_str(args, 0, ctx);
    let Some(elem) = valtype_from_str(&elem_str)
        .filter(|t| matches!(t, wasmi::ValType::FuncRef | wasmi::ValType::ExternRef))
    else {
        return Err(wasm_type_err(
            "WebAssembly.Table: 'element' must be 'anyfunc' or 'externref'",
        ));
    };
    let initial = args.get(1).and_then(|v| v.as_number()).unwrap_or(0.0);
    let max = args.get(2).and_then(|v| v.as_number()).unwrap_or(-1.0);
    if !(0.0..=u32::MAX as f64).contains(&initial) {
        return Err(wasm_range_err(
            "WebAssembly.Table: 'initial' is out of range",
        ));
    }
    let initial = initial as u32;
    let maximum: Option<u32> = (max >= 0.0).then_some(max as u32);
    if let Some(m) = maximum
        && initial > m
    {
        return Err(wasm_range_err(
            "WebAssembly.Table: 'initial' must not exceed 'maximum'",
        ));
    }
    let init_arg = prepare_ref(ctx, args.get(3).unwrap_or(&JsValue::undefined()), elem)?;
    let ty = wasmi::TableType::new(elem, initial, maximum);
    let Some(cell) = page_wasm_cell(ctx) else {
        return Err(wasm_range_err("WebAssembly is unavailable"));
    };
    let mut slot = cell.borrow_mut();
    let st = slot.get_or_insert_with(WasmState::new);
    let init = build_ref(st, init_arg)
        .map_err(|_| wasm_type_err("WebAssembly.Table: invalid initial value"))?;
    let table = wasmi::Table::new(&mut st.store, ty, init)
        .map_err(|e| wasm_range_err(format!("WebAssembly.Table: {e}")))?;
    let id = st.tables.len();
    st.tables.push(table);
    Ok(JsValue::from(id as f64))
}

/// `__wasm_table_length(tableId)` → current length (Number).
fn sys_wasm_table_length(_: &JsValue, args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let Some(cell) = page_wasm_cell(ctx) else {
        return Ok(JsValue::from(0.0));
    };
    let slot = cell.borrow();
    let len = slot
        .as_ref()
        .and_then(|st| {
            arg_id(args, 0)
                .and_then(|i| st.tables.get(i))
                .map(|t| t.size(&st.store))
        })
        .unwrap_or(0);
    Ok(JsValue::from(len as f64))
}

/// `__wasm_table_get(tableId, index)` → the element as a JS value (funcref →
/// Exported Function/null, externref → the JS value/null); throws RangeError for
/// an out-of-bounds index (js-api `Table.get`).
fn sys_wasm_table_get(_: &JsValue, args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let Some(cell) = page_wasm_cell(ctx) else {
        return Ok(JsValue::null());
    };
    let index = args.get(1).and_then(|v| v.as_number()).unwrap_or(-1.0);
    if index < 0.0 {
        return Err(wasm_range_err(
            "WebAssembly.Table.get: index is out of bounds",
        ));
    }
    let index = index as u64;
    enum Tok {
        Null,
        Func(usize),
        Extern(usize),
        Other(wasmi::Val),
        Oob,
    }
    let tok = {
        let mut slot = cell.borrow_mut();
        match slot.as_mut().and_then(|st| {
            arg_id(args, 0)
                .and_then(|i| st.tables.get(i).copied())
                .map(|t| (st, t))
        }) {
            Some((st, t)) => match t.get(&st.store, index) {
                None => Tok::Oob,
                Some(wasmi::Val::FuncRef(wasmi::Ref::Null))
                | Some(wasmi::Val::ExternRef(wasmi::Ref::Null)) => Tok::Null,
                Some(wasmi::Val::FuncRef(wasmi::Ref::Val(f))) => {
                    // No `Func` equality in wasmi → a fresh wrapper (the funcref
                    // read-back identity caveat); the VALUE is correct/callable.
                    let id = st.funcs.len();
                    st.funcs.push(f);
                    Tok::Func(id)
                }
                Some(wasmi::Val::ExternRef(wasmi::Ref::Val(er))) => {
                    let id = er
                        .data(&st.store)
                        .downcast_ref::<usize>()
                        .copied()
                        .unwrap_or(0);
                    Tok::Extern(id)
                }
                Some(other) => Tok::Other(other),
            },
            None => Tok::Oob,
        }
    };
    match tok {
        Tok::Oob => Err(wasm_range_err(
            "WebAssembly.Table.get: index is out of bounds",
        )),
        Tok::Null => Ok(JsValue::null()),
        Tok::Func(id) => wasm_make_func(ctx, id),
        Tok::Extern(id) => wasm_extern_get(ctx, id),
        Tok::Other(v) => wasm_to_js(&v),
    }
}

/// `__wasm_table_set(tableId, index, value)` → undefined; throws RangeError
/// (out of bounds) or TypeError (bad ref value) (js-api `Table.set`).
fn sys_wasm_table_set(_: &JsValue, args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let Some(cell) = page_wasm_cell(ctx) else {
        return Ok(JsValue::undefined());
    };
    let index = args.get(1).and_then(|v| v.as_number()).unwrap_or(-1.0);
    if index < 0.0 {
        return Err(wasm_range_err(
            "WebAssembly.Table.set: index is out of bounds",
        ));
    }
    let index = index as u64;
    let elem = {
        let slot = cell.borrow();
        slot.as_ref().and_then(|st| {
            arg_id(args, 0)
                .and_then(|i| st.tables.get(i))
                .map(|t| t.ty(&st.store).element())
        })
    };
    let Some(elem) = elem else {
        return Err(wasm_range_err("WebAssembly.Table.set: unknown table"));
    };
    let arg = prepare_ref(ctx, args.get(2).unwrap_or(&JsValue::undefined()), elem)?;
    let result: Result<(), String> = {
        let mut slot = cell.borrow_mut();
        if let Some(st) = slot.as_mut() {
            match build_ref(st, arg) {
                Err(()) => Err(String::from("invalid funcref")),
                Ok(val) => match arg_id(args, 0).and_then(|i| st.tables.get(i).copied()) {
                    Some(t) => t.set(&mut st.store, index, val).map_err(|e| format!("{e}")),
                    None => Err(String::from("unknown table")),
                },
            }
        } else {
            Err(String::from("unavailable"))
        }
    };
    match result {
        Ok(()) => Ok(JsValue::undefined()),
        Err(msg) if msg == "invalid funcref" => {
            Err(wasm_type_err("WebAssembly.Table.set: invalid funcref"))
        }
        Err(msg) => Err(wasm_range_err(format!("WebAssembly.Table.set: {msg}"))),
    }
}

/// `__wasm_table_grow(tableId, delta, value)` → previous length; throws
/// RangeError if it fails (js-api `Table.grow`). New cells filled with `value`.
fn sys_wasm_table_grow(_: &JsValue, args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let Some(cell) = page_wasm_cell(ctx) else {
        return Err(wasm_range_err("WebAssembly is unavailable"));
    };
    let delta = args.get(1).and_then(|v| v.as_number());
    let Some(delta) = delta.filter(|d| (0.0..=u32::MAX as f64).contains(d)) else {
        return Err(wasm_range_err("WebAssembly.Table.grow: invalid delta"));
    };
    let delta = delta as u64;
    let elem = {
        let slot = cell.borrow();
        slot.as_ref().and_then(|st| {
            arg_id(args, 0)
                .and_then(|i| st.tables.get(i))
                .map(|t| t.ty(&st.store).element())
        })
    };
    let Some(elem) = elem else {
        return Err(wasm_range_err("WebAssembly.Table.grow: unknown table"));
    };
    let arg = prepare_ref(ctx, args.get(2).unwrap_or(&JsValue::undefined()), elem)?;
    let result: Result<u64, String> = {
        let mut slot = cell.borrow_mut();
        if let Some(st) = slot.as_mut() {
            match build_ref(st, arg) {
                Err(()) => Err(String::from("invalid funcref")),
                Ok(val) => match arg_id(args, 0).and_then(|i| st.tables.get(i).copied()) {
                    Some(t) => t
                        .grow(&mut st.store, delta, val)
                        .map_err(|e| format!("{e}")),
                    None => Err(String::from("unknown table")),
                },
            }
        } else {
            Err(String::from("unavailable"))
        }
    };
    match result {
        Ok(old) => Ok(JsValue::from(old as f64)),
        Err(msg) => Err(wasm_range_err(format!("WebAssembly.Table.grow: {msg}"))),
    }
}

/// `__dom_run_injected_script(nodeId)` — run a `<script>` element that page
/// JS inserted into the live document (the universal SDK-loader idiom
/// `document.body.appendChild(scriptEl)`: reCAPTCHA/hCaptcha, lazy analytics,
/// payment/embed widgets, A/B tools). A real browser fetches+executes such a
/// script; TRust never did, so a runtime-injected dependency silently never
/// loaded — pixiv's login injects `recaptcha/enterprise.js` then polls
/// `window.grecaptcha` forever, so the submit hung. Classic scripts only
/// (the prelude already gates type + first-insertion): a `src` is fetched
/// then evaluated, inline text is evaluated, and a `load`/`error` event fires
/// on the element for code that waits on `script.onload`. The fetch reuses
/// the same cap-/`subresource_allowed`-gated async job `fetch()` uses, so it
/// overlaps with other work and can't pivot to private address space.
fn sys_run_injected_script(_: &JsValue, args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let (node_id, src, text) = {
        let dom = page_dom(ctx);
        let d = dom.borrow();
        let Some(id) = arg_node(&d, args, 0) else {
            return Ok(JsValue::undefined());
        };
        (
            id,
            d.attr(id, "src").map(str::to_string),
            d.text_content(id),
        )
    };
    match src {
        // A `data:` src decodes inline — no network, exactly like a parse-time
        // `data:` classic script (the Instagram bootloader path). Routing it
        // through the net-prepare below rejected the non-http(s) scheme and
        // fired `error` for a script a real browser runs.
        Some(src) if src.trim_start().starts_with("data:") => {
            match crate::img::decode_data_url(src.trim()) {
                Some(body) => {
                    let realm = ctx.realm().clone();
                    let job = NativeAsyncJob::with_realm(
                        async move |cell: &RefCell<&mut Context>| {
                            let mut guard = cell.borrow_mut();
                            eval_injected(&mut guard, "injected-data", &body);
                            fire_script_event(&mut guard, node_id, "load");
                            Ok(JsValue::undefined())
                        },
                        realm,
                    );
                    ctx.enqueue_job(job.into());
                }
                None => fire_script_event(ctx, node_id, "error"),
            }
        }
        Some(src) if !src.trim().is_empty() => {
            match page_net_prepare(ctx, &src, String::from("GET"), None, vec![]) {
                // Blocked/capped/cross-private: report a failed load like a browser.
                None => fire_script_event(ctx, node_id, "error"),
                Some((_handle, request)) => {
                    phase(&format!("src: INJECT {}", request.url));
                    let name = request.url.to_string();
                    let realm = ctx.realm().clone();
                    let job = NativeAsyncJob::with_realm(
                        async move |cell: &RefCell<&mut Context>| {
                            // Await without borrowing the context (so injected
                            // loads overlap like every other async fetch).
                            let result = crate::http::fetch(&request).await;
                            let mut guard = cell.borrow_mut();
                            match result {
                                // HTML §"fetch a classic script": only an OK (2xx)
                                // response runs. A non-ok status (a 404'd webpack
                                // chunk, a 5xx) is a load FAILURE — fire `error`,
                                // never execute the error-page body as script.
                                // (Running a 404's HTML body as JS produced a
                                // spurious `SyntaxError: unexpected token '<'`; the
                                // loader's own onerror — webpack's ChunkLoadError —
                                // is the correct, faithful signal instead.)
                                Ok(resp) if (200..300).contains(&resp.status) => {
                                    let body =
                                        crate::http::decode_body(&resp.content_type, &resp.body);
                                    eval_injected(&mut guard, &name, body.as_bytes());
                                    fire_script_event(&mut guard, node_id, "load");
                                }
                                _ => fire_script_event(&mut guard, node_id, "error"),
                            }
                            Ok(JsValue::undefined())
                        },
                        realm,
                    );
                    ctx.enqueue_job(job.into());
                }
            }
        }
        _ if !text.trim().is_empty() => {
            // Inline injected script: evaluate its text. Run as a (ready) async
            // job so we don't re-enter `ctx.eval` from inside this syscall.
            let realm = ctx.realm().clone();
            let job = NativeAsyncJob::with_realm(
                async move |cell: &RefCell<&mut Context>| {
                    let mut guard = cell.borrow_mut();
                    eval_injected(&mut guard, "injected-inline", text.as_bytes());
                    Ok(JsValue::undefined())
                },
                realm,
            );
            ctx.enqueue_job(job.into());
        }
        _ => {}
    }
    Ok(JsValue::undefined())
}

/// `__dom_load_injected_stylesheet(nodeId)` — a `<link rel=stylesheet>` that
/// page JS inserted into the live document. A real browser fetches the sheet
/// and fires `load` (or `error`) on the element; TRust never did, so a loader
/// that waits on `link.onload` hung forever. This is exactly how webpack's
/// mini-css-extract chunk loader resolves a code-split chunk's CSS: it injects
/// the `<link>` and resolves the chunk promise on the link's `load` event. With
/// no event, `__webpack_require__.e(chunk)` stays pending → a `Promise.all` of
/// chunks (every `React.lazy` route — Twitch's whole page body) never resolves →
/// the route's Suspense shows its spinner forever. We fetch (cap-/SSRF-gated,
/// like injected scripts) and fire `load` on a 2xx else `error`. On success the
/// CSS body is FOLDED INTO THE LIVE CASCADE at the link's document position
/// (HTML §4.2.4: obtaining the resource creates the sheet and adds it to the
/// document's style sheets) — a code-split app ships its LAYOUT in these
/// chunks, and dropping them left every late-loaded route unstyled (Steam's
/// login: the QR frame's width and the 14px checkbox cap live in chunk CSS;
/// without them the QR rendered intrinsic-tiny and the 256px check-mark SVG
/// rendered giant).
fn sys_load_injected_stylesheet(
    _: &JsValue,
    args: &[JsValue],
    ctx: &mut Context,
) -> JsResult<JsValue> {
    let (node_id, href) = {
        let dom = page_dom(ctx);
        let d = dom.borrow();
        let Some(id) = arg_node(&d, args, 0) else {
            return Ok(JsValue::undefined());
        };
        (id, d.attr(id, "href").map(str::to_string))
    };
    let Some(href) = href.filter(|h| !h.trim().is_empty()) else {
        return Ok(JsValue::undefined());
    };
    match page_net_prepare(ctx, &href, String::from("GET"), None, vec![]) {
        // Blocked/capped/cross-private: a failed load, like a browser.
        None => fire_script_event(ctx, node_id, "error"),
        Some((_handle, request)) => {
            phase(&format!("css: INJECT {}", request.url));
            let realm = ctx.realm().clone();
            let job = NativeAsyncJob::with_realm(
                async move |cell: &RefCell<&mut Context>| {
                    let result = crate::http::fetch(&request).await;
                    let mut guard = cell.borrow_mut();
                    match result {
                        Ok(resp) if (200..300).contains(&resp.status) => {
                            let css = crate::http::decode_body(&resp.content_type, &resp.body);
                            page_dom(&mut guard)
                                .borrow_mut()
                                .attach_sheet_to_link(node_id, css);
                            fire_script_event(&mut guard, node_id, "load");
                        }
                        _ => fire_script_event(&mut guard, node_id, "error"),
                    }
                    Ok(JsValue::undefined())
                },
                realm,
            );
            ctx.enqueue_job(job.into());
        }
    }
    Ok(JsValue::undefined())
}

/// Evaluate an injected script's source in the page realm, routing any error
/// to `__trust.errors` (so the `JS:n!` badge + diagnostics see it) and
/// surviving a Boa VM panic — one bad injected script can't kill the actor.
fn eval_injected(ctx: &mut Context, name: &str, source: &[u8]) {
    let res = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
        // Same exact `ctx.eval` unroll as `run_script`, so a dynamically
        // injected `<script>` (webpack chunk loaders inject many, sometimes
        // large, ones) lands in the parse/compile/execute split instead of
        // being invisible — it runs inside an async job future the executor
        // awaits, which the per-loop drain timer doesn't cover.
        let src = Source::from_bytes(source).with_path(std::path::Path::new(name));
        let t = phase_begin();
        let script = boa_engine::Script::parse(src, None, ctx)?;
        phase_end(Phase::Parse, t);
        let t = phase_begin();
        script.codeblock(ctx)?;
        phase_end(Phase::Compile, t);
        let t = phase_begin();
        let r = script.evaluate(ctx);
        phase_end(Phase::Execute, t);
        r
    }));
    if let Ok(Err(err)) = res {
        let msg = format!("{name}: {err}");
        let esc = msg
            .replace('\\', "\\\\")
            .replace('"', "\\\"")
            .replace('\n', "\\n");
        let _ = ctx.eval(Source::from_bytes(
            format!("__trust.errors.push(\"{esc}\")").as_bytes(),
        ));
    }
}

/// Fire a `load`/`error` event on an injected script element (and call its
/// `on<type>` handler), for loaders that wait on `script.onload`.
fn fire_script_event(ctx: &mut Context, node_id: usize, ty: &str) {
    let _ = ctx.eval(Source::from_bytes(
        format!("__trust.scriptEvent({node_id}, \"{ty}\")").as_bytes(),
    ));
}

/// `document.cookie` getter: the jar's non-HttpOnly name=value pairs
/// for this exact host (RAM-only jar; see http.rs). Empty without a net grant.
fn sys_cookie_get(_: &JsValue, _: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let cookies = ctx
        .realm()
        .host_defined()
        .get::<PageNet>()
        .map(|n| crate::http::cookies_for_js(&n.page))
        .unwrap_or_default();
    Ok(str_value(&cookies))
}

/// `document.cookie = "..."`: store in the RAM-only exact-host jar so
/// later reads and matching requests see it.
fn sys_cookie_set(_: &JsValue, args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let line = arg_str(args, 0, ctx);
    if let Some(page) = ctx
        .realm()
        .host_defined()
        .get::<PageNet>()
        .map(|n| n.page.clone())
    {
        crate::http::set_cookie_from_js(&page, &line);
    }
    Ok(JsValue::undefined())
}

/// Parse the shared `(url, method, body, content_type, headers)` arguments of
/// the fetch syscalls: method normalized, body paired with its content type,
/// extra request headers parsed from the newline-delimited `k\nv\nk\nv` blob
/// the prelude builds from `setRequestHeader`/`init.headers`.
#[allow(clippy::type_complexity)]
fn fetch_args(
    args: &[JsValue],
    ctx: &mut Context,
) -> (
    String,
    String,
    Option<(String, Vec<u8>)>,
    Vec<(String, String)>,
) {
    let url_arg = arg_str(args, 0, ctx);
    let mut method: String = arg_str(args, 1, ctx)
        .chars()
        .filter(|c| c.is_ascii_alphabetic())
        .collect();
    method.make_ascii_uppercase();
    if method.is_empty() {
        method = String::from("GET");
    }
    let body = args
        .get(2)
        .filter(|v| !v.is_null_or_undefined())
        .map(|v| arg_bytes_latin1(v, ctx));
    let content_type = args
        .get(3)
        .filter(|v| !v.is_null_or_undefined())
        .map(|_| arg_str(args, 3, ctx));
    let body = body.map(|bytes| {
        (
            content_type.unwrap_or_else(|| String::from("text/plain;charset=UTF-8")),
            bytes,
        )
    });
    let headers = args
        .get(4)
        .filter(|v| !v.is_null_or_undefined())
        .map(|_| parse_header_blob(&arg_str(args, 4, ctx)))
        .unwrap_or_default();
    (url_arg, method, body, headers)
}

/// Parse a `name\nvalue\nname\nvalue` header blob into pairs (empty names
/// dropped). The prelude joins headers this way; values hold no newlines.
fn parse_header_blob(blob: &str) -> Vec<(String, String)> {
    if blob.is_empty() {
        return Vec::new();
    }
    blob.split('\n')
        .collect::<Vec<_>>()
        .chunks(2)
        .filter_map(|c| match c {
            [k, v] if !k.is_empty() => Some(((*k).to_string(), (*v).to_string())),
            _ => None,
        })
        .collect()
}

/// The body as a byte-EXACT latin1 string (each byte → one code unit 0-255), so
/// `Response.arrayBuffer()` recovers the precise bytes — the UTF-8-lossy text is
/// fine for `.text()` but corrupts binary (e.g. a `.wasm` for `instantiate-
/// Streaming`). Carried as a 4th array element the text path ignores.
fn body_latin1(body: &[u8]) -> JsValue {
    str_value(&body.iter().map(|&b| b as char).collect::<String>())
}

/// Response headers as the same `name\nvalue\n…` blob the request side uses
/// (`parse_header_blob` is its inverse); the prelude splits it back into the
/// fetch `Response.headers` / XHR `getResponseHeader` map. Values never hold
/// newlines (read_line strips them), but strip defensively anyway.
fn headers_to_blob(headers: &[(String, String)]) -> String {
    let mut s = String::new();
    for (k, v) in headers {
        if k.is_empty() {
            continue;
        }
        if !s.is_empty() {
            s.push('\n');
        }
        s.push_str(k);
        s.push('\n');
        s.push_str(&v.replace('\n', " "));
    }
    s
}

/// A fetched response as the `[status, content_type, body_text, body_bytes,
/// header_blob]` array the prelude expects (`body_bytes` is byte-exact for
/// `arrayBuffer`; `header_blob` carries ALL response headers — pages read
/// API results out of band, e.g. Steam's `x-eresult`).
fn response_to_array(resp: &crate::http::Response, ctx: &mut Context) -> JsValue {
    let vals = vec![
        JsValue::from(f64::from(resp.status)),
        str_value(&resp.content_type),
        str_value(&String::from_utf8_lossy(&resp.body)),
        body_latin1(&resp.body),
        str_value(&headers_to_blob(&resp.headers)),
    ];
    JsArray::from_iter(vals, ctx).into()
}

/// Same `[status, content_type, body_text, body_bytes, header_blob]` shape
/// from a cached response.
fn cached_to_array(c: &crate::http::CachedResp, ctx: &mut Context) -> JsValue {
    let vals = vec![
        JsValue::from(f64::from(c.status)),
        str_value(&c.content_type),
        str_value(&String::from_utf8_lossy(&c.body)),
        body_latin1(&c.body),
        str_value(&headers_to_blob(&c.headers)),
    ];
    JsArray::from_iter(vals, ctx).into()
}

/// An existing shared-cache entry (in-flight or done) for a page GET, or
/// None. Lets the page's own `fetch()` JOIN a request for a chunk we
/// already have/are fetching, without creating a cache entry for an
/// uncached API GET (a miss falls through to a normal, uncached fetch).
fn peek_page_cache(ctx: &mut Context, target: &str) -> Option<crate::http::SharedFetch> {
    let host = ctx.realm().host_defined();
    let net = host.get::<PageNet>()?;
    let resolved = net.page.join(target).ok()?;
    net.cache.peek(&resolved)
}

fn store_bucket(ctx: &mut Context, args: &[JsValue]) -> Option<(WebStorage, String)> {
    let kind = arg_str(args, 0, ctx);
    let host = ctx.realm().host_defined();
    let store = host.get::<PageStore>()?;
    Some((store.map.clone(), format!("{kind}:{}", store.origin)))
}

fn sys_storage_get(_: &JsValue, args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let key = arg_str(args, 1, ctx);
    let Some((map, bucket)) = store_bucket(ctx, args) else {
        return Ok(JsValue::null());
    };
    let map = map.lock().unwrap();
    Ok(match map.get(&bucket).and_then(|b| b.get(&key)) {
        Some(v) => str_value(v),
        None => JsValue::null(),
    })
}

fn sys_storage_set(_: &JsValue, args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let key = arg_str(args, 1, ctx);
    let value = arg_str(args, 2, ctx);
    if let Some((map, bucket)) = store_bucket(ctx, args) {
        map.lock()
            .unwrap()
            .entry(bucket)
            .or_default()
            .insert(key, value);
    }
    Ok(JsValue::undefined())
}

fn sys_storage_remove(_: &JsValue, args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let key = arg_str(args, 1, ctx);
    if let Some((map, bucket)) = store_bucket(ctx, args)
        && let Some(b) = map.lock().unwrap().get_mut(&bucket)
    {
        b.remove(&key);
    }
    Ok(JsValue::undefined())
}

fn sys_storage_clear(_: &JsValue, args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    if let Some((map, bucket)) = store_bucket(ctx, args) {
        map.lock().unwrap().remove(&bucket);
    }
    Ok(JsValue::undefined())
}

fn sys_storage_key(_: &JsValue, args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let index = args.get(1).and_then(JsValue::as_number).unwrap_or(-1.0);
    let Some((map, bucket)) = store_bucket(ctx, args) else {
        return Ok(JsValue::null());
    };
    let map = map.lock().unwrap();
    let key = (index >= 0.0)
        .then(|| {
            map.get(&bucket)
                .and_then(|b| b.keys().nth(index as usize).cloned())
        })
        .flatten();
    Ok(match key {
        Some(k) => str_value(&k),
        None => JsValue::null(),
    })
}

fn sys_storage_len(_: &JsValue, args: &[JsValue], ctx: &mut Context) -> JsResult<JsValue> {
    let Some((map, bucket)) = store_bucket(ctx, args) else {
        return Ok(JsValue::from(0));
    };
    let n = map.lock().unwrap().get(&bucket).map_or(0, |b| b.len());
    Ok(JsValue::from(n as f64))
}

// ---- Page transformation ---------------------------------------------

/// Scripts the page may execute as classic scripts.
fn is_classic(type_attr: &Option<String>) -> bool {
    match type_attr {
        None => true,
        Some(t) => matches!(
            t.trim().to_ascii_lowercase().as_str(),
            "" | "text/javascript" | "application/javascript" | "text/ecmascript"
        ),
    }
}

/// Most settle-loop timer callbacks per page, beyond which we declare
/// the page non-quiescent and render what exists.
const MAX_TICKS: usize = 200;

/// Print a JS-phase timeline marker against the shared trace clock, when
/// `TRUST_NET_TRACE=1`. Pairs with the net trace so a single load's wall
/// time can be attributed (compute vs network wait, per phase).
fn phase(label: &str) {
    if std::env::var_os("TRUST_NET_TRACE").is_some() {
        eprintln!("js : @{:>6}ms {label}", crate::http::trace_ms());
    }
}

/// Everything a page transformation needs from the outside world.
pub struct PageEnv {
    pub url: String,
    pub viewport: (u16, u16),
    /// Terminal cell size in pixels (width, height) — the picker's font
    /// size. The reported CSS-pixel viewport is `viewport * cell_px`, so
    /// the page sees a window proportional to the real terminal (a wide
    /// terminal looks like a wide browser; SPAs/responsive layouts and
    /// infinite-scrollers measure against it). 8x16 nominal in tests.
    pub cell_px: (u16, u16),
    /// Pre-fetched external scripts keyed by raw `src` attribute
    /// (None = the fetch failed). `Arc` so the parallel-parse pool can hand a
    /// body to a worker thread without cloning it — multi-MB bundles were
    /// being duplicated wholesale at the worst moment of the load.
    pub externals: Vec<(String, Option<std::sync::Arc<Vec<u8>>>)>,
    /// Pre-fetched `<link rel=stylesheet>` bodies keyed by raw `href`,
    /// for the display/visibility cascade (failed fetches are absent —
    /// fail-open, the page just renders un-hidden).
    pub sheets: Vec<(String, String)>,
    /// The shared per-page subresource cache (seeded with the announced
    /// module preloads). The module loader reads module bodies from it,
    /// speculative import prefetch fills it ahead of the loader, and the
    /// page's own `fetch()` joins it — so no chunk is fetched twice and
    /// the module graph downloads concurrently instead of one RTT at a
    /// time. See `http::PageCache`.
    pub cache: std::sync::Arc<crate::http::PageCache>,
    /// Runtime handle for page-initiated fetch/XHR; None = pages get no
    /// network at all (every request resolves to failure).
    pub net: Option<tokio::runtime::Handle>,
    /// Shared session storage; None gets a fresh page-lifetime map.
    pub storage: Option<WebStorage>,
    /// The page's `blob:` URL byte mirror (see `BlobMap`). Created by the
    /// caller so it survives the engine: `execute_js` keeps a clone on the
    /// `Response`, the app hangs it on the `Doc`, and the image pipeline
    /// resolves `blob:` `<img>` srcs from it — even after the page froze.
    pub blobs: BlobMap,
}

impl PageEnv {
    /// No network, no shared storage: the test/diagnostic default.
    #[cfg_attr(not(test), allow(dead_code))]
    pub fn bare(url: &str) -> Self {
        Self {
            url: url.to_string(),
            viewport: (80, 24),
            cell_px: (8, 16),
            externals: Vec::new(),
            sheets: Vec::new(),
            cache: std::sync::Arc::new(crate::http::PageCache::default()),
            net: None,
            storage: None,
            blobs: BlobMap::default(),
        }
    }
}

/// Format a rejected/thrown JS value for an error message: its display
/// form plus an Error's `.stack` when present (diagnostics are worthless
/// without it). Shared by promise-rejection tracking and module rejection.
fn describe_rejection(v: &JsValue, ctx: &mut Context) -> String {
    let mut s = format!("{}", v.display());
    if let Some(o) = v.as_object()
        && let Ok(st) = o.get(boa_engine::js_string!("stack"), ctx)
        && !st.is_undefined()
        && !st.is_null()
        && let Ok(st) = st.to_string(ctx)
        && !st.is_empty()
    {
        s.push_str(&format!("\n{}", st.to_std_string_lossy()));
    }
    s
}

/// Run a page's scripts against a real DOM and return the post-JS HTML.
/// Never fails: any error lands in the Outcome and the best available
/// document is returned.
/// Surfaces unhandled promise rejections — async component updates
/// (Lit's whole update path) fail THROUGH these, invisibly otherwise.
/// Reject records the reason; a later Handle retracts it; whatever
/// remains at drain time was genuinely unhandled.
struct PageHooks {
    rejections: RefCell<Vec<(boa_engine::JsObject, String)>>,
}

impl boa_engine::context::HostHooks for PageHooks {
    fn promise_rejection_tracker(
        &self,
        promise: &boa_engine::JsObject,
        operation: boa_engine::builtins::promise::OperationType,
        context: &mut Context,
    ) {
        use boa_engine::builtins::promise::{OperationType, PromiseState};
        match operation {
            OperationType::Reject => {
                let reason = boa_engine::object::builtins::JsPromise::from_object(promise.clone())
                    .ok()
                    .map(|p| match p.state() {
                        PromiseState::Rejected(v) => describe_rejection(&v, context),
                        _ => String::from("(rejection pending)"),
                    })
                    .unwrap_or_else(|| String::from("(unknown rejection)"));
                let mut pending = self.rejections.borrow_mut();
                if pending.len() < 32 {
                    pending.push((promise.clone(), reason));
                }
            }
            OperationType::Handle => {
                self.rejections
                    .borrow_mut()
                    .retain(|(p, _)| !boa_engine::JsObject::equals(p, promise));
            }
        }
    }
}

/// Best-effort scan of JS module source for its STATIC import specifiers,
/// so we can prefetch them concurrently BEFORE Boa's loader (which we run
/// serially, to keep module loading atomic) asks for them one at a time.
/// This is the engine's "preload scanner": it turns the static module
/// graph from sum-of-RTTs into depth-of-graph-times-RTT, like a browser.
/// Heuristic and fail-open — a false positive prefetches a dud (cached as
/// a failure, harmless), a false negative just falls back to the serial
/// fetch. Recognizes `import…from "x"`, `export…from "x"`, and bare
/// `import "x"`; only path-like specifiers (`/`, `./`, `../`, absolute
/// URL) are kept, which filters most stray matches.
///
/// Dynamic `import(...)` is deliberately NOT scanned: a router entry
/// dynamic-imports EVERY route (archive.org: 51), almost all lazy and
/// never loaded at boot, so prefetching them is pure waste and would
/// starve the real-module cap. The boot-time dynamic imports a page DOES
/// fire stay serial here — parallelizing those is the Boa concurrency
/// follow-up (they need the loader to interleave safely), not the
/// scanner's job.
fn scan_module_imports(src: &[u8]) -> Vec<String> {
    let mut out = Vec::new();
    let n = src.len();
    let is_ident = |b: u8| b.is_ascii_alphanumeric() || b == b'_' || b == b'$';
    let mut i = 0;
    while i < n {
        // Anchor on the keywords that introduce a module specifier.
        let kw = if src[i..].starts_with(b"from") {
            4
        } else if src[i..].starts_with(b"import") {
            6
        } else {
            i += 1;
            continue;
        };
        // Word boundary before (so `transform`/`reimport` don't match).
        if i > 0 && is_ident(src[i - 1]) {
            i += 1;
            continue;
        }
        let mut j = i + kw;
        while j < n && (src[j] as char).is_whitespace() {
            j += 1;
        }
        // `import(` is a DYNAMIC import — skip it (see the doc comment).
        if kw == 6 && j < n && src[j] == b'(' {
            i += kw;
            continue;
        }
        // A quoted string literal here is a STATIC specifier.
        if j < n && (src[j] == b'"' || src[j] == b'\'' || src[j] == b'`') {
            let quote = src[j];
            let start = j + 1;
            let mut k = start;
            while k < n && src[k] != quote && src[k] != b'\n' {
                k += 1;
            }
            if k < n && src[k] == quote {
                if let Ok(spec) = std::str::from_utf8(&src[start..k]) {
                    let path_like = spec.starts_with('/')
                        || spec.starts_with("./")
                        || spec.starts_with("../")
                        || spec.starts_with("http");
                    if path_like && !spec.contains("${") {
                        out.push(spec.to_string());
                    }
                }
                i = k + 1;
                continue;
            }
        }
        i += kw; // not a specifier site; step past the keyword
    }
    out
}

/// Fire concurrent prefetches for `body`'s import specifiers into the
/// shared cache, resolved against `base`. Cap- and `subresource_allowed`-
/// gated and counted like any page fetch; deduped against in-flight
/// entries. The loader, reaching these modules moments later, finds them
/// already in flight (or done) instead of paying a fresh round trip.
fn speculate_imports(ctx: &mut Context, base: &url::Url, body: &[u8]) {
    let specs = scan_module_imports(body);
    if specs.is_empty() {
        return;
    }
    let host = ctx.realm().host_defined();
    let Some(net) = host.get::<PageNet>() else {
        return;
    };
    let handle = net.handle.clone();
    let cache = net.cache.clone();
    for spec in specs.into_iter().take(MAX_SPECULATIVE_IMPORTS) {
        let Some(resolved) = base
            .join(&spec)
            .ok()
            .filter(|u| matches!(u.scheme(), "http" | "https"))
        else {
            continue;
        };
        if cache.peek(&resolved).is_some() {
            continue; // already prefetched, in flight, or done
        }
        if !crate::http::subresource_allowed(&net.page, &resolved)
            || net.fetched.get() >= MAX_PAGE_FETCHES
            || net.budget.exhausted()
        {
            continue;
        }
        net.fetched.set(net.fetched.get() + 1);
        phase(&format!("src: SPECULATE {resolved}"));
        cache.prefetch(&handle, resolved);
    }
}

/// ES modules over the web: imports resolve against the importing
/// module's URL (carried as the Source path), fetch through the page's
/// net grant with the same caps and guards as everything else, and
/// cache per page. Bare specifiers ("lit") have no resolution here and
/// reject — honestly.
struct WebModuleLoader {
    page: Option<url::Url>,
    /// Parsed `Module` records, deduped per page (Boa needs one record
    /// per specifier — re-parsing trips an identity assert).
    modules: RefCell<std::collections::HashMap<String, boa_engine::Module>>,
    /// The shared subresource cache: module bodies arrive here from the
    /// initial prefetch, from speculative import prefetch (fired ahead of
    /// this loader as each module is scanned), and from this loader's own
    /// fetches. A `Shared` future per URL means a body in flight is never
    /// re-requested.
    body: std::sync::Arc<crate::http::PageCache>,
}

impl boa_engine::module::ModuleLoader for WebModuleLoader {
    async fn load_imported_module(
        self: Rc<Self>,
        referrer: boa_engine::module::Referrer,
        specifier: JsString,
        context: &RefCell<&mut Context>,
    ) -> JsResult<boa_engine::Module> {
        let spec = specifier.to_std_string_lossy();
        // `data:` URL modules (RFC 2397): decode the body inline — no network,
        // no shared cache. Vite's modern-browser probe STATICALLY imports
        // `data:text/javascript,if(!import.meta.resolve)throw…` to feature-test;
        // failing to load it makes Vite fall back to its legacy SystemJS/core-js
        // build (joinpeertube.org). Registered under the data: URL itself so a
        // re-import returns the one record (Boa's per-specifier identity rule).
        if spec.starts_with("data:") {
            if let Some(cached) = self.modules.borrow().get(&spec) {
                return Ok(cached.clone());
            }
            let body = crate::img::decode_data_url(&spec).ok_or_else(|| {
                boa_engine::JsNativeError::typ()
                    .with_message(format!("cannot decode data: module '{spec}'"))
            })?;
            let module = {
                let mut ctx = context.borrow_mut();
                let t = phase_begin();
                let m = boa_engine::Module::parse(
                    Source::from_bytes(&body).with_path(std::path::Path::new(&spec)),
                    None,
                    &mut ctx,
                )?;
                phase_end(Phase::Parse, t);
                m
            };
            self.modules
                .borrow_mut()
                .insert(spec.clone(), module.clone());
            return Ok(module);
        }
        // The HTML spec's rule: only absolute URLs and /-, ./-, ../-
        // prefixed paths resolve. Bare specifiers ("lit") need an
        // import map we don't have — reject, don't guess.
        if !(spec.starts_with('/')
            || spec.starts_with("./")
            || spec.starts_with("../")
            || url::Url::parse(&spec).is_ok())
        {
            return Err(boa_engine::JsNativeError::typ()
                .with_message(format!("cannot resolve module specifier '{spec}'"))
                .into());
        }
        let base = referrer
            .path()
            .and_then(|p| p.to_str())
            .and_then(|s| url::Url::parse(s).ok())
            .or_else(|| self.page.clone());
        let resolved = base
            .as_ref()
            .and_then(|b| b.join(&spec).ok())
            .filter(|u| matches!(u.scheme(), "http" | "https"))
            .ok_or_else(|| {
                boa_engine::JsNativeError::typ()
                    .with_message(format!("cannot resolve module specifier '{spec}'"))
            })?;
        let key = resolved.to_string();
        if let Some(cached) = self.modules.borrow().get(&key) {
            phase(&format!("module CACHE-HIT {key}"));
            return Ok(cached.clone());
        }

        let fail = || {
            boa_engine::JsNativeError::typ()
                .with_message(format!("module fetch failed or blocked: {key}"))
        };
        // The body comes from the shared cache: already there if the
        // initial prefetch announced it or a speculative prefetch ran
        // ahead of us; otherwise we start it now. Either way one request
        // per URL — the bundler's own `fetch()` of this chunk joins it.
        //
        // We acquire the shared fetch under a brief borrow, then `.await`
        // it WITHOUT holding the context, so the sibling module-load jobs
        // the spec's `inner_load` enqueued concurrently actually overlap
        // on the network instead of each parking the page thread in turn.
        // (The old code BLOCKED here — `block_on_fetch`'s synchronous recv
        // serialized the whole graph into one-fetch-per-RTT and let a
        // single slow chunk stall everything. Awaiting is what the async
        // `ModuleLoader` trait + the concurrent job executor are for.)
        let hit = self.body.peek(&resolved).is_some();
        let fetch = {
            let mut ctx = context.borrow_mut();
            module_fetch(&mut ctx, &self.body, &resolved)
        }
        .ok_or_else(fail)?;
        let cached = fetch.await.ok().ok_or_else(fail)?;
        phase(&format!(
            "module {} {key}",
            if hit { "CACHED" } else { "NETWORK" }
        ));
        // Re-check after the await: a concurrent load of the SAME url may
        // have parsed it while we were on the wire. Module identity per
        // url MUST be stable — Boa's per-referrer `loaded_modules` holds a
        // single record and asserts it — so the first job to reach `parse`
        // wins and every other sharer returns that record. Parse + insert
        // below is synchronous (no `.await` between this check and the
        // insert), so exactly one job parses a given url; the re-check
        // can't race it.
        if let Some(cached) = self.modules.borrow().get(&key) {
            return Ok(cached.clone());
        }
        let module = {
            let mut ctx = context.borrow_mut();
            // Prime the NEXT wave before parsing this one: prefetch this
            // module's own imports so they're in flight before the loader
            // asks for each.
            speculate_imports(&mut ctx, &resolved, &cached.body);
            let t = phase_begin();
            let m = boa_engine::Module::parse(
                Source::from_bytes(&cached.body).with_path(std::path::Path::new(&key)),
                None,
                &mut ctx,
            )?;
            phase_end(Phase::Parse, t);
            m
        };
        self.modules.borrow_mut().insert(key, module.clone());
        Ok(module)
    }

    /// Populate `import.meta` for a module. We expose `import.meta.url` — the
    /// module's own absolute URL (the path we attach at parse time) — which
    /// bundlers rely on to resolve sibling chunks: Vite/SvelteKit's preload
    /// helper does `new URL("../nodes/x.js", import.meta.url)`, so a missing
    /// `url` makes every relative resolution throw "Invalid URL" and the app
    /// never boots.
    fn init_import_meta(
        self: Rc<Self>,
        import_meta: &boa_engine::JsObject,
        module: &boa_engine::Module,
        context: &mut Context,
    ) {
        let url = module
            .path()
            .and_then(|p| p.to_str())
            .map(str::to_string)
            .or_else(|| self.page.as_ref().map(url::Url::to_string))
            .unwrap_or_default();
        let _ = import_meta.set(
            boa_engine::js_string!("url"),
            JsString::from(url.clone()),
            false,
            context,
        );
        // `import.meta.resolve(spec)` → spec resolved against this module's URL
        // (HTML "HostGetImportMetaProperties"). Vite's modern-browser probe
        // imports a data: module that throws `if(!import.meta.resolve)`, so
        // without this the page detects a "legacy" browser and loads its
        // SystemJS/core-js fallback. The module's own URL is captured.
        let resolve = NativeFunction::from_copy_closure_with_captures(
            |_this, args, base: &JsString, ctx| {
                let spec = args.first().cloned().unwrap_or_default().to_string(ctx)?;
                let base = base.to_std_string_lossy();
                match url::Url::parse(&base)
                    .ok()
                    .and_then(|b| b.join(&spec.to_std_string_lossy()).ok())
                {
                    Some(u) => Ok(JsString::from(u.to_string()).into()),
                    None => Err(boa_engine::JsNativeError::typ()
                        .with_message("Failed to resolve module specifier")
                        .into()),
                }
            },
            JsString::from(url),
        )
        .to_js_function(context.realm());
        let _ = import_meta.set(boa_engine::js_string!("resolve"), resolve, false, context);
    }
}

/// Run one parsed module to completion: load (imports fetch through the
/// loader), link, evaluate, driving the job queue until the promise
/// settles or the budget calls time.
fn run_module(
    ctx: &mut Context,
    name: &str,
    source: &[u8],
    path: &str,
    budget: &Budget,
    outcome: &mut Outcome,
    register: Option<(&Rc<WebModuleLoader>, &str)>,
) {
    let parsed = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
        let t = phase_begin();
        let m = boa_engine::Module::parse(
            Source::from_bytes(source).with_path(std::path::Path::new(path)),
            None,
            ctx,
        );
        phase_end(Phase::Parse, t);
        m
    }));
    let module = match parsed {
        Ok(Ok(m)) => m,
        Ok(Err(err)) => {
            outcome.errors.push(format!("{name}: {err}"));
            return;
        }
        Err(_) => {
            outcome
                .errors
                .push(format!("{name}: engine panic (Boa bug) — page JS halted"));
            outcome.panicked = true;
            return;
        }
    };
    // Register the entry module in the loader cache under its own URL BEFORE
    // evaluating it, so a later `import` of the entry's own URL (archive.org
    // does this) reuses THIS instance instead of re-fetching + parsing a
    // second Module record for the same specifier — which both wastes a
    // fetch per chunk (cascading through its import subgraph) and risks the
    // duplicate-record identity assert. One tracked Module, as intended.
    if let Some((loader, key)) = register {
        loader
            .modules
            .borrow_mut()
            .insert(key.to_string(), module.clone());
    }
    let evaluated = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
        let promise = module.load_link_evaluate(ctx);
        // Drive load/link/evaluate — and any fetches the module's
        // top-level code kicks off — to quiescence under the runtime
        // (concurrent, budget-bounded), then read the settled state.
        run_jobs_into(ctx, budget, outcome);
        match promise.state() {
            boa_engine::builtins::promise::PromiseState::Pending => {
                Some(String::from("module still pending at budget end"))
            }
            boa_engine::builtins::promise::PromiseState::Fulfilled(_) => None,
            boa_engine::builtins::promise::PromiseState::Rejected(err) => {
                // Was a generic string while the cyclic-module `Debug`
                // recursion made formatting a module value dangerous; the
                // fork patched that, so report the real reason + stack.
                Some(describe_rejection(&err, ctx))
            }
        }
    }));
    match evaluated {
        Ok(None) => {}
        Ok(Some(err)) => outcome.errors.push(format!("{name}: {err}")),
        Err(_) => {
            outcome
                .errors
                .push(format!("{name}: engine panic (Boa bug) — page JS halted"));
            outcome.panicked = true;
        }
    }
}

/// A page loaded and settled: the engine + arena, alive. The one-shot
/// `transform` serializes and drops it; the page actor keeps it and
/// dispatches events into it.
struct LoadedPage {
    ctx: Context,
    dom: Rc<RefCell<Dom>>,
    budget: Rc<Budget>,
    outcome: Outcome,
    started: Instant,
    page_url: Option<url::Url>,
    hooks: Rc<PageHooks>,
    /// The render-canonical form (`render_canonical`) of the last `Updated` we
    /// emitted, for render dedup. The actor re-serializes on every dirty wake but
    /// must NOT emit an Updated unless what we PAINT changed — else the app
    /// re-parses + re-lays-out its whole doc (a ~1s UI freeze) for a change that
    /// paints nothing: a mutation to a dropped element (`<style>`, hidden
    /// subtree) OR to a non-rendered attribute (`alt`/`class`/`title`/`aria-*` —
    /// Twitch rotates a co-streamer's name in a loaded avatar's `alt` text every
    /// second). Serializing + canonicalizing to compare is cheap (~ms); the
    /// app-side layout this skips is what froze the UI.
    last_render: Option<String>,
    /// The clipped scroll-region nodes the app confirmed it laid out
    /// (`PageCmd::LiveRegions`). A mutation is patched only when confined to one
    /// of these (INCREMENTAL_LAYOUT_PLAN.md §4b) — everything else takes the full
    /// path, so a non-region scroll box can't trigger a failed-patch→resync.
    live_regions: std::collections::HashSet<usize>,
    /// The cached inline IFC-boundary nodes the app can splice (`Doc.boundaries`,
    /// via `PageCmd::LiveBoundaries`). A mutation whose nearest IFC boundary is
    /// here is patched as a general inline `Patched` (Tier 2); everything else
    /// takes the full path (INCREMENTAL_LAYOUT_PLAN.md §14).
    live_boundaries: std::collections::HashSet<usize>,
    /// Per-boundary render-dedup baselines (INCREMENTAL_LAYOUT_PLAN.md §12c, W1):
    /// the `render_canonical` form of the last patch we emitted for each relayout
    /// boundary, keyed by its `data-trust-node`. The patch path serializes ONLY a
    /// dirty boundary's subtree (never the whole document) and drops the patch
    /// when its canonical render is unchanged — the per-boundary analogue of
    /// `last_render`, so an invisible mutation inside a boundary (an `alt`/`aria`
    /// rotation) still emits nothing. Populated lazily on the first patch per
    /// boundary; cleared whenever a full `Updated` resyncs the whole document
    /// (the app re-laid everything, so every baseline is moot) and pruned of
    /// boundaries that left the tree.
    boundary_render: std::collections::HashMap<usize, String>,
}

/// Parse, run scripts, fire lifecycle, settle. Err(outcome) means
/// "render the original HTML with this outcome" (no scripts, or our
/// own plumbing failed).
fn load_page(
    html: &str,
    env: &PageEnv,
    ws_events: Option<tokio::sync::mpsc::Sender<(usize, crate::ws::WsIn)>>,
    fetch_events: Option<FetchSender>,
    worker_events: Option<WorkerSender>,
) -> Result<LoadedPage, Outcome> {
    phase("load_page start (DOM parse)");
    phases_reset();
    let page_url = env.url.as_str();
    let viewport = env.viewport;
    let cell_px = env.cell_px;
    let externals = &env.externals;
    let mut outcome = Outcome::default();
    let dom = Rc::new(RefCell::new(Dom::parse_document(html)));
    // The CSS-pixel viewport (cols/rows × the terminal's cell size) that the
    // cascade evaluates `@media` against — the same window the page sees as
    // innerWidth/innerHeight below.
    dom.borrow_mut().set_viewport_px(
        u32::from(viewport.0) * u32::from(cell_px.0.max(1)),
        u32::from(viewport.1) * u32::from(cell_px.1.max(1)),
    );
    // The terminal cell size, for the live serializer's px→row `scrollTop` bake.
    dom.borrow_mut().set_cell_px(cell_px.0, cell_px.1);
    if !env.sheets.is_empty() {
        dom.borrow_mut().attach_external_sheets(&env.sheets);
    }
    // Drop classic scripts marked `nomodule`: they target user agents WITHOUT
    // module support, and we execute module scripts, so a real browser never
    // runs them (HTML §"prepare the script element": a classic+nomodule script
    // is not executed when module scripts are supported). Running them loads the
    // legacy polyfill payload (e.g. core-js) that force-replaces platform globals
    // like `URL` with its own — exactly the build a modern browser skips. Module
    // scripts ignore `nomodule`, so this only filters classic ones.
    let scripts: Vec<_> = {
        let d = dom.borrow();
        d.scripts()
            .into_iter()
            .filter(|(_, _, ty, node)| !(is_classic(ty) && d.attr(*node, "nomodule").is_some()))
            .collect()
    };
    if scripts.is_empty() {
        // No JS ran: the original bytes stand (so <noscript> content
        // still renders, as it should).
        return Err(outcome);
    }

    let started = Instant::now();
    let parsed_url = url::Url::parse(page_url).ok();
    // The document base URL (HTML §4.2.3): the page URL, overridden by the
    // first `<base href>`. Relative entry-script/module `src`s resolve against
    // it, not the page URL — peer.tube sets `<base href="/client/en-US/">` and
    // references its scripts relatively, so resolving against the page URL hits
    // the SPA catch-all (every unknown path returns index.html). Mirrors the
    // prefetch's `base_with_doc_base`, so the engine's module URLs agree with
    // the seeded cache keys.
    let base_url = {
        let d = dom.borrow();
        let mut b = parsed_url.clone();
        for id in d.descendants(crate::dom::DOCUMENT) {
            if d.tag_name(id) == Some("base")
                && let Some(href) = d.attr(id, "href")
                && let Some(j) = parsed_url.as_ref().and_then(|u| u.join(href.trim()).ok())
            {
                b = Some(j);
                break;
            }
        }
        b
    };
    let loader = Rc::new(WebModuleLoader {
        page: base_url.clone(),
        modules: RefCell::new(std::collections::HashMap::new()),
        body: env.cache.clone(),
    });
    let (mut ctx, hooks) = page_context_with(Some(loader.clone()));
    let budget = Rc::new(Budget::new(WALL_BUDGET));
    {
        let mut host = ctx.realm().host_defined_mut();
        host.insert(PageDom(dom.clone()));
        // WebAssembly engine state. Unconditional (no net/actor needed — wasm is
        // local computation), available on both the resident-actor and one-shot
        // `transform` paths. Lazily allocates its engine on first use, so a page
        // that never touches wasm pays nothing.
        host.insert(PageWasm::new());
        host.insert(PageStore {
            map: env.storage.clone().unwrap_or_default(),
            origin: parsed_url
                .as_ref()
                .map(|u| u.origin().ascii_serialization())
                .unwrap_or_else(|| String::from("null")),
        });
        // The blob byte mirror (the caller keeps the other clone — see
        // `PageEnv.blobs`); unconditional, like PageStore: pages mint blob
        // image URLs with or without net.
        host.insert(PageBlobs(env.blobs.clone()));
        if let (Some(handle), Some(page)) = (env.net.clone(), parsed_url.clone()) {
            host.insert(PageNet {
                handle,
                page,
                budget: budget.clone(),
                fetched: std::cell::Cell::new(0),
                dispatch: std::cell::Cell::new(false),
                fetch_events: fetch_events.clone(),
                next_fetch_id: std::cell::Cell::new(1),
                cache: env.cache.clone(),
            });
        }
        // Register the WebSocket host BEFORE any script runs. socket.io (Open
        // WebUI and friends) opens its WS during page load / DOMContentLoaded,
        // so the very first `new WebSocket(...)` must already find a `PageWs`,
        // or `__ws_open` returns -1 and the socket is never opened on that
        // attempt — the page then has no transport for its streamed reply until
        // socket.io's reconnect timer fires at rest and retries, an avoidable
        // delay (it was the "took a while to hit the model" lag). Only the
        // resident-actor path supplies a `ws_events` sender; the one-shot
        // `transform` gets None (no actor to forward inbound frames to).
        if let (Some(ws_tx), Some(handle), Some(page)) =
            (ws_events, env.net.clone(), parsed_url.clone())
        {
            host.insert(PageWs {
                handle,
                page,
                events: ws_tx,
                sockets: RefCell::new(std::collections::HashMap::new()),
                next_id: std::cell::Cell::new(1),
            });
        }
        // Register the Worker host BEFORE any script runs, for the same reason
        // as PageWs: a page may `new Worker(...)` at load time. Only the
        // resident-actor path supplies a `worker_events` sender (the one-shot
        // `transform` gets None → `__worker_spawn` returns -1, no workers).
        if let (Some(worker_tx), Some(handle), Some(page)) =
            (worker_events, env.net.clone(), parsed_url.clone())
        {
            host.insert(PageWorkers {
                handle,
                page,
                events: worker_tx,
                workers: RefCell::new(std::collections::HashMap::new()),
                next_id: std::cell::Cell::new(1),
            });
        }
        // Geometry backing: a layout pass over this same arena answers the JS
        // box APIs. Needs an absolute base to resolve hrefs during layout; if
        // the page URL didn't parse, `__dom_rect` is simply absent and the
        // getters keep their viewport-box fallback.
        if let Some(base) = parsed_url.clone() {
            host.insert(PageGeom {
                base,
                width_cells: viewport.0,
                height_cells: viewport.1,
                cell_px,
                borders: crate::layout::borders_enabled(),
                cache: Rc::new(RefCell::new((u64::MAX, std::collections::HashMap::new()))),
            });
        }
    }
    if let Err(err) = register_syscalls(&mut ctx) {
        outcome.errors.push(format!("syscalls: {err}"));
        return Err(outcome);
    }
    // CSS-pixel viewport from the real terminal: cols/rows times the
    // terminal's cell pixel size (the picker's font size; 8x16 nominal).
    let cfg = format!(
        "globalThis.__trust_cfg = {{ url: \"{}\", ua: \"TRust/0.1\", width: {}, height: {}, hardwareConcurrency: {} }};",
        esc_js(page_url),
        u32::from(viewport.0) * u32::from(cell_px.0.max(1)),
        u32::from(viewport.1) * u32::from(cell_px.1.max(1)),
        // navigator.hardwareConcurrency reports the real host logical-processor
        // count (HTML NavigatorConcurrentHardware) — honest, not a fixed spoof.
        std::thread::available_parallelism()
            .map(|n| n.get())
            .unwrap_or(8),
    );
    // TRust lazy parsing (default on; `TRUST_NO_LAZY_PARSE` disables): enable
    // body-skip-at-parse and deferred compilation on this page thread before any
    // of the page's own scripts load. The prelude (next line) and the
    // image-cached compiles self-suppress, so they stay eager. The parallel-parse
    // workers get the same setting per-job (see `dispatch_parallel_parse`).
    set_lazy_enabled(lazy_parse_on());
    run_script(&mut ctx, "config", cfg.as_bytes(), &budget, &mut outcome);
    run_prelude(&mut ctx, &budget, &mut outcome);
    // Arm the function-execution census AFTER the prelude so it counts only the
    // page's own scripts (the lazy-parse sizing gate; `TRUST_FN_CENSUS`).
    if fn_census_on() {
        boa_engine::vm::fn_census::arm();
    }
    if !outcome.errors.is_empty() {
        // The prelude is ours: if it broke, render without JS and say so.
        return Err(outcome);
    }
    // Tenure the immortal platform graph (intrinsics + prelude) as the GC's
    // permanent generation, now that it's fully built and before any page
    // script allocates. This runs one collection (reclaiming prelude setup
    // garbage — and, on a reused thread, the previous page's platform) and then
    // flags the survivors so they stop being re-ref-counted every later
    // collection. See `gc_permgen_on`.
    if gc_permgen_on() {
        let _tenured = boa_engine::gc::retenure_permanent();
    }
    phase(&format!(
        "prelude done; {} top-level scripts",
        scripts.len()
    ));

    // CDN compile cache (Phase 2): hash each external body ONCE (`cdn_keys` —
    // SHA-256 over a multi-MB bundle was being paid at up to three decision
    // points). A library compiled on an earlier page of this session is
    // already a detached image — those scripts will be rehydrated, not
    // compiled, so they're excluded from the parse pool below and rehydrated
    // in the loop.
    let cdn_keys = cdn_cache_keys(&scripts, externals);
    let cache_hits = cdn_cache_hits(&cdn_keys);

    // Parallel parse (Step 5a): external classic scripts raw-parse on a worker
    // pool NOW, overlapping the rest of this thread's work (the prelude already
    // ran; earlier scripts' execution and later scripts' parse now overlap). The
    // loop below still compiles + runs each in document order — only the lex/
    // parse phase moved off this thread. Cache hits are skipped (no parse needed).
    let mut parse_pool =
        dispatch_parallel_parse(&scripts, externals, &cdn_keys, &cache_hits, &mut ctx);

    for (i, (src, inline, type_attr, node)) in scripts.iter().enumerate() {
        let script_started = Instant::now();
        if std::env::var_os("TRUST_NET_TRACE").is_some() {
            let label = src.as_deref().unwrap_or("<inline>");
            let ty = type_attr.as_deref().unwrap_or("classic");
            phase(&format!("script[{i}] start {ty} {label}"));
        }
        if !is_classic(type_attr) {
            // ES modules execute for real now; non-module foreign types
            // (importmap, json, ...) still skip.
            if type_attr.as_deref().is_some_and(|t| t.trim() == "module") {
                match src {
                    Some(src) => {
                        // Load the entry module THROUGH the loader via a
                        // synthetic importer (register) — do NOT let Boa
                        // run it as its own entry. archive.org dynamically
                        // imports its OWN entry URL; registering it under
                        // its URL keeps ONE tracked Module (a second record
                        // for the same specifier trips an identity assert
                        // whose panic stack-overflows formatting the cyclic
                        // graph). Its body comes from the shared cache (it
                        // was seeded as a classic <script>), and we
                        // speculatively prefetch its imports so the first
                        // wave is already in flight.
                        let resolved = base_url
                            .as_ref()
                            .and_then(|b| b.join(src).ok())
                            .filter(|u| matches!(u.scheme(), "http" | "https"));
                        let cached = resolved
                            .as_ref()
                            .and_then(|u| load_module_body(&mut ctx, &env.cache, u));
                        match (resolved, cached) {
                            (Some(resolved), Some(cached)) => {
                                let path = resolved.to_string();
                                speculate_imports(&mut ctx, &resolved, &cached.body);
                                run_module(
                                    &mut ctx,
                                    src,
                                    &cached.body,
                                    &path,
                                    &budget,
                                    &mut outcome,
                                    Some((&loader, &path)),
                                );
                            }
                            _ => outcome.modules_skipped += 1,
                        }
                    }
                    None => {
                        let name = format!("inline-module#{}", i + 1);
                        // An inline module's base URL is the document base URL,
                        // so its relative imports resolve like the page's.
                        let base = base_url.as_ref().map(|u| u.as_str()).unwrap_or(page_url);
                        run_module(
                            &mut ctx,
                            &name,
                            inline.as_bytes(),
                            base,
                            &budget,
                            &mut outcome,
                            None,
                        );
                    }
                }
                if outcome.panicked {
                    break;
                }
                run_jobs_into(&mut ctx, &budget, &mut outcome);
            }
            phase(&format!(
                "script[{i}] done +{}ms",
                script_started.elapsed().as_millis()
            ));
            continue;
        }
        // `document.currentScript` is the classic script element while its
        // own code runs (null for modules and between scripts) — SvelteKit's
        // bootstrap reads `document.currentScript.parentElement` to find its
        // mount node, so without this the whole app fails to start.
        set_current_script(&mut ctx, Some(*node));
        match src {
            // `data:` URL classic script (RFC 2397): decode the body inline — no
            // network, no shared cache. Instagram/Facebook inline their entire
            // bootloader as `data:` scripts (the requireLazy/Env bootstrap), so
            // without this the page never starts. Mirrors the `data:` module path
            // in `load_imported_module`.
            Some(src) if src.starts_with("data:") => {
                let name = format!("data#{}", i + 1);
                match crate::img::decode_data_url(src) {
                    Some(body) => run_script(&mut ctx, &name, &body, &budget, &mut outcome),
                    None => outcome
                        .errors
                        .push(format!("{name}: cannot decode data: URL")),
                }
            }
            Some(src) => match externals.iter().find(|(k, _)| k == src) {
                Some((_, Some(body))) => {
                    // Route through the CDN cache: a reusable image is rehydrated
                    // (no parse, no compile); otherwise compile this page's copy —
                    // from the worker pool's raw parse when it took this script,
                    // else inline — and cache the image if it's realm-portable.
                    let prepared = parse_pool
                        .as_mut()
                        .filter(|p| p.was_dispatched(i))
                        .map(|pool| pool.take(i));
                    run_external_classic(
                        &mut ctx,
                        src,
                        body,
                        cdn_keys.get(&i).copied(),
                        prepared,
                        &budget,
                        &mut outcome,
                    );
                }
                _ => {
                    // Not in the parallel prefetch (beyond the prefetch lid, or
                    // its prefetch failed). A browser fetches a classic script
                    // wherever it sits in the document, so fetch it on demand
                    // THROUGH the shared cache — the prefetch cap is only a
                    // parallelism lid, never a correctness cliff (a code-split
                    // SPA whose chunk count exceeds the lid still boots). Bounded
                    // by MAX_PAGE_FETCHES + subresource_allowed via
                    // `page_net_prepare`. A deliberately blocked ad/tracker host
                    // stays silent (expected, not a page error); a genuine
                    // failure (no net / blocked / fetch error) keeps the old
                    // "not fetched" note.
                    let resolved = base_url
                        .as_ref()
                        .and_then(|b| b.join(src).ok())
                        .filter(|u| matches!(u.scheme(), "http" | "https"));
                    let blocked = resolved
                        .as_ref()
                        .and_then(|u| u.host_str())
                        .is_some_and(crate::http::is_ad_or_tracker_host);
                    if blocked {
                        // expected — ad/tracker block, no badge
                    } else if let Some(cached) = resolved
                        .as_ref()
                        .and_then(|u| load_module_body(&mut ctx, &env.cache, u))
                    {
                        run_external_classic(
                            &mut ctx,
                            src,
                            &cached.body,
                            None, // fetched on demand: no precomputed key (hashed inside)
                            None,
                            &budget,
                            &mut outcome,
                        );
                    } else {
                        outcome.errors.push(format!("{src}: not fetched"));
                    }
                }
            },
            None => {
                let name = format!("inline#{}", i + 1);
                run_script(&mut ctx, &name, inline.as_bytes(), &budget, &mut outcome);
            }
        }
        if outcome.panicked {
            // Engine bug: what the page built so far still renders. (Don't
            // touch the VM further — currentScript is moot once we break.)
            break;
        }
        set_current_script(&mut ctx, None);
        run_jobs_into(&mut ctx, &budget, &mut outcome);
        phase(&format!(
            "script[{i}] done +{}ms",
            script_started.elapsed().as_millis()
        ));
    }

    if !outcome.panicked {
        // Fire DOMContentLoaded, then RETURN at this "interactive"
        // boundary: scripts have run and the page shell is built, but the
        // post-DOMContentLoaded settle (which DRAINS background network —
        // e.g. an SPA's data fetches) is deferred to `settle_page`. The
        // actor paints the shell here before that settle, so a data-driven
        // page shows its chrome immediately instead of waiting for every
        // background fetch (see `page_actor`). The one-shot `transform`
        // path calls `settle_page` straight away, so its render is
        // unchanged.
        phase("scripts done; DOMContentLoaded");
        dump_vm_profile("scripts");
        run_script(
            &mut ctx,
            "DOMContentLoaded",
            b"__trust.readyState = \"interactive\"; __trust.hydrateFrames(); __trust.fire(document, \"DOMContentLoaded\", true);",
            &budget,
            &mut outcome,
        );
    }

    drain_js_side(&mut ctx, &mut outcome);
    drain_rejections(&hooks, &mut outcome);
    dump_vm_profile("DOMContentLoaded");
    Ok(LoadedPage {
        ctx,
        dom,
        budget,
        outcome,
        started,
        page_url: parsed_url,
        hooks,
        last_render: None,
        live_regions: std::collections::HashSet::new(),
        live_boundaries: std::collections::HashSet::new(),
        boundary_render: std::collections::HashMap::new(),
    })
}

/// Drain the post-DOMContentLoaded lifecycle: settle (background network +
/// timers), the `load` event, then a final job drain. This is where a
/// page's in-flight fetches (and the DOM mutations they cause) complete —
/// split out of `load_page` so the actor can paint the interactive shell
/// FIRST and let this run after. Idempotent-ish: a page with no pending
/// network/timers settles instantly here (so the shell == the full
/// render), which keeps the one-shot path and non-network tests unchanged.
fn settle_page(page: &mut LoadedPage) {
    if !page.outcome.panicked {
        phase("settle start");
        settle(&mut page.ctx, &page.budget, MAX_TICKS, &mut page.outcome);
        phase("settle done");
        run_script(
            &mut page.ctx,
            "load",
            b"__trust.readyState = \"complete\"; __trust.fire(window, \"load\", false);",
            &page.budget,
            &mut page.outcome,
        );
        // The load handler can schedule post-load work as a timer — the very
        // common `setTimeout(finish, 0)` pattern (every WPT testharness page
        // completes this way; many SPAs defer init like this). Drain to
        // quiescence (DUE-NOW timers + microtasks), not just the microtask
        // queue, so that 0-delay work runs as part of the load settle. Still
        // budget/MAX_TICKS-bounded; any real-delay timers left pending fire at
        // their real time later, in the actor's at-rest wake loop.
        settle(&mut page.ctx, &page.budget, MAX_TICKS, &mut page.outcome);
        // Fire `load` on any image whose reveal a handler is waiting for, so a
        // fade-in-on-load image is shown rather than hidden at `opacity:0`.
        settle_image_loads(&mut page.ctx, &page.budget, MAX_TICKS, &mut page.outcome);
        phase("load done");
    }

    drain_js_side(&mut page.ctx, &mut page.outcome);
    drain_rejections(&page.hooks, &mut page.outcome);
    phase(&format!(
        "load finished; last DOM mutation was @{}ms",
        crate::dom::last_mutation_ms()
    ));
    if std::env::var_os("TRUST_NET_TRACE").is_some() {
        // Reading the live set after a forced collection tells us the page's
        // true GC footprint — used to size the GC policy (see GC_BIG_LIVE).
        let before = boa_engine::gc::gc_profile();
        boa_engine::gc::force_collect();
        let after = boa_engine::gc::gc_profile();
        phase(&format!(
            "GC: {} collections, {:?} total; live set ~{} MiB",
            before.0,
            before.1,
            after.2 / (1024 * 1024)
        ));
    }
    page.outcome.fetches = page
        .ctx
        .realm()
        .host_defined()
        .get::<PageNet>()
        .map_or(0, |n| n.fetched.get());
    // Which JS functions burned the settle phase (under TRUST_JS_PROFILE) — the
    // settle is where a data-driven SPA spends its seconds, and the load_page
    // dumps only cover up to DOMContentLoaded, so without this the dominant
    // phase is unsampled. Pairs with the phase split below.
    dump_vm_profile("settle");
    // Step 1 decision-gate output: the whole-load parse/compile/execute split
    // (under TRUST_JS_PHASE). `page.started` was stamped at load start, so this
    // is the full load+settle wall — including this page's settle execution,
    // which `engine_profile` (one bundle in isolation) can't see.
    report_phases(page.started.elapsed());
    // Lazy-parse sizing gate (under TRUST_FN_CENSUS): of this page's own
    // compiled functions, how many never ran this boot.
    report_fn_census();
}

/// Evaluate a `__trust.*` entry point that RUNS PAGE CALLBACKS (timer ticks,
/// IntersectionObserver delivery, image-load scans) with the same panic
/// containment as `run_script`/`run_jobs_into`. These used to be bare
/// `ctx.eval`s — the one remaining place a Boa VM panic inside page code could
/// unwind the resident actor thread, silently killing the live page (and
/// skipping the thread's allocator purge on the way out) instead of degrading
/// to the `· JS:n!` badge. `None` = the eval failed or panicked; on panic
/// `outcome.panicked` is set so the caller's normal Trouble path runs.
fn guarded_eval(
    ctx: &mut Context,
    src: &[u8],
    what: &str,
    outcome: &mut Outcome,
) -> Option<JsValue> {
    let result = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
        ctx.eval(Source::from_bytes(src))
    }));
    match result {
        Ok(Ok(v)) => Some(v),
        Ok(Err(err)) => {
            outcome.errors.push(format!("{what}: {err}"));
            None
        }
        Err(_) => {
            outcome
                .errors
                .push(format!("{what}: engine panic (Boa bug) — page JS halted"));
            outcome.panicked = true;
            None
        }
    }
}

/// Drain microtasks + DUE-NOW (0-delay) timers to quiescence at the CURRENT
/// instant — it does NOT advance virtual time. Real-delay timers (rAF,
/// intervals, `setTimeout(_, N>0)`) are left pending for the at-rest wake loop
/// (`settle_to`), so load/dispatch paint the page's real initial state and
/// time-driven work runs as real time elapses (the browser model). Budget-
/// bounded. Job errors (exceptions escaping microtasks) are REAL page errors:
/// collect, don't discard.
fn settle(ctx: &mut Context, budget: &Budget, max_ticks: usize, outcome: &mut Outcome) {
    let mut ticks = 0;
    loop {
        run_jobs_into(ctx, budget, outcome);
        if budget.exhausted() || ticks >= max_ticks || outcome.panicked {
            phase(&format!(
                "settle: {ticks} ticks, exhausted={}",
                budget.exhausted()
            ));
            break;
        }
        // `__trust.tick` fires due-now timer callbacks (page JS) synchronously,
        // so its execution is real engine work — time it into the execute
        // bucket. It runs via `guarded_eval` (not `run_script`/a job): a VM
        // panic inside a timer callback must cost the page, not the actor
        // thread. Timed so the profiler doesn't mis-attribute it to Rust-side.
        let t = phase_begin();
        let ticked = guarded_eval(ctx, b"__trust.tick()", "timer tick", outcome);
        phase_end(Phase::Execute, t);
        match ticked {
            Some(v) if v.to_boolean() => ticks += 1,
            _ => {
                phase(&format!("settle: {ticks} ticks, quiescent"));
                break;
            }
        }
    }
}

/// Fire every timer due by `abs_ms` (a REAL wall-clock deadline, in `timers.now`
/// units) and drain the microtasks/fetches their callbacks schedule, to
/// quiescence. The at-rest analog of `settle`: where `settle` FAST-FORWARDS
/// virtual time (load/dispatch — drain due work ASAP), this advances to a real
/// deadline so a 1s interval fires once per real second. Bounded by the per-
/// wake budget + `max_ticks`; a 0-delay timer a callback schedules (now due by
/// `abs_ms`) is caught on the next pass.
fn settle_to(
    ctx: &mut Context,
    budget: &Budget,
    max_ticks: usize,
    outcome: &mut Outcome,
    abs_ms: f64,
) {
    let mut ticks = 0;
    loop {
        // `tickTo` fires due timer callbacks synchronously (page JS), so time it
        // into the execute bucket like the `tick` call in `settle` does — and
        // guard it identically (a VM panic in an at-rest timer callback must
        // degrade the page, not unwind the actor).
        let t = phase_begin();
        let fired = guarded_eval(
            ctx,
            format!("__trust.tickTo({abs_ms})").as_bytes(),
            "timer tick",
            outcome,
        )
        .and_then(|v| v.as_number())
        .unwrap_or(0.0);
        phase_end(Phase::Execute, t);
        run_jobs_into(ctx, budget, outcome);
        ticks += 1;
        if fired < 1.0 || budget.exhausted() || ticks >= max_ticks || outcome.panicked {
            break;
        }
    }
}

/// How many scan→settle passes the synthetic-image-load driver makes. One
/// reveals the current content; a couple more catch images a `load` handler
/// inserts in turn (lightGallery loads the slide, then preloads its
/// neighbours). Bounded so a pathological load handler can't loop forever.
const IMG_LOAD_PASSES: usize = 3;

/// Schedule synthetic `<img>` `load` events for anything waiting on one, then
/// settle so the handlers run, repeating a few passes to catch images those
/// handlers insert (see `trust.scanImageLoads`). The reveal-on-load idiom would
/// otherwise leave such images at `opacity:0` forever (a headless DOM never
/// fires `load`), and the layout drops an invisible image. A no-op on a page
/// where nothing listens for `load`.
fn settle_image_loads(ctx: &mut Context, budget: &Budget, max_ticks: usize, outcome: &mut Outcome) {
    for _ in 0..IMG_LOAD_PASSES {
        let t = phase_begin();
        let scheduled = guarded_eval(ctx, b"__trust.scanImageLoads()", "image load scan", outcome)
            .and_then(|v| v.as_number())
            .unwrap_or(0.0);
        phase_end(Phase::Execute, t);
        if scheduled < 1.0 || outcome.panicked {
            break;
        }
        settle(ctx, budget, max_ticks, outcome);
    }
}

/// Drive the job queue to quiescence. When the page has a net grant its
/// async fetch jobs must be polled under the tokio runtime (so their
/// socket I/O is reactored) and they run CONCURRENTLY — this is where
/// `Promise.all([fetch, fetch])` actually overlaps. Bounded by the wall
/// deadline: on expiry the future is dropped at an await boundary and we
/// keep whatever the DOM already holds. No-net pages take the plain
/// synchronous path (no runtime needed).
fn run_jobs_into(ctx: &mut Context, budget: &Budget, outcome: &mut Outcome) {
    let handle = ctx
        .realm()
        .host_defined()
        .get::<PageNet>()
        .map(|n| n.handle.clone());
    let exec = ctx.downcast_job_executor::<PageJobExecutor>();
    // catch_unwind the drain, like `run_script`/`run_module` already do: a
    // job's execution can panic on a Boa edge (e.g. a host uncatchable limit
    // reaching a reject path the fork doesn't yet propagate cleanly), and that
    // panic must cost the page, NOT unwind and kill the resident actor thread
    // — which would leave the page a dead engine ("scripts no longer running"
    // on every click). The asymmetry of leaving THIS drain unprotected while
    // `eval`/module-eval were wrapped is exactly what made archive.org's
    // promise-reaction limit kill the engine. The DOM mutations so far stay
    // serializable (RefCell guards release during unwind).
    let drained = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
        match (handle, exec) {
            (Some(handle), Some(exec)) => {
                let cell = RefCell::new(ctx);
                handle.block_on(async {
                    let fut = exec.run_jobs_async(&cell);
                    tokio::pin!(fut);
                    // Drive the job loop until it finishes (all promises + fetches
                    // settled) or the budget deadline passes. The deadline is
                    // RE-READ each slice because a dispatch-time fetch pushes it
                    // out (wire time): a stale one-shot timeout would cancel an
                    // in-flight LLM completion at the 1s compute cap. A slice
                    // timing out doesn't drop `fut`, so the in-flight request
                    // survives to the next slice; only the final deadline drops it.
                    loop {
                        let remaining = budget.remaining();
                        if remaining.is_zero() {
                            break Ok(()); // deadline reached: render what we have
                        }
                        let slice = remaining.min(Duration::from_millis(200));
                        match tokio::time::timeout(slice, &mut fut).await {
                            Ok(r) => break r,   // job loop finished
                            Err(_) => continue, // re-read the (maybe extended) deadline
                        }
                    }
                })
            }
            _ => ctx.run_jobs(),
        }
    }));
    match drained {
        Ok(Ok(())) => {}
        Ok(Err(err)) => outcome.errors.push(format!("async job: {err}")),
        Err(_) => {
            outcome.errors.push(String::from(
                "async job: engine panic (Boa bug) — page JS halted",
            ));
            outcome.panicked = true;
        }
    }
}

/// Report rejections that never found a handler. They land in the
/// console diagnostics channel, not errors: Boa never retracts
/// already-handled rejections (no Handle op observed), so pre-rejected
/// promises a page catches later would otherwise false-positive the
/// JS:n! badge. Diagnostics tools (js_diag/net_diag/canaries) print
/// console, which is where these earn their keep.
fn drain_rejections(hooks: &PageHooks, outcome: &mut Outcome) {
    for (_, reason) in hooks.rejections.borrow_mut().drain(..) {
        let line = format!("unhandled rejection: {reason}");
        if !outcome.console.contains(&line) {
            outcome.console.push(line);
        }
    }
}

/// Pull handler errors and console output collected on the JS side.
fn drain_js_side(ctx: &mut Context, outcome: &mut Outcome) {
    if let Ok(v) = ctx.eval(Source::from_bytes(
        b"__trust.errors.splice(0).join(\"\\u0000\")",
    )) && let Ok(s) = v.to_string(ctx)
    {
        let joined = s.to_std_string_lossy();
        outcome.errors.extend(
            joined
                .split('\0')
                .filter(|e| !e.is_empty())
                .map(String::from),
        );
    }
    if let Ok(v) = ctx.eval(Source::from_bytes(
        b"__trust.logs.splice(0).join(\"\\u0000\")",
    )) && let Ok(s) = v.to_string(ctx)
    {
        let joined = s.to_std_string_lossy();
        outcome.console.extend(
            joined
                .split('\0')
                .filter(|e| !e.is_empty())
                .map(String::from),
        );
    }
}

/// Run a page's scripts against a real DOM and return the post-JS HTML
/// (one-shot: the engine is dropped). Never fails: any error lands in
/// the Outcome and the best available document is returned.
/// Apply ONLY the CSS cascade to a page — no JS. Parses the HTML, attaches
/// the (already-fetched) external stylesheets, and serializes; the serializer
/// bakes every cascaded property onto each element, exactly as the full JS
/// pipeline does. Used whenever JS won't run — a page with no `<script>`,
/// `set js off`, or the JS-load-timeout fallback — so the page still lays out
/// per its OWN stylesheets (flex, grid, visibility:hidden, …) instead of bare
/// UA defaults. Without this, e.g. GitHub's code view (when its heavy JS times
/// out) renders line numbers stacked above the code and nav menus expanded,
/// because `display:flex`/`visibility:hidden` from its sheets never apply.
#[cfg_attr(not(test), allow(dead_code))] // one-call form; production uses css_prepare + css_finish
pub fn css_bake(
    html: &str,
    sheets: &[(String, String)],
    viewport: (u16, u16),
    cell_px: (u16, u16),
) -> String {
    let dom = css_prepare(html, viewport, cell_px);
    css_finish(dom, sheets)
}

/// Parse a page into an arena with its viewport set — the front half of the
/// no-JS `css_bake`, split out so `http::css_only` can load the page's frames
/// (an async fetch + `Dom::install_frame_document`) between parse and
/// serialize, the script-less mirror of the JS pipeline's frame loading.
pub fn css_prepare(html: &str, viewport: (u16, u16), cell_px: (u16, u16)) -> Dom {
    let mut dom = Dom::parse_document(html);
    dom.set_viewport_px(
        u32::from(viewport.0) * u32::from(cell_px.0.max(1)),
        u32::from(viewport.1) * u32::from(cell_px.1.max(1)),
    );
    dom.set_cell_px(cell_px.0, cell_px.1);
    dom
}

/// Attach the page's external sheets and serialize the cascade-baked DOM —
/// the back half of `css_bake`.
pub fn css_finish(mut dom: Dom, sheets: &[(String, String)]) -> String {
    if !sheets.is_empty() {
        dom.attach_external_sheets(sheets);
    }
    dom.serialize(DOCUMENT)
}

pub fn transform(html: &str, env: &PageEnv) -> (String, Outcome) {
    match load_page(html, env, None, None, None) {
        Err(outcome) => (html.to_string(), outcome),
        Ok(mut page) => {
            // One-shot snapshot: no resident actor will run deferred timers
            // later, so the settle FAST-FORWARDS virtual time to the page's
            // eventual rendered state (rAF-deferred content, delayed timeouts).
            // The live actor leaves this off and runs that work at real time.
            let _ = page.ctx.eval(Source::from_bytes(b"__trust.oneShot = true"));
            settle_page(&mut page); // `load_page(.., None)` ⇒ fetches await in-line
            page.outcome.elapsed = page.started.elapsed();
            // Inner-scroll GATE diagnostic: report definite_height for every
            // vertical scroll container on the live (full-cascade) arena before it
            // is serialized (which drops overflow-y/min-height). See
            // `layout::scroll_box_report`.
            if std::env::var("TRUST_DIAG_SCROLL_BOXES").is_ok()
                && let Ok(base) = url::Url::parse(&env.url)
            {
                let d = page.dom.borrow();
                eprintln!(
                    "{}",
                    crate::layout::scroll_box_report(
                        &d,
                        &base,
                        (env.viewport.0 as usize, env.viewport.1 as usize),
                    )
                );
            }
            let out = page.dom.borrow().serialize(DOCUMENT);
            (out, std::mem::take(&mut page.outcome))
        }
    }
}

// ---- The living page actor --------------------------------------------
//
// A displayed page keeps its engine + arena on a resident thread; the
// app talks to it over channels exactly like a telnet connection task.
// One live engine ever (the foreground page); navigation away drops the
// handle and the actor exits.

/// App → page.
#[derive(Debug)]
pub enum PageCmd {
    /// Dispatch a click on this arena node.
    Click(usize),
    /// Set a form control's value in the live DOM, then fire input/change.
    SetValue {
        node: usize,
        value: String,
        checked: Option<bool>,
    },
    /// Dispatch a submit event on a live form. If page JS does not
    /// prevent it, the app proceeds with its existing HTTP submit path.
    Submit {
        form: usize,
        submitter: Option<usize>,
    },
    /// A WebSocket event from a page-opened socket (the WS task forwards inbound
    /// frames + open/close here). Dispatched like a click: fire the JS event,
    /// settle, re-render. This is how a socket.io stream (chat tokens) drives
    /// the page with no busy-poll — a frame is just another event.
    Ws { id: usize, event: crate::ws::WsIn },
    /// A Web Worker posted a message back (or errored). The worker thread
    /// forwards `(id, WorkerOut)`; dispatched like a click — fire the JS event,
    /// settle, re-render. This is how a worker's result drives the page.
    Worker { id: usize, event: WorkerOut },
    /// The user scrolled the laid-out document; `x`/`y` are the viewport's
    /// top-left in CSS px (document origin). Updates `window.scrollY`, fires the
    /// viewport `scroll` event, and re-runs IntersectionObserver — so a site's
    /// own infinite-scroll logic (a window scroll handler, or an IO sentinel)
    /// fires its load-more request and the appended content re-renders.
    Scroll { x: f64, y: f64 },
    /// The terminal's pointer (mouse cursor OR the gopherus selection — her
    /// call: the selection IS the pointer) came to rest on a new element, or on
    /// none (`node: None` — chrome rows / selection cleared). Dispatches the
    /// Pointer Events transition sequence (pointer/mouse out→leave→over→enter→
    /// move with relatedTarget) from the old target to this one, and moves the
    /// cascade's `:hover` chain. `x`/`y` are viewport-relative CSS px of the
    /// hovered cell's center. The app sends only COMMITTED targets (diff +
    /// dwell-at-rest), so this is target-change-rate bounded, not motion-rate.
    Hover { node: Option<usize>, x: f64, y: f64 },
    /// Per-region CLIP box the app measured (CSSOM View, Phase 3): `(node,
    /// clientHeight, clientWidth)` px. Stored on the live DOM so `clientHeight`/
    /// `clientWidth` read TRUE values (the conditional pin reads them). Only the
    /// clip box round-trips — `scrollHeight` reads the actor's own fresh
    /// `__dom_rect` (current content, no render lag). No event/re-render — pure
    /// measurement backing, like the geometry box map behind `__dom_rect`.
    RegionGeom { items: Vec<(usize, f64, f64)> },
    /// The user wheeled/paged an inner-scroll region: write its new `scrollTop`
    /// (px) back into the live element and fire its `scroll` event, so a page
    /// that conditionally pins to the bottom learns the user scrolled up and
    /// stops following (CSSOM View — the region→page write-back).
    SetScroll { node: usize, top: f64, left: f64 },
    /// The app couldn't apply an incremental `Patched` (the boundary wasn't a
    /// live region, or a verify failed) — re-emit the WHOLE document as a full
    /// `Updated` so the app resyncs. The downgrade path
    /// (INCREMENTAL_LAYOUT_PLAN.md §7); unreachable when the boundary predicate
    /// is correct.
    Resync,
    /// The current set of CLIPPED scroll-region nodes (by `data-trust-node`) the
    /// app has laid out. The actor patches a mutation ONLY when it's confined to
    /// one of these (INCREMENTAL_LAYOUT_PLAN.md §4b) — a non-region scroll box
    /// (content fits / height-elastic) takes the full path instead of a failed
    /// patch. The app sends the full set whenever it changes (deduped).
    LiveRegions(Vec<usize>),
    /// The current set of cached INLINE IFC-boundary nodes (the `Doc.boundaries`
    /// node set) the app can splice into `Doc.rows` (INCREMENTAL_LAYOUT_PLAN.md
    /// §14). The actor proposes a general inline `Patched` ONLY for a boundary in
    /// this set; one the app hasn't cached takes the full path (no failed-patch
    /// resync). Sent whenever it changes (deduped).
    LiveBoundaries(Vec<usize>),
}

/// Which kind of relayout boundary a patch targets (INCREMENTAL_LAYOUT_PLAN.md
/// §2). v1 emits only `Size` (scroll regions — content-independent outer box,
/// in-place swap); `WidthStable` (Tier 2: relayout + shift) is reserved.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum BoundaryTier {
    /// Size-contained: the boundary's outer box (incl. height) is unchanged, so
    /// the splice touches only its buffer/range — nothing outside moves.
    Size,
    /// Width-stable, height-elastic (Tier 2): relayout the subtree, then shift
    /// the following content. Reserved; not emitted in v1.
    WidthStable,
}

/// One targeted incremental-layout patch: a relayout boundary's freshly
/// serialized subtree (with its inherited context materialized,
/// INCREMENTAL_LAYOUT_PLAN.md §4a). The app re-lays ONLY this subtree.
#[derive(Debug)]
pub struct SubtreePatch {
    /// The boundary's arena node id (baked as `data-trust-node`) — the app maps
    /// it to the live `Region` to swap.
    pub node: usize,
    /// `Dom::serialize_patch` output: the boundary inside a context wrapper.
    pub html: String,
    pub tier: BoundaryTier,
}

/// Page → app.
#[derive(Debug)]
pub enum PageEvt {
    /// A render of a page that stays alive for interaction.
    Updated { html: String, outcome: Outcome },
    /// Targeted incremental re-render: re-lay ONLY these relayout boundaries,
    /// leaving the rest of the document untouched (INCREMENTAL_LAYOUT_PLAN.md).
    /// The app applies each via `patch_live_doc`, falling back to a `Resync`
    /// request if any can't be applied.
    Patched {
        patches: Vec<SubtreePatch>,
        outcome: Outcome,
    },
    /// Final render: nothing to interact with, the actor has exited.
    /// (Free efficiency: text articles never hold an engine.)
    Static { html: String, outcome: Outcome },
    /// An un-prevented click on a live anchor: the app navigates
    /// (absolute URL, already resolved against the page).
    Navigate(String),
    /// A same-document fragment scroll the page requested (`location.href = "#x"`
    /// / `location.hash = …`): the app scrolls the view to the element with this
    /// `id`/`<a name>` (empty = the top). The live engine has no scroll model, so
    /// the app resolves it against `Doc.anchor_rows`. Emitted AFTER the dispatch's
    /// render, so the app scrolls in the freshly-rendered doc.
    ScrollToFragment(String),
    /// A dispatch produced errors but no content change.
    Trouble(Vec<String>),
    /// A dispatch settled without a renderable mutation.
    Settled,
    /// A page-initiated inner-scroll write (CSSOM View, Phase 3): the page set
    /// `element.scrollTop` (a chat pinning to bottom) on a scroll-region element
    /// without otherwise mutating the DOM. The app re-windows that region (by
    /// `node`, the actor node id baked as `data-trust-node`) — a cheap re-blit,
    /// no re-parse. `top`/`left` are px. When the same dispatch ALSO mutated the
    /// DOM, the `Updated`'s baked `data-trust-scroll-top` carries it instead.
    Scrolled {
        node: usize,
        top: f64,
        /// Horizontal position — carried for protocol symmetry with
        /// `scrollLeft` writes; the app re-windows vertically only (terminal
        /// regions have no h-scroll), so nothing reads it yet.
        #[allow(dead_code)]
        left: f64,
    },
    /// The page did not prevent a form submit; the app should perform
    /// the normal HTTP form submission it already prepared.
    SubmitDefault,
    /// A CLICK on a submit control fired the form's `submit` event and the
    /// page did not prevent it — the app should run the native GET/POST for
    /// this form. Carries the form + submitter arena nodes (the app maps them
    /// to its doc-model indices); unlike `SubmitDefault` the app hasn't
    /// pre-recorded which form, because the click path didn't know.
    SubmitForm { form: usize, submitter: usize },
}

#[derive(Debug)]
pub struct PageHandle {
    pub cmds: tokio::sync::mpsc::Sender<PageCmd>,
}

/// Wall budget for a single user-event dispatch's COMPUTE (a fetch fired
/// during it extends the deadline — see `DISPATCH_NET_GRACE`).
const DISPATCH_BUDGET: Duration = Duration::from_secs(1);

/// How long a dispatch may wait on in-flight network before giving up. A
/// page-initiated fetch during a dispatch pushes the deadline out to this, so a
/// click that asks an LLM for a reply waits for the (possibly slow, reasoning)
/// reply instead of being cancelled at the 1s compute cap. Generous so it works
/// with EVERY model; still bounded so a hung server can't hold the page forever
/// (the user can also Esc). The wait parks on the reactor — no idle CPU.
const DISPATCH_NET_GRACE: Duration = Duration::from_secs(300);
/// Settle ticks allowed after a dispatch (load-time settle uses MAX_TICKS).
const DISPATCH_TICKS: usize = 50;
/// Settle ticks per AT-REST wake (the idle `timer_wake` loop). Unlike a dispatch
/// — which settles a click's whole cascade to completion (`DISPATCH_TICKS`) — an
/// at-rest wake fires ONE generation of due timers (one event-loop "task"), drains
/// the microtask checkpoint, and returns to the sleep. A callback that re-arms a
/// 0-delay timer (React's scheduler MessageChannel loop; an Apollo poll that never
/// settles because its data is gated behind a bot wall) therefore advances at the
/// `WAKE_FLOOR` cadence (~15fps) instead of running 50 generations crammed into a
/// single virtual instant per wake — which pegged a CPU core on any page that
/// never reaches a stable state. `setInterval`/`requestAnimationFrame` are
/// future-dated, so they already fire one generation per wake and are unaffected;
/// only a due-NOW re-arming chain is rate-limited, and one task per turn is the
/// faithful event-loop model regardless. A finite deferred chain still completes,
/// just one step per frame.
const REST_TICKS: usize = 1;
/// The page thread owns all parsing/execution: same wide stack as the
/// one-shot path (Boa's parser recursion, see CLAUDE.md).
const PAGE_STACK: usize = 64 * 1024 * 1024;

/// At rest the actor never wakes more often than this, even if a page arms a
/// 0/16ms timer (a `requestAnimationFrame` chain) — so an animation settles to
/// ~15fps instead of pegging a core. Sub-floor delays are coalesced to the
/// frame; a one-shot `setTimeout` with a longer delay still fires near its real
/// time (the floor only raises sub-frame waits). Her call: 15fps render cadence
/// (see CLAUDE.md). A page with no pending timers arms NO sleep and parks on
/// the command channel — zero idle CPU, exactly like the old blocking park.
const WAKE_FLOOR: Duration = Duration::from_millis(66);

/// What unblocked the at-rest event loop: an app command (`None` = the app
/// dropped the page handle), a background fetch completing (`None` = the
/// channel closed, i.e. the page is going away), or the next-timer-deadline
/// sleep elapsing.
enum Wake {
    Cmd(Option<PageCmd>),
    Fetch(Option<(usize, FetchResult)>),
    Timer,
}

/// Sleep `d`, or never resolve when there's no pending timer — the loop then
/// parks purely on the command channel (zero idle CPU).
async fn sleep_or_pending(d: Option<Duration>) {
    match d {
        Some(d) => tokio::time::sleep(d).await,
        None => std::future::pending::<()>().await,
    }
}

/// Spawn a living page. The first event is either `Static` (actor
/// already gone) or `Updated` (alive, send it `PageCmd`s). Dropping the
/// handle shuts the actor down.
pub fn spawn_page(
    html: String,
    env: PageEnv,
) -> (PageHandle, tokio::sync::mpsc::Receiver<PageEvt>) {
    let (cmd_tx, cmd_rx) = tokio::sync::mpsc::channel(16);
    let (evt_tx, evt_rx) = tokio::sync::mpsc::channel(16);
    // The actor keeps a clone of its own command sender so a WebSocket task can
    // post inbound frames back as `PageCmd::Ws` (see `setup_page_ws`).
    let cmd_self = cmd_tx.clone();
    let spawned = std::thread::Builder::new()
        .name(String::from("trust-page"))
        .stack_size(PAGE_STACK)
        .spawn(move || {
            page_actor(html, env, cmd_rx, evt_tx, cmd_self);
            // `page_actor` has returned, so the Context + DOM arena have dropped
            // and this thread's whole JS heap is freed back to its (about-to-be-
            // abandoned) mimalloc heap. Purge it to the OS NOW — on the owning
            // thread, the instant it's free. This is the V8 "idle GC on
            // navigation" analogue, and it fires at exactly the right moment:
            // navigating away drops the `PageHandle`, this actor exits, the heap
            // frees, and we return it. Doing it from the app's run loop instead
            // raced — tearing down a multi-GB heap outlasts a light next page's
            // load, so the app went idle and purged before the heap was freed.
            // `mi_collect` is a global purge, so this also reclaims any other
            // freed high-water. This is what makes RSS fall after a heavy page.
            crate::release_allocator_memory();
        });
    if spawned.is_err() {
        // The dropped evt sender tells the caller the page is gone.
    }
    (PageHandle { cmds: cmd_tx }, evt_rx)
}

/// The full worker-scope JS: the shared structured-clone codec (extracted from
/// PRELUDE so it's a single source of truth) followed by the DOM-less worker
/// global scope. Built once per process.
fn worker_prelude() -> &'static str {
    static WP: std::sync::OnceLock<String> = std::sync::OnceLock::new();
    WP.get_or_init(|| {
        let codec = PRELUDE
            .split_once("/*__SC_CODEC_BEGIN__*/")
            .and_then(|(_, rest)| rest.split_once("/*__SC_CODEC_END__*/"))
            .map(|(c, _)| c)
            .unwrap_or("");
        // The WebAssembly block is self-contained (takes its own `g`), so the
        // worker reuses it verbatim — wasm runs inside a Worker too.
        let wasm = PRELUDE
            .split_once("/*__WASM_BEGIN__*/")
            .and_then(|(_, rest)| rest.split_once("/*__WASM_END__*/"))
            .map(|(c, _)| c)
            .unwrap_or("");
        format!("{codec}\n{WORKER_SCOPE}\n{wasm}")
    })
    .as_str()
}

