    // ---- Phase 2b: the living page actor ----

    /// Spawn an actor with no net/storage and hand back the channels.
    fn live(html: &str) -> (PageHandle, tokio::sync::mpsc::Receiver<PageEvt>) {
        spawn_page(
            html.to_string(),
            PageEnv::bare("https://example.com/dir/page"),
        )
    }

    #[test]
    fn a_click_driven_animation_completes_at_rest() {
        // Humble's "Dismiss banner" steps a `Date.now()`/`requestAnimationFrame`
        // animation and removes the element after 500ms. Under the real-time
        // model the dispatch does NOT fast-forward: clicking starts the
        // animation (the first `step()` runs synchronously and just schedules a
        // rAF — no mutation, so the dispatch emits `Settled`), then the rAF
        // chain fires AT REST over ~500ms of real wall time and removes the
        // banner — a real animation, like a browser. The handler is DELEGATED on
        // an ancestor and matched by selector (Backbone's `click .js-dismiss-
        // button`), so this also exercises that the synthetic click BUBBLES.
        let (handle, mut events) = live(
            r##"<body><div id="banner">BANNER</div><button class="js-dismiss-button">close</button><script>
            document.addEventListener('click', function (e) {
                if (!(e.target.closest && e.target.closest('.js-dismiss-button'))) return;
                var el = document.getElementById('banner');
                var start = Date.now(), dur = 500;
                (function step() {
                    if (Date.now() - start >= dur) { el.parentNode.removeChild(el); return; }
                    requestAnimationFrame(step);
                })();
            });
            </script></body>"##,
        );
        let mut rendered = String::new();
        for _ in 0..4 {
            match events.blocking_recv() {
                Some(PageEvt::Updated { html, .. }) | Some(PageEvt::Static { html, .. }) => {
                    rendered = html;
                    if rendered.contains("BANNER") {
                        break;
                    }
                }
                other => panic!("expected a render, got {other:?}"),
            }
        }
        assert!(rendered.contains("BANNER"), "initial render: {rendered}");
        let button = rendered
            .split("x-trust-js:")
            .nth(1)
            .and_then(|r| r.split(':').next())
            .expect("a clickable marker for the button")
            .parse::<usize>()
            .unwrap();
        handle.cmds.blocking_send(PageCmd::Click(button)).unwrap();
        // The animation runs at rest: a Settled (mutation-less dispatch) and a
        // silent ~500ms of rAF frames, then one Updated when the banner is
        // removed. Loop until it's gone (each blocking_recv parks on the wake).
        let mut removed = false;
        for _ in 0..20 {
            match events.blocking_recv() {
                Some(PageEvt::Updated { html, outcome }) => {
                    assert!(outcome.errors.is_empty(), "{:?}", outcome.errors);
                    if !html.contains("BANNER") {
                        removed = true;
                        break;
                    }
                }
                Some(PageEvt::Settled) => continue,
                other => panic!("unexpected event: {other:?}"),
            }
        }
        assert!(
            removed,
            "the 500ms click-driven animation must remove the banner at rest"
        );
    }

    #[test]
    fn confined_boundaries_walks_up_to_the_nearest_cached_boundary() {
        // INCREMENTAL_LAYOUT_PLAN.md §14 (the walk-up): a deep mutation whose
        // NEAREST IFC boundary (a row-sharing flex item — the viewer counter
        // pattern) the app couldn't cache routes to its enclosing CACHED section
        // and patches it, instead of forcing a whole-document render.
        use crate::dom::DirtyKind;
        use std::collections::HashSet;
        let dom = Dom::parse_document(
            r#"<html><body><div data-trust-node="9" style="display:flow-root"><div style="display:flex"><div data-trust-node="5">x<span id="t">N</span></div></div></div></body></html>"#,
        );
        let find = |n: &str| {
            dom.descendants(DOCUMENT)
                .into_iter()
                .find(|&id| dom.attr(id, "data-trust-node") == Some(n))
                .unwrap()
        };
        let section = find("9");
        let target = dom.get_by_id("t").unwrap();
        let regions: HashSet<usize> = HashSet::new();
        // Only the OUTER section (9) is cached — the inner flex item (5) is not.
        let cached: HashSet<usize> = [section].into_iter().collect();
        assert_eq!(
            confined_boundaries(
                &dom,
                &regions,
                &cached,
                Some(&[(target, DirtyKind::Content)])
            ),
            Some(vec![(section, BoundaryTier::WidthStable)]),
            "the mutation walks up past the uncached flex item to the cached section"
        );
    }

    #[test]
    fn confined_boundaries_routes_a_cached_inline_boundary_to_a_width_stable_patch() {
        // INCREMENTAL_LAYOUT_PLAN.md §14: a content mutation inside a block-filling
        // IFC boundary the app has CACHED is proposed as a `WidthStable` patch (the
        // Doc.rows splice); the SAME boundary uncached takes the full path.
        use crate::dom::DirtyKind;
        use std::collections::HashSet;
        let dom = Dom::parse_document(
            r#"<html><body><div data-trust-node="5" style="display:flow-root"><span id="t">x</span></div></body></html>"#,
        );
        let boundary = dom
            .descendants(DOCUMENT)
            .into_iter()
            .find(|&id| dom.attr(id, "data-trust-node") == Some("5"))
            .unwrap();
        let child = dom.get_by_id("t").unwrap();
        let regions: HashSet<usize> = HashSet::new();
        let targets = [(child, DirtyKind::Content)];
        // Cached → a targeted WidthStable patch on the boundary.
        let cached: HashSet<usize> = [boundary].into_iter().collect();
        assert_eq!(
            confined_boundaries(&dom, &regions, &cached, Some(&targets)),
            Some(vec![(boundary, BoundaryTier::WidthStable)]),
        );
        // Uncached → no inline patch proposed (the full path is always correct).
        let empty: HashSet<usize> = HashSet::new();
        assert_eq!(
            confined_boundaries(&dom, &regions, &empty, Some(&targets)),
            None,
        );
    }

    #[test]
    fn a_chat_append_emits_a_targeted_patch_not_a_full_render() {
        // INCREMENTAL_LAYOUT_PLAN.md Tier 1 — the headline behaviour: a click that
        // appends a message INTO a scroll region emits a TARGETED `Patched` for
        // that region (so the app re-lays only it), NOT a whole-document
        // `Updated`. The build-then-append (`createElement`+`textContent`+
        // `appendChild`) is exactly the common pattern the `is_connected` skip
        // keeps on the patch path.
        let mut seed = String::new();
        for i in 0..30 {
            seed.push_str(&format!("<div>seed{i:02}</div>"));
        }
        // The clickable is a plain <div> (not a <button>) so the ONLY baked
        // `data-trust-node` is the scroll region's — the test reads it to send
        // `LiveRegions` (the app's job: it confirms which boxes are live regions).
        let (handle, mut events) = live(&format!(
            r##"<body><div id="add">add</div>
            <div id="chat" style="height:96px;overflow-y:scroll">{seed}</div>
            <script>
            document.getElementById('add').addEventListener('click', function () {{
                var d = document.createElement('div');
                d.textContent = 'NEWMSG';
                document.getElementById('chat').appendChild(d);
            }});
            </script></body>"##
        ));
        let mut rendered = String::new();
        for _ in 0..4 {
            match events.blocking_recv() {
                Some(PageEvt::Updated { html, .. }) | Some(PageEvt::Static { html, .. }) => {
                    rendered = html;
                    if rendered.contains("seed00") {
                        break;
                    }
                }
                Some(PageEvt::Settled | PageEvt::Trouble(_)) => continue,
                other => panic!("expected a render, got {other:?}"),
            }
        }
        let button = rendered
            .split("x-trust-js:")
            .nth(1)
            .and_then(|r| r.split(':').next())
            .expect("a clickable marker for the button")
            .parse::<usize>()
            .unwrap();
        // The app confirms #chat is a live clipped region (the layout decides
        // this; the actor only patches confirmed regions).
        let chat_node = rendered
            .split("data-trust-node=\"")
            .nth(1)
            .and_then(|r| r.split('"').next())
            .expect("the region's baked node id")
            .parse::<usize>()
            .unwrap();
        handle
            .cmds
            .blocking_send(PageCmd::LiveRegions(vec![chat_node]))
            .unwrap();
        handle.cmds.blocking_send(PageCmd::Click(button)).unwrap();
        let mut saw_patch = false;
        for _ in 0..6 {
            match events.blocking_recv() {
                Some(PageEvt::Patched { patches, .. }) => {
                    assert_eq!(patches.len(), 1, "exactly one region patched");
                    assert!(
                        patches[0].html.contains("NEWMSG"),
                        "patch carries the new message"
                    );
                    assert!(
                        patches[0].html.contains("seed00"),
                        "patch is the WHOLE region subtree (so the app re-lays it)"
                    );
                    assert_eq!(patches[0].tier, BoundaryTier::Size);
                    saw_patch = true;
                    break;
                }
                Some(PageEvt::Updated { .. }) => {
                    panic!("a contained chat append must NOT trigger a full Updated")
                }
                Some(PageEvt::Settled | PageEvt::Trouble(_)) => continue,
                other => panic!("unexpected event: {other:?}"),
            }
        }
        assert!(
            saw_patch,
            "the chat append produced a targeted region patch"
        );
    }

    #[test]
    fn a_chat_append_with_a_reply_button_still_patches() {
        // The real-chat shape: every message holds a reply `<button>` (Twitch).
        // A `<button>` carries no editable state and activates by node id, so a
        // region full of them must STILL patch — not fall back to a full
        // ~1.4MB-document `Updated` per message (the old over-broad exclusion
        // lumped `button` with stateful `<input>`/`<select>`/`<textarea>`).
        let mut seed = String::new();
        for i in 0..30 {
            seed.push_str(&format!("<div>seed{i:02}</div>"));
        }
        let (handle, mut events) = live(&format!(
            r##"<body><div id="add">add</div>
            <div id="chat" style="height:96px;overflow-y:scroll">{seed}</div>
            <script>
            document.getElementById('add').addEventListener('click', function () {{
                var d = document.createElement('div');
                d.innerHTML = 'NEWMSG <button aria-label="Click to reply">reply</button>';
                document.getElementById('chat').appendChild(d);
            }});
            </script></body>"##
        ));
        let mut rendered = String::new();
        for _ in 0..4 {
            match events.blocking_recv() {
                Some(PageEvt::Updated { html, .. }) | Some(PageEvt::Static { html, .. }) => {
                    rendered = html;
                    if rendered.contains("seed00") {
                        break;
                    }
                }
                Some(PageEvt::Settled | PageEvt::Trouble(_)) => continue,
                other => panic!("expected a render, got {other:?}"),
            }
        }
        // The "add" trigger is the FIRST clickable (it precedes #chat in document
        // order; the seed divs are plain), so its marker parses cleanly.
        let button = rendered
            .split("x-trust-js:")
            .nth(1)
            .and_then(|r| r.split(':').next())
            .expect("a clickable marker for the add trigger")
            .parse::<usize>()
            .unwrap();
        let chat_node = rendered
            .split("data-trust-node=\"")
            .nth(1)
            .and_then(|r| r.split('"').next())
            .expect("the region's baked node id")
            .parse::<usize>()
            .unwrap();
        handle
            .cmds
            .blocking_send(PageCmd::LiveRegions(vec![chat_node]))
            .unwrap();
        handle.cmds.blocking_send(PageCmd::Click(button)).unwrap();
        let mut saw_patch = false;
        for _ in 0..6 {
            match events.blocking_recv() {
                Some(PageEvt::Patched { patches, .. }) => {
                    assert_eq!(patches.len(), 1, "exactly one region patched");
                    assert!(
                        patches[0].html.contains("NEWMSG"),
                        "patch carries the new message + its reply button"
                    );
                    saw_patch = true;
                    break;
                }
                Some(PageEvt::Updated { .. }) => {
                    panic!("a chat append whose message holds a <button> must STILL patch")
                }
                Some(PageEvt::Settled | PageEvt::Trouble(_)) => continue,
                other => panic!("unexpected event: {other:?}"),
            }
        }
        assert!(saw_patch, "a region containing a <button> still patches");
    }

    #[test]
    fn an_invisible_in_region_mutation_dedups_and_the_full_path_carries_prior_patches() {
        // INCREMENTAL_LAYOUT_PLAN.md §12c W1 (scoped change-detection). Three
        // properties in one flow:
        //  (a) a VISIBLE append inside a live region emits a targeted `Patched`
        //      (the patch path — no whole-document serialize);
        //  (b) an INVISIBLE mutation inside that SAME region (an `aria-label`
        //      rotation, which `render_canonical` drops) dedups per-boundary and
        //      emits NOTHING (a `Settled`, not a `Patched`/`Updated`);
        //  (c) a later NON-confined mutation (header text, outside any region)
        //      takes the FULL path and its `Updated` STILL carries the earlier
        //      region append — the actor DOM is the truth, so `last_render`
        //      staleness on the patch path costs only a redundant full render,
        //      never a wrong one (§12c step 5).
        let mut seed = String::new();
        for i in 0..30 {
            seed.push_str(&format!("<div>seed{i:02}</div>"));
        }
        let (handle, mut events) = live(&format!(
            r##"<body><div id="hdr">HDR0</div>
            <div id="add">add</div><div id="aria">aria</div><div id="hchg">hchg</div>
            <div id="chat" style="height:96px;overflow-y:scroll">{seed}</div>
            <script>
            document.getElementById('add').addEventListener('click', function () {{
                var d = document.createElement('div');
                d.textContent = 'NEWMSG';
                document.getElementById('chat').appendChild(d);
            }});
            document.getElementById('aria').addEventListener('click', function () {{
                // Invisible: an aria rotation on a child INSIDE the region.
                document.getElementById('chat').firstElementChild
                    .setAttribute('aria-label', 'tick');
            }});
            document.getElementById('hchg').addEventListener('click', function () {{
                document.getElementById('hdr').textContent = 'HDR1';
            }});
            </script></body>"##
        ));
        let mut rendered = String::new();
        for _ in 0..4 {
            match events.blocking_recv() {
                Some(PageEvt::Updated { html, .. }) | Some(PageEvt::Static { html, .. }) => {
                    rendered = html;
                    if rendered.contains("seed00") {
                        break;
                    }
                }
                Some(PageEvt::Settled | PageEvt::Trouble(_)) => continue,
                other => panic!("expected a render, got {other:?}"),
            }
        }
        // The clickables serialize in document order: add, aria, hchg (the seed
        // divs are plain). Collect their node ids in that order.
        let ids: Vec<usize> = rendered
            .split("x-trust-js:")
            .skip(1)
            .map(|r| r.split(':').next().unwrap().parse::<usize>().unwrap())
            .collect();
        assert!(ids.len() >= 3, "add/aria/hchg markers: {ids:?}");
        let (add, aria, hchg) = (ids[0], ids[1], ids[2]);
        let chat_node = rendered
            .split("data-trust-node=\"")
            .nth(1)
            .and_then(|r| r.split('"').next())
            .expect("the region's baked node id")
            .parse::<usize>()
            .unwrap();
        handle
            .cmds
            .blocking_send(PageCmd::LiveRegions(vec![chat_node]))
            .unwrap();

        // (a) Append → a targeted Patched carrying the new message.
        handle.cmds.blocking_send(PageCmd::Click(add)).unwrap();
        let mut saw_patch = false;
        for _ in 0..6 {
            match events.blocking_recv() {
                Some(PageEvt::Patched { patches, .. }) => {
                    assert!(patches[0].html.contains("NEWMSG"), "patch carries append");
                    saw_patch = true;
                    break;
                }
                Some(PageEvt::Updated { .. }) => panic!("append must patch, not full-render"),
                Some(PageEvt::Settled | PageEvt::Trouble(_)) => continue,
                other => panic!("unexpected event: {other:?}"),
            }
        }
        assert!(saw_patch, "the append patched the region");

        // (b) Invisible aria rotation inside the region → per-boundary dedup →
        // NOTHING painted (a Settled, never a Patched/Updated).
        handle.cmds.blocking_send(PageCmd::Click(aria)).unwrap();
        // The invisible mutation emits exactly one event (a silent Settled) —
        // anything else is a failure, so a single recv suffices.
        match events.blocking_recv() {
            Some(PageEvt::Settled) => {}
            Some(PageEvt::Patched { .. }) => {
                panic!("an invisible in-region mutation must NOT emit a patch")
            }
            Some(PageEvt::Updated { .. }) => {
                panic!("an invisible in-region mutation must NOT full-render")
            }
            Some(PageEvt::Trouble(e)) => panic!("unexpected trouble: {e:?}"),
            other => panic!("unexpected event: {other:?}"),
        }

        // (c) A non-confined mutation (header, outside any region) → FULL path,
        // whose Updated carries BOTH the header change AND the earlier append
        // (the patch path left `last_render` stale; the full serialize is truth).
        handle.cmds.blocking_send(PageCmd::Click(hchg)).unwrap();
        let mut saw_full = false;
        for _ in 0..6 {
            match events.blocking_recv() {
                Some(PageEvt::Updated { html, .. }) => {
                    assert!(html.contains("HDR1"), "full render shows the header change");
                    assert!(
                        html.contains("NEWMSG"),
                        "full render still carries the patched append (coherence)"
                    );
                    saw_full = true;
                    break;
                }
                Some(PageEvt::Patched { .. }) => {
                    panic!("an out-of-region change takes the full path")
                }
                Some(PageEvt::Settled | PageEvt::Trouble(_)) => continue,
                other => panic!("unexpected event: {other:?}"),
            }
        }
        assert!(
            saw_full,
            "the out-of-region mutation full-rendered coherently"
        );
    }

    #[test]
    fn a_raf_chain_runs_to_completion_at_rest() {
        // A rAF chain runs AT REST under the real-time model — one frame per
        // real wake, with NO virtual-time ceiling to freeze it (the old
        // `tick(1000)` window bug, now structurally gone: there is no
        // fast-forward window in the live path). A framework's rAF-deferred
        // render (Open WebUI's streamed token once rendered an empty body when
        // the window bug froze it) now flushes as real time elapses. The first
        // `step()` runs synchronously at load (counter 1); the rest fire at
        // rest, and the last sets a marker — which must appear.
        let (_handle, mut events) = live(
            r##"<body><div id="n">0</div><script>
            var n = 0;
            (function step() {
                n++;
                document.getElementById('n').textContent = String(n);
                if (n >= 6) { document.body.setAttribute('data-raf-done', 'yes'); return; }
                requestAnimationFrame(step);
            })();
            </script></body>"##,
        );
        let mut done = false;
        for _ in 0..24 {
            match events.blocking_recv() {
                Some(PageEvt::Updated { html, .. }) => {
                    if html.contains("data-raf-done=\"yes\"") {
                        assert!(html.contains(">6<"), "counter reached 6: {html}");
                        done = true;
                        break;
                    }
                }
                Some(PageEvt::Settled | PageEvt::Trouble(_)) => continue,
                Some(PageEvt::Static { .. }) => panic!("a rAF page must stay live"),
                other => panic!("expected a render, got {other:?}"),
            }
        }
        assert!(done, "the rAF chain must run to completion at rest");
    }

    #[test]
    fn a_page_with_nothing_to_click_goes_static() {
        let (_handle, mut events) = live(
            "<body><p id=t>quiet</p><script>\
             document.getElementById('t').textContent = 'ran';</script></body>",
        );
        match events.blocking_recv() {
            Some(PageEvt::Static { html, outcome }) => {
                assert!(html.contains("ran"), "{html}");
                assert!(outcome.errors.is_empty(), "{:?}", outcome.errors);
            }
            other => panic!("expected Static, got {other:?}"),
        }
        // The actor exited: the event channel is closed.
        assert!(events.blocking_recv().is_none());
    }

    /// Pull a `COUNT=<n>` value out of a render (the at-rest timer tests mark
    /// their counter this way so it's unambiguous in the serialized HTML).
    fn marked_count(html: &str) -> Option<u64> {
        let tail = html.split_once("COUNT=")?.1;
        let digits: String = tail.chars().take_while(|c| c.is_ascii_digit()).collect();
        digits.parse().ok()
    }

    #[test]
    fn an_at_rest_timeout_chain_fires_one_generation_per_wake() {
        // A perpetual `setTimeout(0)` re-arm chain — the shape React's scheduler
        // takes (its MessageChannel posts route through our `setTimeout(0)`), and
        // the shape a never-settling poll takes when its data is gated behind a
        // bot wall (Twitch). It fast-forwards during the load settle (to ~MAX_TICKS)
        // and then continues AT REST. Each at-rest wake must fire ONE generation
        // (`REST_TICKS`), not drain the re-arming chain dozens of times per wake —
        // the latter pegged a CPU core on any page that never reaches a fixpoint,
        // because `settle_to` would re-fire the due-now timer up to `DISPATCH_TICKS`
        // times in a SINGLE wake. So the counter climbs by a SMALL step between
        // consecutive at-rest renders, not ~50.
        let (_handle, mut events) = live(
            r##"<body><div id="n">COUNT=0</div><script>
            var n = 0;
            (function chain() {
                n++;
                document.getElementById('n').textContent = 'COUNT=' + n;
                setTimeout(chain, 0);
            })();
            </script></body>"##,
        );
        let mut counts = vec![];
        for _ in 0..80 {
            match events.blocking_recv() {
                Some(PageEvt::Updated { html, .. }) => {
                    if let Some(c) = marked_count(&html) {
                        counts.push(c);
                    }
                    if counts.len() >= 5 {
                        break;
                    }
                }
                Some(PageEvt::Settled | PageEvt::Trouble(_)) => continue,
                Some(PageEvt::Static { .. }) => panic!("a timer-chain page must stay live"),
                other => panic!("expected a render, got {other:?}"),
            }
        }
        assert!(
            counts.len() >= 4,
            "expected several at-rest renders, got {counts:?}"
        );
        // The chain advances (it's alive), but the STEADY at-rest increment per
        // render is one generation per wake. Skip the first delta — it spans the
        // load→rest handoff (the load fast-forwarded the chain to ~MAX_TICKS).
        let deltas: Vec<u64> = counts.windows(2).map(|w| w[1] - w[0]).collect();
        assert!(
            counts.last().unwrap() > counts.first().unwrap(),
            "the chain must keep advancing at rest: {counts:?}"
        );
        assert!(
            deltas[1..].iter().all(|&d| d <= 4),
            "each at-rest wake fires ~one generation (REST_TICKS), not ~DISPATCH_TICKS: deltas {deltas:?}"
        );
    }

    #[test]
    fn an_interval_keeps_ticking_at_rest() {
        // A page whose ONLY behavior is a `setInterval` incrementing a counter —
        // no clickables, no forms. Before the living-engine loop this went
        // Static and froze; now its own clock drives it at rest, so the counter
        // keeps climbing across real-time wakes (the core of step 1).
        let (_handle, mut events) = live(
            r##"<body><div id="n">COUNT=0</div><script>
            var n = 0;
            setInterval(function () { n++; document.getElementById('n').textContent = 'COUNT=' + n; }, 50);
            </script></body>"##,
        );
        // The first LIVE render (the interval page must NOT go Static).
        let first = loop {
            match events.blocking_recv() {
                Some(PageEvt::Updated { html, .. }) => {
                    if let Some(c) = marked_count(&html) {
                        break c;
                    }
                }
                Some(PageEvt::Static { .. }) => {
                    panic!("an interval page must stay live, not go Static")
                }
                Some(PageEvt::Settled | PageEvt::Trouble(_)) => continue,
                other => panic!("expected a render, got {other:?}"),
            }
        };
        // Subsequent renders arrive ~one per real frame (WAKE_FLOOR) as the
        // interval fires at rest; the counter must strictly climb.
        let mut later = first;
        for _ in 0..16 {
            match events.blocking_recv() {
                Some(PageEvt::Updated { html, .. }) => {
                    if let Some(c) = marked_count(&html) {
                        later = c;
                        if later > first + 2 {
                            break;
                        }
                    }
                }
                Some(PageEvt::Settled | PageEvt::Trouble(_)) => continue,
                other => panic!("expected a render, got {other:?}"),
            }
        }
        assert!(
            later > first,
            "the interval must keep ticking at rest: first={first} later={later}"
        );
    }

    #[test]
    fn an_interval_is_not_fast_forwarded_at_load() {
        // The load settle must NOT pre-run a repeating interval (it's ongoing
        // real-time work, not deferred init): the page paints its INITIAL state
        // — COUNT=0 — like a browser, instead of jumping to ~MAX_TICKS. The
        // at-rest loop then advances it (see `an_interval_keeps_ticking_at_rest`).
        let (_handle, mut events) = live(
            r##"<body><div id="n">COUNT=0</div><script>
            var n = 0;
            setInterval(function () { n++; document.getElementById('n').textContent = 'COUNT=' + n; }, 50);
            </script></body>"##,
        );
        let first = loop {
            match events.blocking_recv() {
                Some(PageEvt::Updated { html, .. }) => {
                    if let Some(c) = marked_count(&html) {
                        break c;
                    }
                }
                Some(PageEvt::Static { .. }) => panic!("an interval page must stay live"),
                Some(PageEvt::Settled | PageEvt::Trouble(_)) => continue,
                other => panic!("expected a render, got {other:?}"),
            }
        };
        assert_eq!(
            first, 0,
            "the interval must not fire during the load settle"
        );
    }

    #[test]
    fn timers_pass_extra_arguments_at_rest() {
        // HTML §8.6: setInterval/setTimeout forward trailing args to the
        // callback. Exercised at rest (intervals don't fast-forward), so this
        // also re-confirms the at-rest loop drives a net-less timer.
        let (_handle, mut events) = live(
            r##"<body><div id="out">none</div><script>
            setInterval(function (a, b) {
                document.getElementById('out').textContent = 'ARGS=' + a + b;
            }, 50, 'AL', 'PHA');
            </script></body>"##,
        );
        let mut saw = false;
        for _ in 0..16 {
            match events.blocking_recv() {
                Some(PageEvt::Updated { html, .. }) => {
                    if html.contains("ARGS=ALPHA") {
                        saw = true;
                        break;
                    }
                }
                Some(PageEvt::Settled | PageEvt::Trouble(_)) => continue,
                Some(PageEvt::Static { .. }) => panic!("a timer page must stay live"),
                other => panic!("expected a render, got {other:?}"),
            }
        }
        assert!(saw, "the timer callback received its trailing arguments");
    }

    #[test]
    fn request_animation_frame_runs_at_rest() {
        // A rAF chain (each frame schedules the next) is a one-shot setTimeout
        // driven by the same wake loop; it must keep firing at rest with a
        // monotonic timestamp, so the frame counter climbs. (rAF chains DO
        // fast-forward during the load settle — a documented deviation — so the
        // first render may already be well above 0; we assert it CLIMBS.)
        let (_handle, mut events) = live(
            r##"<body><div id="f">FRAME=0</div><script>
            var n = 0;
            function step(ts) {
                n++;
                document.getElementById('f').textContent = 'FRAME=' + n;
                requestAnimationFrame(step);
            }
            requestAnimationFrame(step);
            </script></body>"##,
        );
        fn frame(html: &str) -> Option<u64> {
            let tail = html.split_once("FRAME=")?.1;
            tail.chars()
                .take_while(|c| c.is_ascii_digit())
                .collect::<String>()
                .parse()
                .ok()
        }
        let first = loop {
            match events.blocking_recv() {
                Some(PageEvt::Updated { html, .. }) => {
                    if let Some(c) = frame(&html) {
                        break c;
                    }
                }
                Some(PageEvt::Static { .. }) => panic!("a rAF page must stay live"),
                Some(PageEvt::Settled | PageEvt::Trouble(_)) => continue,
                other => panic!("expected a render, got {other:?}"),
            }
        };
        let mut later = first;
        for _ in 0..16 {
            match events.blocking_recv() {
                Some(PageEvt::Updated { html, .. }) => {
                    if let Some(c) = frame(&html) {
                        later = c;
                        if later > first + 1 {
                            break;
                        }
                    }
                }
                Some(PageEvt::Settled | PageEvt::Trouble(_)) => continue,
                other => panic!("expected a render, got {other:?}"),
            }
        }
        assert!(
            later > first,
            "requestAnimationFrame must keep firing at rest: first={first} later={later}"
        );
    }

    #[test]
    fn an_idle_page_parks_without_spurious_renders() {
        // A clickable page with NO pending timers: after its load render the
        // actor parks on the command channel (no sleep arm) and emits NOTHING
        // at rest. A spurious Settled/Updated stream here would mean we wake
        // when we shouldn't — the zero-idle-CPU invariant the rework must keep.
        let (_handle, mut events) = live(
            r##"<body><button id="b">hi</button><script>
            document.getElementById('b').addEventListener('click', function () {});
            </script></body>"##,
        );
        match events.blocking_recv() {
            Some(PageEvt::Updated { .. }) => {}
            other => panic!("expected a live render, got {other:?}"),
        }
        // Give the actor real time to (mis)behave, then confirm it stayed quiet.
        std::thread::sleep(std::time::Duration::from_millis(200));
        match events.try_recv() {
            Err(tokio::sync::mpsc::error::TryRecvError::Empty) => {}
            other => panic!("an idle page must stay silent at rest, got {other:?}"),
        }
    }

    #[test]
    fn a_timer_can_navigate_at_rest() {
        // `setTimeout(() => location.href = …)` — a JS meta-refresh. The 1100ms
        // delay clears the load settle's 1000ms fast-forward window, so it fires
        // at REST (proving the timer wake routes script navigation), not at load.
        let (_handle, mut events) = live(
            r##"<body><p>redirecting…</p><script>
            setTimeout(function () { location.href = '/next'; }, 1100);
            </script></body>"##,
        );
        // Drain any load render(s), then expect the at-rest navigation.
        let mut navigated = None;
        for _ in 0..8 {
            match events.blocking_recv() {
                Some(PageEvt::Navigate(url)) => {
                    navigated = Some(url);
                    break;
                }
                Some(PageEvt::Updated { .. } | PageEvt::Settled) => continue,
                Some(PageEvt::Static { .. }) => {
                    panic!("a page with a pending timer must stay live")
                }
                other => panic!("expected Navigate, got {other:?}"),
            }
        }
        let url = navigated.expect("the timer must navigate at rest");
        assert!(
            url.ends_with("/next"),
            "resolved against the page base: {url}"
        );
    }

    /// Web Worker, end-to-end through the page actor: a page creates a real
    /// `Worker` (a second engine on its own thread), posts it a structured-clone
    /// message, and the worker echoes a (mutated) reply back, which fires the
    /// page's `onmessage` and re-renders. Proves the whole pipeline: spawn +
    /// script fetch + DOM-less worker scope + bidirectional structured-clone
    /// messaging + the worker→page forwarder + stay-alive-for-workers.
    #[test]
    fn a_worker_round_trips_a_structured_clone_message() {
        use tokio::io::{AsyncReadExt as _, AsyncWriteExt as _};
        let rt = tokio::runtime::Builder::new_multi_thread()
            .worker_threads(2)
            .enable_all()
            .build()
            .unwrap();
        let listener =
            rt.block_on(async { tokio::net::TcpListener::bind("127.0.0.1:0").await.unwrap() });
        let port = listener.local_addr().unwrap().port();
        rt.spawn(async move {
            loop {
                let Ok((mut sock, _)) = listener.accept().await else {
                    return;
                };
                let mut req = Vec::new();
                let mut buf = [0u8; 2048];
                while !req.windows(4).any(|w| w == b"\r\n\r\n") {
                    match sock.read(&mut buf).await {
                        Ok(0) | Err(_) => break,
                        Ok(n) => req.extend_from_slice(&buf[..n]),
                    }
                }
                let text = String::from_utf8_lossy(&req).into_owned();
                let reply: Vec<u8> = if text.starts_with("GET /worker.js ") {
                    b"HTTP/1.1 200 OK\r\nContent-Type: text/javascript\r\nConnection: close\r\n\r\n\
                      self.onmessage = function (e) {\
                        self.postMessage({ pong: e.data.ping + 1, who: self.name, items: [e.data.ping, 'x'] });\
                      };"
                    .to_vec()
                } else {
                    b"HTTP/1.1 404 Nope\r\nContent-Length: 0\r\n\r\n".to_vec()
                };
                let _ = sock.write_all(&reply).await;
            }
        });

        let html = format!(
            "<body><pre id=o></pre><script>\
             var w = new Worker('http://127.0.0.1:{port}/worker.js', {{ name: 'echo' }});\
             w.onmessage = function (e) {{ document.getElementById('o').textContent = 'GOT pong=' + e.data.pong + ' who=' + e.data.who + ' items=' + e.data.items.join('+'); }};\
             w.onerror = function (e) {{ document.getElementById('o').textContent = 'ERR ' + e.message; }};\
             w.postMessage({{ ping: 41 }});\
             </script></body>"
        );
        let mut env = PageEnv::bare(&format!("http://127.0.0.1:{port}/"));
        env.net = Some(rt.handle().clone());
        let (handle, mut events) = spawn_page(html, env);

        // Poll (not blocking_recv) so a stuck worker can't hang the suite.
        let deadline = std::time::Instant::now() + Duration::from_secs(15);
        let mut got = String::new();
        while std::time::Instant::now() < deadline {
            match events.try_recv() {
                Ok(PageEvt::Updated { html, .. }) | Ok(PageEvt::Static { html, .. }) => {
                    got = html;
                    if got.contains("GOT pong=") || got.contains("ERR ") {
                        break;
                    }
                }
                Ok(_) => {}
                Err(tokio::sync::mpsc::error::TryRecvError::Empty) => {
                    std::thread::sleep(Duration::from_millis(20));
                }
                Err(tokio::sync::mpsc::error::TryRecvError::Disconnected) => break,
            }
        }
        drop(handle);
        assert!(
            got.contains("GOT pong=42 who=echo items=41+x"),
            "worker round-trip failed: {got}"
        );
    }

    /// A binary request body — a `Uint8Array` carrying bytes >= 0x80, e.g. a page
    /// that gzips its own POST (YouTube's `youtubei` search continuation) — must
    /// reach the wire BYTE-EXACT. The prelude flattens it to a latin1 byte-string
    /// (`__bodyWire`) and the syscall decodes it byte-for-byte
    /// (`arg_bytes_latin1`). The old path round-tripped it through a UTF-8 Rust
    /// `String` (`into_bytes`), doubling every byte >= 0x80 (`8b` -> `c2 8b`), so
    /// the server saw a corrupt gzip stream and rejected it with 400.
    #[test]
    fn a_binary_request_body_reaches_the_wire_byte_exact() {
        use std::sync::{Arc, Mutex};
        use tokio::io::{AsyncReadExt as _, AsyncWriteExt as _};
        let rt = tokio::runtime::Builder::new_multi_thread()
            .worker_threads(2)
            .enable_all()
            .build()
            .unwrap();
        let listener =
            rt.block_on(async { tokio::net::TcpListener::bind("127.0.0.1:0").await.unwrap() });
        let port = listener.local_addr().unwrap().port();
        let captured: Arc<Mutex<Vec<u8>>> = Arc::new(Mutex::new(Vec::new()));
        let cap = captured.clone();
        rt.spawn(async move {
            let Ok((mut sock, _)) = listener.accept().await else {
                return;
            };
            let mut req = Vec::new();
            let mut buf = [0u8; 4096];
            loop {
                if let Some(pos) = req.windows(4).position(|w| w == b"\r\n\r\n") {
                    let head = String::from_utf8_lossy(&req[..pos]).to_lowercase();
                    let clen = head
                        .lines()
                        .find_map(|l| l.strip_prefix("content-length:"))
                        .and_then(|v| v.trim().parse::<usize>().ok())
                        .unwrap_or(0);
                    let start = pos + 4;
                    while req.len() < start + clen {
                        match sock.read(&mut buf).await {
                            Ok(0) | Err(_) => break,
                            Ok(n) => req.extend_from_slice(&buf[..n]),
                        }
                    }
                    *cap.lock().unwrap() = req[start..(start + clen).min(req.len())].to_vec();
                    break;
                }
                match sock.read(&mut buf).await {
                    Ok(0) | Err(_) => break,
                    Ok(n) => req.extend_from_slice(&buf[..n]),
                }
            }
            let _ = sock
                .write_all(b"HTTP/1.1 200 OK\r\nContent-Length: 2\r\nConnection: close\r\n\r\nok")
                .await;
        });

        let html = format!(
            "<body><script>\
             fetch('http://127.0.0.1:{port}/echo', {{ method: 'POST', \
             body: new Uint8Array([0x1f, 0x8b, 0x08, 0x00, 0xff, 0x80, 0xc2, 0xa5]) }});\
             </script></body>"
        );
        let mut env = PageEnv::bare(&format!("http://127.0.0.1:{port}/"));
        env.net = Some(rt.handle().clone());
        let (handle, _events) = spawn_page(html, env);

        let deadline = std::time::Instant::now() + Duration::from_secs(15);
        while captured.lock().unwrap().is_empty() && std::time::Instant::now() < deadline {
            std::thread::sleep(Duration::from_millis(20));
        }
        drop(handle);
        let body = captured.lock().unwrap().clone();
        assert_eq!(
            body,
            vec![0x1f, 0x8b, 0x08, 0x00, 0xff, 0x80, 0xc2, 0xa5],
            "binary POST body must reach the wire byte-exact, got {body:02x?}"
        );
    }

    #[test]
    fn formdata_collects_form_fields_and_supports_the_entry_api() {
        // FormData (XHR standard §5): the entry API (append/set/get/getAll/
        // delete/has, iteration, Blob→File conversion) and `new FormData(form)`
        // collecting submittable fields per HTML §"constructing the entry
        // list" — named enabled fields, checked-only checkboxes/radios,
        // selected options, no buttons. Steam's store main.js news one up in a
        // timer; a ReferenceError there degraded the page badge to ·JS:n!.
        let (out, outcome) = page(
            r##"<body>
            <form id=f>
              <input name=user value=ruby>
              <input type=checkbox name=on1 checked>
              <input type=checkbox name=off1>
              <input type=radio name=pick value=b checked>
              <input type=radio name=pick value=c>
              <select name=sel><option value=x>x</option><option value=y selected>y</option></select>
              <textarea name=note>hello</textarea>
              <input name=nope disabled value=no>
              <input type=submit name=go value=Go>
            </form>
            <div id=out></div><script>
            var ok = [];
            var fd = new FormData();
            fd.append('a', '1'); fd.append('a', '2'); fd.append('b', 3);
            ok.push(fd.get('a') === '1');
            ok.push(fd.getAll('a').join(',') === '1,2');
            ok.push(fd.has('b') && fd.get('b') === '3');
            fd.set('a', '9');
            ok.push(fd.getAll('a').join(',') === '9');
            fd.delete('b');
            ok.push(!fd.has('b'));
            var names = [];
            for (var e of fd) names.push(e[0] + '=' + e[1]);
            ok.push(names.join('&') === 'a=9');
            fd.append('file', new Blob(['bytes'], { type: 'text/x-thing' }), 'thing.txt');
            ok.push(fd.get('file') instanceof File && fd.get('file').name === 'thing.txt');
            var got = [];
            new FormData(document.getElementById('f')).forEach(function (v, k) { got.push(k + '=' + v); });
            ok.push(got.join('&') === 'user=ruby&on1=on&pick=b&sel=y&note=hello');
            document.getElementById('out').textContent = ok.join(' ');
            </script></body>"##,
        );
        assert!(outcome.errors.is_empty(), "{:?}", outcome.errors);
        assert!(
            out.contains("true true true true true true true true"),
            "FormData probes failed: {out}"
        );
    }

    /// A `fetch(url, {body: FormData})` goes on the wire as multipart/form-data
    /// (RFC 7578): the Content-Type header advertises the boundary, each entry
    /// is a Content-Disposition part, a File part carries filename + its own
    /// type, and the body closes with the terminal boundary.
    #[test]
    fn a_formdata_body_posts_multipart_with_a_boundary() {
        use std::sync::{Arc, Mutex};
        use tokio::io::{AsyncReadExt as _, AsyncWriteExt as _};
        let rt = tokio::runtime::Builder::new_multi_thread()
            .worker_threads(2)
            .enable_all()
            .build()
            .unwrap();
        let listener =
            rt.block_on(async { tokio::net::TcpListener::bind("127.0.0.1:0").await.unwrap() });
        let port = listener.local_addr().unwrap().port();
        let captured: Arc<Mutex<Vec<u8>>> = Arc::new(Mutex::new(Vec::new()));
        let cap = captured.clone();
        rt.spawn(async move {
            let Ok((mut sock, _)) = listener.accept().await else {
                return;
            };
            let mut req = Vec::new();
            let mut buf = [0u8; 4096];
            loop {
                if let Some(pos) = req.windows(4).position(|w| w == b"\r\n\r\n") {
                    let head = String::from_utf8_lossy(&req[..pos]).to_lowercase();
                    let clen = head
                        .lines()
                        .find_map(|l| l.strip_prefix("content-length:"))
                        .and_then(|v| v.trim().parse::<usize>().ok())
                        .unwrap_or(0);
                    let start = pos + 4;
                    while req.len() < start + clen {
                        match sock.read(&mut buf).await {
                            Ok(0) | Err(_) => break,
                            Ok(n) => req.extend_from_slice(&buf[..n]),
                        }
                    }
                    *cap.lock().unwrap() = req;
                    break;
                }
                match sock.read(&mut buf).await {
                    Ok(0) | Err(_) => break,
                    Ok(n) => req.extend_from_slice(&buf[..n]),
                }
            }
            let _ = sock
                .write_all(b"HTTP/1.1 200 OK\r\nContent-Length: 2\r\nConnection: close\r\n\r\nok")
                .await;
        });

        let html = format!(
            "<body><script>\
             var fd = new FormData();\
             fd.append('kind', 'story');\
             fd.append('data', new Blob(['payload'], {{ type: 'text/x-data' }}), 'p.bin');\
             fetch('http://127.0.0.1:{port}/up', {{ method: 'POST', body: fd }});\
             </script></body>"
        );
        let mut env = PageEnv::bare(&format!("http://127.0.0.1:{port}/"));
        env.net = Some(rt.handle().clone());
        let (handle, _events) = spawn_page(html, env);

        let deadline = std::time::Instant::now() + Duration::from_secs(15);
        while captured.lock().unwrap().is_empty() && std::time::Instant::now() < deadline {
            std::thread::sleep(Duration::from_millis(20));
        }
        drop(handle);
        let req = String::from_utf8_lossy(&captured.lock().unwrap().clone()).to_string();
        let boundary = req
            .lines()
            .find_map(|l| {
                l.to_ascii_lowercase()
                    .strip_prefix("content-type: multipart/form-data; boundary=")
                    .map(|b| l[l.len() - b.len()..].to_string())
            })
            .unwrap_or_else(|| panic!("no multipart content-type header in: {req}"));
        let expect_field = format!(
            "--{boundary}\r\nContent-Disposition: form-data; name=\"kind\"\r\n\r\nstory\r\n"
        );
        assert!(req.contains(&expect_field), "field part missing: {req}");
        let expect_file = format!(
            "--{boundary}\r\nContent-Disposition: form-data; name=\"data\"; filename=\"p.bin\"\r\n\
             Content-Type: text/x-data\r\n\r\npayload\r\n"
        );
        assert!(req.contains(&expect_file), "file part missing: {req}");
        assert!(
            req.ends_with(&format!("--{boundary}--\r\n")),
            "terminal boundary missing: {req}"
        );
    }

    /// Phase 3 inner scroll, end-to-end: the app pushes a region's box geometry
    /// (`RegionGeom`), the page reads the TRUE `clientHeight`/`scrollHeight` and
    /// pins (`scrollTop = scrollHeight`), and the next render bakes
    /// `data-trust-scroll-top` (rows) — the signal `flow_region` re-seeds the
    /// region's voffset from. Proves the geometry round-trip + the `scrollTop`
    /// setter (clamp to `scrollHeight − clientHeight`) + the baked signal
    /// together, which is exactly the chat pin-to-bottom path.
    #[test]
    fn a_region_pins_using_pushed_geometry_and_bakes_the_signal() {
        fn id_after(html: &str, marker: &str) -> usize {
            let start = html
                .find(marker)
                .unwrap_or_else(|| panic!("marker {marker} not in {html}"))
                + marker.len();
            html[start..]
                .chars()
                .take_while(char::is_ascii_digit)
                .collect::<String>()
                .parse()
                .unwrap()
        }
        fn next_updated(events: &mut tokio::sync::mpsc::Receiver<PageEvt>) -> String {
            let deadline = std::time::Instant::now() + Duration::from_secs(10);
            while std::time::Instant::now() < deadline {
                match events.try_recv() {
                    Ok(PageEvt::Updated { html, .. }) | Ok(PageEvt::Static { html, .. }) => {
                        return html;
                    }
                    Ok(_) => {}
                    Err(tokio::sync::mpsc::error::TryRecvError::Empty) => {
                        std::thread::sleep(Duration::from_millis(20));
                    }
                    Err(_) => break,
                }
            }
            panic!("no render received");
        }

        // The scroll container gets a `data-trust-node`; the anchor (the trigger)
        // gets a JsClick `x-trust-js:<id>:` marker, NOT a node id — so each marker
        // is unambiguous. The onclick reads the geometry, then pins. 40 rows of
        // content overflow the 64px (4-row) clip the app pushes.
        let mut lines = String::new();
        for i in 0..40 {
            lines.push_str(&format!("<p>line {i}</p>"));
        }
        let html = format!(
            "<body>\
             <div id=s style='overflow-y:auto;height:64px'>{lines}</div>\
             <pre id=o>idle</pre>\
             <a href='#' onclick=\"var s=document.getElementById('s');\
               document.getElementById('o').textContent='ch='+s.clientHeight+' sh='+s.scrollHeight;\
               s.scrollTop=s.scrollHeight; return false;\">pin</a>\
             <script>window.__ready = 1;</script>\
             </body>"
        );
        let env = PageEnv::bare("https://example.com/");
        let (handle, mut events) = spawn_page(html, env);

        let first = next_updated(&mut events);
        let region_node = id_after(&first, "data-trust-node=\"");
        let click_id = id_after(&first, "x-trust-js:");
        assert!(
            !first.contains("data-trust-scroll-top"),
            "a fresh region has no scroll signal yet: {first}"
        );

        // The app measured the region's CLIP box (a 64px viewport). Push it, then
        // click the pin — the page reads clientHeight=64 (pushed) and scrollHeight
        // from the actor's fresh measure (the 40-row content, ≫ 64).
        handle
            .cmds
            .blocking_send(PageCmd::RegionGeom {
                items: vec![(region_node, 64.0, 100.0)],
            })
            .unwrap();
        handle.cmds.blocking_send(PageCmd::Click(click_id)).unwrap();

        let got = next_updated(&mut events);
        drop(handle);
        assert!(
            got.contains("ch=64"),
            "the page read the pushed clientHeight: {got}"
        );
        let sh = id_after(&got, "sh=");
        assert!(
            sh > 64,
            "scrollHeight read the fresh content extent (> the 64px clip): sh={sh} in {got}"
        );
        // scrollTop pins to scrollHeight − clientHeight > 0 ⇒ a non-zero signal.
        let signal = id_after(&got, "data-trust-scroll-top=\"");
        assert!(
            signal > 0,
            "the pin baked a non-zero scrollTop signal (rows): {got}"
        );
    }

    /// The worker scope is DOM-less and spec-shaped, and its own event loop runs
    /// timers at rest. A worker MUST NOT expose `window`/`document` (libraries
    /// detect worker context exactly that way); `self === globalThis`;
    /// `importScripts` is callable; `navigator` is present. The reply is sent
    /// from a `setTimeout` so it also proves the worker's real-time timer loop
    /// fires without a message to pump it.
    #[test]
    fn a_worker_scope_is_dom_less_and_runs_timers() {
        use tokio::io::{AsyncReadExt as _, AsyncWriteExt as _};
        let rt = tokio::runtime::Builder::new_multi_thread()
            .worker_threads(2)
            .enable_all()
            .build()
            .unwrap();
        let listener =
            rt.block_on(async { tokio::net::TcpListener::bind("127.0.0.1:0").await.unwrap() });
        let port = listener.local_addr().unwrap().port();
        rt.spawn(async move {
            loop {
                let Ok((mut sock, _)) = listener.accept().await else {
                    return;
                };
                let mut req = Vec::new();
                let mut buf = [0u8; 2048];
                while !req.windows(4).any(|w| w == b"\r\n\r\n") {
                    match sock.read(&mut buf).await {
                        Ok(0) | Err(_) => break,
                        Ok(n) => req.extend_from_slice(&buf[..n]),
                    }
                }
                let reply: Vec<u8> = if String::from_utf8_lossy(&req).starts_with("GET /w.js ") {
                    b"HTTP/1.1 200 OK\r\nContent-Type: text/javascript\r\nConnection: close\r\n\r\n\
                      self.onmessage = function () {\
                        setTimeout(function () {\
                          self.postMessage({ win: typeof window, doc: typeof document,\
                            sg: (self === globalThis), imp: typeof importScripts,\
                            hwc: navigator.hardwareConcurrency, t: 'fired' });\
                        }, 30);\
                      };"
                    .to_vec()
                } else {
                    b"HTTP/1.1 404 Nope\r\nContent-Length: 0\r\n\r\n".to_vec()
                };
                let _ = sock.write_all(&reply).await;
            }
        });
        let html = format!(
            "<body><pre id=o></pre><script>\
             var w = new Worker('http://127.0.0.1:{port}/w.js');\
             w.onmessage = function (e) {{ var d = e.data; document.getElementById('o').textContent = \
               'SCOPE win=' + d.win + ' doc=' + d.doc + ' sg=' + d.sg + ' imp=' + d.imp + ' hwc=' + (typeof d.hwc) + ' t=' + d.t; }};\
             w.postMessage('go');\
             </script></body>"
        );
        let mut env = PageEnv::bare(&format!("http://127.0.0.1:{port}/"));
        env.net = Some(rt.handle().clone());
        let (handle, mut events) = spawn_page(html, env);
        let deadline = std::time::Instant::now() + Duration::from_secs(15);
        let mut got = String::new();
        while std::time::Instant::now() < deadline {
            match events.try_recv() {
                Ok(PageEvt::Updated { html, .. }) | Ok(PageEvt::Static { html, .. }) => {
                    got = html;
                    if got.contains("SCOPE ") {
                        break;
                    }
                }
                Ok(_) => {}
                Err(tokio::sync::mpsc::error::TryRecvError::Empty) => {
                    std::thread::sleep(Duration::from_millis(20));
                }
                Err(tokio::sync::mpsc::error::TryRecvError::Disconnected) => break,
            }
        }
        drop(handle);
        assert!(
            got.contains(
                "SCOPE win=undefined doc=undefined sg=true imp=function hwc=number t=fired"
            ),
            "worker scope/timer invariants: {got}"
        );
    }

    #[test]
    fn wasm_runs_inside_a_worker() {
        // WebAssembly is available in the worker scope (its own engine on the
        // worker thread): a worker compiles + instantiates + calls, off-thread.
        use tokio::io::{AsyncReadExt as _, AsyncWriteExt as _};
        let bytes = wat_u8(
            r#"(module (func (export "add") (param i32 i32) (result i32)
                local.get 0 local.get 1 i32.add))"#,
        );
        let worker_js = format!(
            "self.onmessage = function () {{\
               var inst = new WebAssembly.Instance(new WebAssembly.Module({bytes}));\
               self.postMessage({{ r: inst.exports.add(40, 2), wa: (typeof WebAssembly) }});\
             }};"
        );
        let reply = format!(
            "HTTP/1.1 200 OK\r\nContent-Type: text/javascript\r\nConnection: close\r\n\r\n{worker_js}"
        )
        .into_bytes();
        let rt = tokio::runtime::Builder::new_multi_thread()
            .worker_threads(2)
            .enable_all()
            .build()
            .unwrap();
        let listener =
            rt.block_on(async { tokio::net::TcpListener::bind("127.0.0.1:0").await.unwrap() });
        let port = listener.local_addr().unwrap().port();
        rt.spawn(async move {
            loop {
                let Ok((mut sock, _)) = listener.accept().await else {
                    return;
                };
                let reply = reply.clone();
                let mut req = Vec::new();
                let mut buf = [0u8; 2048];
                while !req.windows(4).any(|w| w == b"\r\n\r\n") {
                    match sock.read(&mut buf).await {
                        Ok(0) | Err(_) => break,
                        Ok(n) => req.extend_from_slice(&buf[..n]),
                    }
                }
                let out: Vec<u8> = if String::from_utf8_lossy(&req).starts_with("GET /w.js ") {
                    reply
                } else {
                    b"HTTP/1.1 404 Nope\r\nContent-Length: 0\r\n\r\n".to_vec()
                };
                let _ = sock.write_all(&out).await;
            }
        });
        let html = format!(
            "<body><pre id=o></pre><script>\
             var w = new Worker('http://127.0.0.1:{port}/w.js');\
             w.onmessage = function (e) {{ document.getElementById('o').textContent = \
               'WASMW r=' + e.data.r + ' wa=' + e.data.wa; }};\
             w.postMessage('go');\
             </script></body>"
        );
        let mut env = PageEnv::bare(&format!("http://127.0.0.1:{port}/"));
        env.net = Some(rt.handle().clone());
        let (handle, mut events) = spawn_page(html, env);
        let deadline = std::time::Instant::now() + Duration::from_secs(15);
        let mut got = String::new();
        while std::time::Instant::now() < deadline {
            match events.try_recv() {
                Ok(PageEvt::Updated { html, .. }) | Ok(PageEvt::Static { html, .. }) => {
                    got = html;
                    if got.contains("WASMW ") {
                        break;
                    }
                }
                Ok(_) => {}
                Err(tokio::sync::mpsc::error::TryRecvError::Empty) => {
                    std::thread::sleep(Duration::from_millis(20));
                }
                Err(tokio::sync::mpsc::error::TryRecvError::Disconnected) => break,
            }
        }
        drop(handle);
        assert!(
            got.contains("WASMW r=42 wa=object"),
            "wasm in worker: {got}"
        );
    }

    /// React synthetic-event system, end-to-end through the page actor:
    /// a `useState` counter whose `onClick` is delegated at the root
    /// container. A real click must bubble to React's root listener, map
    /// the target DOM node back to its fiber, fire the handler, and
    /// re-render. Manual (needs the bundles), like `react_canary`.
    #[test]
    #[ignore = "manual canary: needs React bundles in target/canary/"]
    fn react_clicks_drive_a_state_counter() {
        let (Ok(react), Ok(react_dom)) = (
            std::fs::read("target/canary/react.production.min.js"),
            std::fs::read("target/canary/react-dom.production.min.js"),
        ) else {
            eprintln!("no React bundles in target/canary/");
            return;
        };
        const PROBE: &str = r##"
            var e = React.createElement;
            function App() {
                var st = React.useState(0);
                var n = st[0], setN = st[1];
                return e("div", { className: "react-app" }, [
                    e("h1", { key: "h" }, "count: " + n),
                    e("button", { key: "b", onClick: function () { setN(n + 1); } }, "increment"),
                ]);
            }
            ReactDOM.createRoot(document.getElementById("target")).render(e(App));
        "##;
        let html = format!(
            "<html><head>\
             <script src=\"/react.js\"></script>\
             <script src=\"/react-dom.js\"></script>\
             </head><body><div id=\"target\"></div>\
             <script>{PROBE}</script></body></html>"
        );
        let mut env = PageEnv::bare("https://example.com/");
        env.externals = vec![
            ("/react.js".to_string(), Some(std::sync::Arc::new(react))),
            (
                "/react-dom.js".to_string(),
                Some(std::sync::Arc::new(react_dom)),
            ),
        ];
        let (handle, mut events) = spawn_page(html, env);

        // Drain to the render that actually shows the React tree (the actor
        // may emit a clickable shell first, then the filled render).
        let mut html = String::new();
        for _ in 0..4 {
            match events.blocking_recv() {
                Some(PageEvt::Updated { html: h, outcome })
                | Some(PageEvt::Static { html: h, outcome }) => {
                    assert!(outcome.errors.is_empty(), "{:?}", outcome.errors);
                    html = h;
                    if html.contains("count: 0") {
                        break;
                    }
                }
                other => panic!("expected Updated/Static, got {other:?}"),
            }
        }
        assert!(html.contains("count: 0"), "initial render missing: {html}");
        let button = html
            .split("x-trust-js:")
            .nth(1)
            .and_then(|r| r.split(':').next())
            .expect("a clickable marker for the React button")
            .parse::<usize>()
            .unwrap();

        handle.cmds.blocking_send(PageCmd::Click(button)).unwrap();
        let Some(PageEvt::Updated { html, outcome }) = events.blocking_recv() else {
            panic!("expected Updated after React click");
        };
        assert!(outcome.errors.is_empty(), "{:?}", outcome.errors);
        assert!(
            html.contains("count: 1"),
            "React onClick did not re-render through the synthetic event system: {html}"
        );
    }

    /// React controlled inputs: a text field whose `value` is React state
    /// and whose `onChange` writes it back. React installs a value-tracker
    /// on the input (an instance `value` setter) and only fires onChange if
    /// the tracker sees a real change. Our `formSet` sets `el.value` then
    /// fires `input` — this proves the change still reaches React.
    #[test]
    #[ignore = "manual canary: needs React bundles in target/canary/"]
    fn react_controlled_input_reflects_set_value() {
        let (Ok(react), Ok(react_dom)) = (
            std::fs::read("target/canary/react.production.min.js"),
            std::fs::read("target/canary/react-dom.production.min.js"),
        ) else {
            eprintln!("no React bundles in target/canary/");
            return;
        };
        const PROBE: &str = r##"
            var e = React.createElement;
            function App() {
                var st = React.useState("");
                var text = st[0], setText = st[1];
                return e("div", { className: "react-app" }, [
                    e("input", { key: "i", id: "field", value: text,
                        onChange: function (ev) { setText(ev.target.value); } }),
                    e("p", { key: "p", className: "echo" }, "echo: " + text),
                ]);
            }
            ReactDOM.createRoot(document.getElementById("target")).render(e(App));
        "##;
        let html = format!(
            "<html><head>\
             <script src=\"/react.js\"></script>\
             <script src=\"/react-dom.js\"></script>\
             </head><body><div id=\"target\"></div>\
             <script>{PROBE}</script></body></html>"
        );
        let mut env = PageEnv::bare("https://example.com/");
        env.externals = vec![
            ("/react.js".to_string(), Some(std::sync::Arc::new(react))),
            (
                "/react-dom.js".to_string(),
                Some(std::sync::Arc::new(react_dom)),
            ),
        ];
        let (handle, mut events) = spawn_page(html, env);

        let mut html = String::new();
        for _ in 0..4 {
            match events.blocking_recv() {
                Some(PageEvt::Updated { html: h, outcome })
                | Some(PageEvt::Static { html: h, outcome }) => {
                    assert!(outcome.errors.is_empty(), "{:?}", outcome.errors);
                    html = h;
                    if html.contains("echo:") {
                        break;
                    }
                }
                other => panic!("expected Updated/Static, got {other:?}"),
            }
        }
        // Find the input field's actor node id (data-trust-node on controls).
        let field = html
            .split("data-trust-node=\"")
            .nth(1)
            .and_then(|r| r.split('"').next())
            .expect("a data-trust-node on the input")
            .parse::<usize>()
            .unwrap();

        handle
            .cmds
            .blocking_send(PageCmd::SetValue {
                node: field,
                value: "hello".into(),
                checked: None,
            })
            .unwrap();
        let Some(PageEvt::Updated { html, outcome }) = events.blocking_recv() else {
            panic!("expected Updated after SetValue");
        };
        assert!(outcome.errors.is_empty(), "{:?}", outcome.errors);
        assert!(
            html.contains("echo: hello"),
            "React onChange did not see the controlled-input value: {html}"
        );
    }

    #[test]
    fn contenteditable_host_is_an_editable_field() {
        // A `contenteditable` div is a typeable field. The host keeps the page
        // resident (like a form control); SetValue drives the real editing
        // algorithm — a cancelable `beforeinput`, then the content is replaced
        // and `input` fires (inputType "insertText") — so a listener sees the
        // edit and the host's text reflects it. This is the general
        // rich-text-editor input path (ProseMirror/TipTap, Quill, comment boxes).
        let html = "<body>\
             <div contenteditable=\"true\" id=\"ed\" data-placeholder=\"Type here\"></div>\
             <pre id=\"out\"></pre>\
             <script>\
               const ed = document.getElementById('ed');\
               ed.addEventListener('input', (e) => { \
                 document.getElementById('out').textContent = 'in:' + ed.textContent + '|it:' + e.inputType; });\
             </script></body>";
        let env = PageEnv::bare("https://example.com/");
        let (handle, mut events) = spawn_page(html.to_string(), env);
        // First render: the live shell. The contenteditable host keeps it live.
        let first = match events.blocking_recv() {
            Some(PageEvt::Updated { html, outcome }) => {
                assert!(outcome.errors.is_empty(), "{:?}", outcome.errors);
                html
            }
            other => panic!("expected a live Updated shell, got {other:?}"),
        };
        // The host carries a data-trust-node (it routes to the editable path).
        let node = first
            .split("data-trust-node=\"")
            .nth(1)
            .and_then(|r| r.split('"').next())
            .expect("a data-trust-node on the contenteditable host")
            .parse::<usize>()
            .unwrap();
        handle
            .cmds
            .blocking_send(PageCmd::SetValue {
                node,
                value: "hello world".into(),
                checked: None,
            })
            .unwrap();
        let Some(PageEvt::Updated { html, outcome }) = events.blocking_recv() else {
            panic!("expected Updated after editing the contenteditable");
        };
        assert!(outcome.errors.is_empty(), "{:?}", outcome.errors);
        assert!(
            html.contains("in:hello world|it:insertText"),
            "input listener did not see the edit: {html}"
        );
        assert!(
            html.contains("hello world"),
            "host content not updated: {html}"
        );
    }

    /// A TodoMVC-shaped React app driven end-to-end through the page actor:
    /// the live proof that controlled inputs, form submit, keyed list
    /// rendering, checkbox toggle, and delete all compose. Written with
    /// `createElement` (no JSX/Babel — that's a build step that doesn't ship
    /// to most production sites; the runtime is what we care about).
    #[test]
    #[ignore = "manual canary: needs React bundles in target/canary/"]
    fn react_todomvc_app_runs_through_the_actor() {
        let (Ok(react), Ok(react_dom)) = (
            std::fs::read("target/canary/react.production.min.js"),
            std::fs::read("target/canary/react-dom.production.min.js"),
        ) else {
            eprintln!("no React bundles in target/canary/");
            return;
        };
        const PROBE: &str = r##"
            var e = React.createElement, useState = React.useState, useRef = React.useRef;
            function TodoApp() {
                var ts = useState([]); var todos = ts[0], setTodos = ts[1];
                var ds = useState(""); var draft = ds[0], setDraft = ds[1];
                var nextId = useRef(1);
                function add(ev) {
                    ev.preventDefault();
                    var t = draft.trim(); if (!t) return;
                    setTodos(todos.concat([{ id: nextId.current++, text: t, done: false }]));
                    setDraft("");
                }
                function toggle(id) {
                    setTodos(todos.map(function (t) {
                        return t.id === id ? { id: t.id, text: t.text, done: !t.done } : t;
                    }));
                }
                function remove(id) {
                    setTodos(todos.filter(function (t) { return t.id !== id; }));
                }
                var left = todos.filter(function (t) { return !t.done; }).length;
                return e("div", { className: "todoapp" }, [
                    e("form", { key: "f", onSubmit: add }, [
                        e("input", { key: "i", id: "new-todo", value: draft,
                            onChange: function (ev) { setDraft(ev.target.value); } }),
                        e("button", { key: "a", type: "submit" }, "ADD"),
                    ]),
                    e("ul", { key: "l", className: "todo-list" }, todos.map(function (t) {
                        return e("li", { key: t.id, className: t.done ? "completed" : "active" }, [
                            e("input", { key: "c", type: "checkbox", className: "toggle",
                                checked: t.done, onChange: function () { toggle(t.id); } }),
                            e("label", { key: "t" }, t.text),
                            e("button", { key: "d", className: "destroy",
                                onClick: function () { remove(t.id); } }, "DEL-" + t.id),
                        ]);
                    })),
                    e("span", { key: "n", className: "todo-count" }, left + " left"),
                ]);
            }
            ReactDOM.createRoot(document.getElementById("target")).render(e(TodoApp));
        "##;
        let html = format!(
            "<html><head>\
             <script src=\"/react.js\"></script>\
             <script src=\"/react-dom.js\"></script>\
             </head><body><div id=\"target\"></div>\
             <script>{PROBE}</script></body></html>"
        );
        let mut env = PageEnv::bare("https://example.com/");
        env.externals = vec![
            ("/react.js".to_string(), Some(std::sync::Arc::new(react))),
            (
                "/react-dom.js".to_string(),
                Some(std::sync::Arc::new(react_dom)),
            ),
        ];
        let (handle, mut events) = spawn_page(html, env);

        // Helpers over the serialized snapshot. The actor node id of the
        // first element whose serialization (from `marker` onward) carries a
        // data-trust-node — used to find a specific control by a preceding
        // attribute like `id="new-todo"` or the `<form` tag.
        fn node_after(html: &str, marker: &str) -> usize {
            let from = html.find(marker).unwrap_or_else(|| panic!("no {marker:?}"));
            html[from..]
                .split("data-trust-node=\"")
                .nth(1)
                .and_then(|r| r.split('"').next())
                .expect("a data-trust-node")
                .parse()
                .unwrap()
        }
        // The actor node id of the clickable whose wrapped content holds `text`.
        fn marker_for(html: &str, text: &str) -> usize {
            for seg in html.split("x-trust-js:").skip(1) {
                let id: usize = seg.split(':').next().unwrap().parse().unwrap();
                let content = seg
                    .split_once("\">")
                    .map(|(_, c)| c.split("</a>").next().unwrap_or(""))
                    .unwrap_or("");
                if content.contains(text) {
                    return id;
                }
            }
            panic!("no clickable marker containing {text:?} in {html}");
        }
        let drain = |events: &mut tokio::sync::mpsc::Receiver<PageEvt>, want: &str| -> String {
            use tokio::sync::mpsc::error::TryRecvError;
            let deadline = Instant::now() + std::time::Duration::from_secs(10);
            loop {
                match events.try_recv() {
                    Ok(PageEvt::Updated { html, outcome })
                    | Ok(PageEvt::Static { html, outcome }) => {
                        assert!(outcome.errors.is_empty(), "{:?}", outcome.errors);
                        if html.contains(want) {
                            return html;
                        }
                    }
                    Ok(_) => {}
                    Err(TryRecvError::Empty) => {
                        if Instant::now() > deadline {
                            panic!("timeout waiting for {want:?}");
                        }
                        std::thread::sleep(std::time::Duration::from_millis(20));
                    }
                    Err(TryRecvError::Disconnected) => panic!("actor closed waiting for {want:?}"),
                }
            }
        };

        // Adds a todo: type into the controlled input, then submit the form
        // (the ADD button is type=submit — the app routes such controls to
        // PageCmd::Submit, exactly as it would for a user pressing it).
        let add_todo = |handle: &PageHandle,
                        events: &mut tokio::sync::mpsc::Receiver<PageEvt>,
                        html: &str,
                        text: &str|
         -> String {
            let input = node_after(html, "id=\"new-todo\"");
            handle
                .cmds
                .blocking_send(PageCmd::SetValue {
                    node: input,
                    value: text.into(),
                    checked: None,
                })
                .unwrap();
            let html = drain(events, text);
            let form = node_after(&html, "<form");
            let submitter = node_after(&html, "type=\"submit\"");
            handle
                .cmds
                .blocking_send(PageCmd::Submit {
                    form,
                    submitter: Some(submitter),
                })
                .unwrap();
            html
        };

        // Initial render: empty list, "0 left".
        let html = drain(&mut events, "0 left");

        // Add the first todo and confirm it renders as an active item.
        add_todo(&handle, &mut events, &html, "buy milk");
        let html = drain(&mut events, "1 left");
        assert!(
            html.contains(">buy milk</label>"),
            "todo not rendered: {html}"
        );
        assert!(
            html.contains("class=\"active\""),
            "todo should be active: {html}"
        );

        // Add a second todo.
        add_todo(&handle, &mut events, &html, "walk dog");
        let html = drain(&mut events, "2 left");

        // Toggle the first todo complete via its checkbox.
        let check1 = node_after(&html, "class=\"toggle\"");
        handle
            .cmds
            .blocking_send(PageCmd::SetValue {
                node: check1,
                value: String::new(),
                checked: Some(true),
            })
            .unwrap();
        let html = drain(&mut events, "1 left");
        assert!(
            html.contains("class=\"completed\""),
            "checkbox toggle did not mark the todo completed: {html}"
        );

        // Delete the second todo (its destroy button reads "DEL-2").
        let del2 = marker_for(&html, "DEL-2");
        handle.cmds.blocking_send(PageCmd::Click(del2)).unwrap();
        let html = drain(&mut events, "0 left");
        assert!(!html.contains("walk dog"), "deleted todo lingered: {html}");
        assert!(html.contains("buy milk"), "wrong todo deleted: {html}");
    }

    #[test]
    fn clicks_drive_an_onclick_counter() {
        let (handle, mut events) = live(
            "<body><h1 id=n>0</h1>\
             <button id=inc onclick=\"var n = document.getElementById('n'); \
             n.textContent = String(Number(n.textContent) + 1);\">+1</button>\
             <script>void 0;</script></body>",
        );
        let Some(PageEvt::Updated { html, .. }) = events.blocking_recv() else {
            panic!("expected first Updated");
        };
        // The button is followable: wrapped in a click marker.
        let marker = html
            .split("x-trust-js:")
            .nth(1)
            .and_then(|rest| rest.split(':').next())
            .expect("marker in extraction")
            .parse::<usize>()
            .unwrap();

        handle.cmds.blocking_send(PageCmd::Click(marker)).unwrap();
        let Some(PageEvt::Updated { html, outcome }) = events.blocking_recv() else {
            panic!("expected Updated after click");
        };
        assert!(outcome.errors.is_empty(), "{:?}", outcome.errors);
        assert!(html.contains(">1</h1>"), "{html}");

        handle.cmds.blocking_send(PageCmd::Click(marker)).unwrap();
        let Some(PageEvt::Updated { html, .. }) = events.blocking_recv() else {
            panic!("expected Updated after second click");
        };
        assert!(html.contains(">2</h1>"), "{html}");
    }

    #[test]
    fn scan_module_imports_finds_static_skips_dynamic() {
        let src = br#"
            import a from "./a.js";
            import { b } from '/b.js';
            export { c } from "../c.js";
            import "/side-effect.js";
            import x from `./tpl.js`;
            const r = import("./dynamic.js");
            const lazy = import(`./route-${name}.js`);
            import bare from "lodash";
        "#;
        let found = scan_module_imports(src);
        // Static, path-like specifiers — including a non-interpolated
        // backtick — are caught.
        for want in ["./a.js", "/b.js", "../c.js", "/side-effect.js", "./tpl.js"] {
            assert!(found.iter().any(|s| s == want), "missing {want}: {found:?}");
        }
        // Dynamic `import(...)` is deliberately skipped (router fan-out).
        assert!(
            !found.iter().any(|s| s == "./dynamic.js"),
            "dynamic import was scanned: {found:?}"
        );
        // Interpolated template specifiers are unpredictable — skipped.
        assert!(
            !found.iter().any(|s| s.contains("route-")),
            "interpolated specifier was scanned: {found:?}"
        );
        // Bare specifiers (no path) don't resolve here — skipped.
        assert!(
            !found.iter().any(|s| s == "lodash"),
            "bare specifier was scanned: {found:?}"
        );
    }

    #[test]
    fn resize_observer_callback_receives_entries() {
        // archive.org's SharedResizeObserver does `new ResizeObserver(e =>
        // requestAnimationFrame(() => { for (let t of e) ... }))`. If our
        // RO fires the callback without a real entries array (or the value
        // doesn't survive into the rAF closure), the for-of hits
        // ToObject(undefined) — the TypeError that drove Sentry. Pin it.
        let env = PageEnv::bare("https://example.com/");
        let html = r#"<body><div id=out>no</div><script>
            const ro = new ResizeObserver(e => {
                requestAnimationFrame(() => {
                    let n = 0; for (let t of e) { n++; }
                    document.getElementById('out').textContent = 'entries=' + n;
                });
            });
            ro.observe(document.body);
        </script></body>"#;
        let (out, outcome) = transform(html, &env);
        assert!(outcome.errors.is_empty(), "errors: {:?}", outcome.errors);
        assert!(out.contains("entries=1"), "RO entries not delivered: {out}");
    }

    #[test]
    fn this_in_doubly_nested_arrow_survives_capture() {
        // Minimal pin for the Boa `this`-escape fix (the archive.org /
        // SharedResizeObserver crash, distilled). A non-arrow function whose
        // ONLY reason to materialize a function environment is a `this`
        // referenced from a DOUBLY-nested arrow. The old escape analysis
        // marked the intermediate arrow scope (arrows never materialize for
        // `this`), so the enclosing function stayed un-materialized and `this`
        // resolved to the wrong (outer) environment — `f()` returned
        // undefined. No module/ResizeObserver/Sentry needed: this is pure
        // engine scoping.
        let env = PageEnv::bare("https://example.com/");
        let (out, outcome) = transform(
            r#"<body><div id=out>no</div><script>
                function Outer() {
                    this.v = 42;
                    this.make = () => () => this.v;
                }
                document.getElementById('out').textContent =
                    'val ' + (new Outer().make()());
            </script></body>"#,
            &env,
        );
        assert!(outcome.errors.is_empty(), "errors: {:?}", outcome.errors);
        assert!(out.contains("val 42"), "this lost in nested arrow: {out}");
    }

    // Regression (2026-06-16): archive.org's `SharedResizeObserver`, wrapped by
    // Sentry's `Ti` function-instrumentation, threw "cannot convert undefined
    // to object". Faithful shape: a MODULE with `var t=class{…},n=e(…)`, a
    // `new ResizeObserver(e => rAF(() => { for (let t of e) this.…(t.target) }))`,
    // and Sentry's `Ti` wrapping of setTimeout/rAF. Root cause was NOT the
    // captured `e` (it resolves fine) but the inner arrow's `this`: a `this`
    // read from a doubly-nested arrow escaped onto the intermediate arrow scope
    // instead of the class constructor, so the constructor never materialized
    // and `this.resizeHandlers` was a property access on `undefined`. Fixed in
    // the Boa fork's scope analyzer (arrow scopes are skipped when escaping
    // `this`). See `this_in_doubly_nested_arrow_survives_capture` for the
    // distilled case. Librewolf: 0 errors.
    #[test]
    fn sentry_wrapped_resize_observer_keeps_captured_entries() {
        let env = PageEnv::bare("https://example.com/");
        env.cache.seed(
            String::from("https://example.com/lib.js"),
            200,
            String::from("text/javascript"),
            b"export const n = (o) => o;".to_vec(),
        );
        env.cache.seed(
            String::from("https://example.com/main.js"),
            200,
            String::from("text/javascript"),
            br#"import { n as e } from './lib.js';
                function Ti(fn){
                    if (typeof fn !== 'function') return fn;
                    if (fn.__sentry_wrapped__) return fn.__sentry_wrapped__;
                    const r = function(){ const m = Array.prototype.map.call(arguments, x => Ti(x)); return fn.apply(this, m); };
                    try { for (let k in fn) if (Object.prototype.hasOwnProperty.call(fn,k)) r[k]=fn[k]; } catch(_){}
                    try { Object.defineProperty(fn, '__sentry_wrapped__', { value: r, configurable: true }); } catch(_){}
                    return r;
                }
                function fill(o,n,repl){ o[n]=repl(o[n]); }
                fill(globalThis,'requestAnimationFrame', o => function(cb){ return o.apply(this,[Ti(cb)]); });
                fill(globalThis,'setTimeout', o => function(){ arguments[0]=Ti(arguments[0]); return o.apply(this,arguments); });
                var t = class {
                    constructor() {
                        this.resizeObserver = new ResizeObserver(e => {
                            window.requestAnimationFrame(() => {
                                for (let t of e) this.resizeHandlers.get(t.target);
                                document.getElementById('out').textContent = 'looped ' + e.length;
                            });
                        });
                        this.resizeHandlers = new Map();
                    }
                    add(el) { this.resizeHandlers.set(el, 1); this.resizeObserver.observe(el); }
                }, n = e({ SharedResizeObserver: () => t });
                new t().add(document.body);"#
                .to_vec(),
        );
        let (out, outcome) = transform(
            "<body><div id=out>no</div>\
             <script type=module src='/main.js'></script></body>",
            &env,
        );
        assert!(outcome.errors.is_empty(), "errors: {:?}", outcome.errors);
        assert!(out.contains("looped 1"), "captured RO entries lost: {out}");
    }

    #[test]
    fn preloaded_modules_run_without_network() {
        // The parallel-prefetch contract: bodies seeded into the shared
        // cache serve the module graph — entry AND imports — with no net
        // grant at all.
        let env = PageEnv::bare("https://example.com/");
        env.cache.seed(
            String::from("https://example.com/main.js"),
            200,
            String::from("text/javascript"),
            b"import { x } from './lib.js';\
              document.getElementById('t').textContent = x;"
                .to_vec(),
        );
        env.cache.seed(
            String::from("https://example.com/lib.js"),
            200,
            String::from("text/javascript"),
            b"export const x = 'preloaded graph';".to_vec(),
        );
        let (out, outcome) = transform(
            "<body><div id=t></div>\
             <script type=module src='/main.js'></script></body>",
            &env,
        );
        assert!(outcome.errors.is_empty(), "{:?}", outcome.errors);
        assert_eq!(outcome.modules_skipped, 0);
        assert!(out.contains("preloaded graph"), "{out}");
    }

    #[test]
    fn wide_module_fanout_runs_instead_of_falling_back() {
        // Regression for the removed import/preload caps: an entry module
        // that statically imports 30 modules (a 31-preload graph) used to be
        // SKIPPED wholesale (`MAX_SAFE_MODULE_IMPORTS`/`MAX_SAFE_MODULE_PRELOADS`
        // = 24) and the page fell back to un-transformed HTML — the blunt
        // workaround for Boa's cyclic-module crash. With the Boa fork making
        // that crash a catchable panic instead, a wide *acyclic* graph like
        // this must just run.
        const N: usize = 30;
        let env = PageEnv::bare("https://example.com/");
        let mut imports = String::new();
        let mut sum = String::new();
        for i in 0..N {
            imports.push_str(&format!("import {{ v as v{i} }} from './m{i}.js';\n"));
            if i > 0 {
                sum.push('+');
            }
            sum.push_str(&format!("v{i}"));
            env.cache.seed(
                format!("https://example.com/m{i}.js"),
                200,
                String::from("text/javascript"),
                format!("export const v = {i};").into_bytes(),
            );
        }
        env.cache.seed(
            String::from("https://example.com/main.js"),
            200,
            String::from("text/javascript"),
            format!("{imports}document.getElementById('t').textContent = 'sum=' + ({sum});")
                .into_bytes(),
        );

        let (out, outcome) = transform(
            "<body><div id=t></div>\
             <script type=module src='/main.js'></script></body>",
            &env,
        );
        assert!(outcome.errors.is_empty(), "{:?}", outcome.errors);
        assert_eq!(outcome.modules_skipped, 0);
        // 0 + 1 + ... + 29 = 435.
        assert!(out.contains("sum=435"), "{out}");
    }

    #[test]
    fn dynamic_import_of_a_statically_imported_module_does_not_halt() {
        // Boa-fork regression (vm/opcode/call/mod.rs `load_dyn_import`): the
        // `Referrer::Module` arm shadowed the loaded `module` with the REFERRER
        // module, so a dynamic `import()` of a specifier ALSO statically imported
        // recorded/asserted the wrong module — tripping a `debug_assert_eq!` that
        // halted ALL page JS (archive.org's `import('…/app-services-*.js')`). The
        // fork renames the binding so the LOADED module is used, like the
        // Realm/Script arms. `cargo test` is a debug build, so the assert is live
        // here: before the fix this page reported an "engine panic" error.
        let env = PageEnv::bare("https://example.com/");
        env.cache.seed(
            String::from("https://example.com/dep.js"),
            200,
            String::from("text/javascript"),
            b"export const v = 42;".to_vec(),
        );
        env.cache.seed(
            String::from("https://example.com/main.js"),
            200,
            String::from("text/javascript"),
            b"import { v } from './dep.js';\n\
              import('./dep.js').then(m => {\n\
                document.getElementById('t').textContent = 'static=' + v + ' dynamic=' + m.v;\n\
              });"
            .to_vec(),
        );
        let (out, outcome) = transform(
            "<body><div id=t></div>\
             <script type=module src='/main.js'></script></body>",
            &env,
        );
        assert!(outcome.errors.is_empty(), "{:?}", outcome.errors);
        assert!(out.contains("static=42 dynamic=42"), "{out}");
    }

    #[test]
    fn adopted_stylesheets_hide_through_the_cascade() {
        // Both adoption orders: replaceSync-then-adopt (Lit's shape)
        // and adopt-then-replaceSync (needs the sheet→scope re-sync).
        let (out, outcome) = page(
            r##"<body><div id=host></div><p class=light>light target</p>
            <p>stays</p><script>
            const host = document.getElementById('host');
            const root = host.attachShadow({ mode: 'open' });
            root.innerHTML = '<p class="sec">shadow secret</p><p>shadow public</p>';
            const sheet = new CSSStyleSheet();
            sheet.replaceSync('.sec { display: none }');
            root.adoptedStyleSheets = [sheet];
            const docSheet = new CSSStyleSheet();
            document.adoptedStyleSheets = [docSheet];
            docSheet.replaceSync('.light { display: none }');
            </script></body>"##,
        );
        assert!(outcome.errors.is_empty(), "{:?}", outcome.errors);
        assert!(!out.contains("shadow secret"), "{out}");
        assert!(out.contains("shadow public"), "{out}");
        assert!(!out.contains("light target"), "{out}");
        assert!(out.contains("stays"), "{out}");
    }

    #[test]
    fn style_element_insert_rule_reaches_the_cascade() {
        // styled-components / CSS-in-JS "speedy" mode injects ALL its CSS via
        // styleEl.sheet.insertRule(), leaving the <style> text node EMPTY. Our
        // Rust cascade reads <style> text, so a <style>-owned sheet must mirror
        // its joined rules back into the element — else every flex/grid rule is
        // invisible and a styled-components page (Twitch) collapses to one block
        // column. Also pins insert-at-index and delete-at-index (cascade order
        // is load-bearing): a later `.gone{display:block}` would WIN over the
        // earlier `display:none`, so a working deleteRule is what keeps it hidden.
        let (out, outcome) = page(
            r##"<head><style id=sc></style></head><body>
            <p class=gone>hide me</p><p class=keep>keep me</p>
            <script>
            const sheet = document.getElementById('sc').sheet;
            sheet.insertRule('.gone { display: none }', 0);
            sheet.insertRule('.keep { display: block }', 0);   // prepend (mid-insert)
            sheet.insertRule('.gone { display: block }', 2);   // append: would un-hide
            sheet.deleteRule(2);                               // remove it: .gone stays hidden
            </script></body>"##,
        );
        assert!(outcome.errors.is_empty(), "{:?}", outcome.errors);
        assert!(!out.contains("hide me"), "{out}");
        assert!(out.contains("keep me"), "{out}");
    }

    #[test]
    fn live_click_moves_active_tab_border_via_cascade_rebake() {
        // A tab UI on a living page: clicking the inactive tab moves the
        // `selected` class, and the re-serialization RE-BAKES the cascade so
        // the active border follows — the new tab gains `border-bottom:4px`,
        // the old one drops to `1px`. This is the SL Marketplace tab case.
        let (handle, mut events) = live(
            "<head><style>.tab{border-bottom:1px solid}.tab.selected{border-bottom:4px solid}</style></head>\
             <body>\
             <a href=\"#\" class=tablink><div class=\"tab selected\" id=t1>Items</div></a>\
             <a href=\"#\" class=tablink><div class=tab id=t2>Merchants</div></a>\
             <script>\
             document.querySelectorAll('.tablink').forEach(function(a){\
               a.addEventListener('click', function(e){\
                 e.preventDefault();\
                 document.querySelectorAll('.tab').forEach(function(d){d.classList.remove('selected');});\
                 a.querySelector('.tab').classList.add('selected');\
               });\
             });</script></body>",
        );
        // The baked border-bottom width on the tab div with the given id.
        let border_of = |html: &str, id: &str| -> String {
            let at = html.find(&format!("id=\"{id}\"")).expect("tab present");
            let style_at = html[at..].find("style=\"").expect("baked style") + at + 7;
            let end = html[style_at..].find('"').unwrap() + style_at;
            html[style_at..end]
                .split(';')
                .find_map(|d| {
                    d.trim()
                        .strip_prefix("border-bottom-width:")
                        .map(str::to_string)
                })
                .unwrap_or_default()
        };
        let Some(PageEvt::Updated { html, .. }) = events.blocking_recv() else {
            panic!("expected first Updated");
        };
        assert_eq!(border_of(&html, "t1"), "4px", "Items starts active");
        assert_eq!(border_of(&html, "t2"), "1px", "Merchants starts inactive");

        let at = html.find("Merchants").unwrap();
        let marker = html[..at]
            .rfind("x-trust-js:")
            .map(|i| {
                html[i + "x-trust-js:".len()..]
                    .split(':')
                    .next()
                    .unwrap()
                    .parse::<usize>()
                    .unwrap()
            })
            .unwrap();
        handle.cmds.blocking_send(PageCmd::Click(marker)).unwrap();
        let Some(PageEvt::Updated { html, outcome }) = events.blocking_recv() else {
            panic!("expected Updated after click");
        };
        assert!(outcome.errors.is_empty(), "{:?}", outcome.errors);
        assert_eq!(
            border_of(&html, "t1"),
            "1px",
            "Items deactivated after click"
        );
        assert_eq!(border_of(&html, "t2"), "4px", "Merchants now active");
    }

    #[test]
    fn clicking_a_submit_button_fires_the_form_submit() {
        // A live <button type=submit> reaches the app as a JsClick (the live
        // serializer wraps every button). Clicking it must run the form-
        // submission algorithm so the form's own `submit` handler (React's
        // onSubmit is bound on the <form>, not the button) fires — pixiv's
        // login button did "nothing" because only a bare click event went out.
        let (handle, mut events) = live(
            "<body><form id=f><input name=q><button type=submit>Go</button></form>\
             <pre id=out>idle</pre><script>\
             document.getElementById('f').addEventListener('submit', function (e) {\
                 e.preventDefault();\
                 document.getElementById('out').textContent = 'submitted:' + (e.submitter ? e.submitter.textContent : 'none');\
             });</script></body>",
        );
        let Some(PageEvt::Updated { html, .. }) = events.blocking_recv() else {
            panic!("live form should keep the actor resident");
        };
        let button = live_node_after(&html, "<button");
        handle.cmds.blocking_send(PageCmd::Click(button)).unwrap();
        // Submit was prevented → the page owns the update; the handler ran and
        // saw the submitter, and the app is NOT asked to navigate.
        let html2 = loop {
            match events.blocking_recv() {
                Some(PageEvt::Updated { html, .. }) => break html,
                Some(PageEvt::Settled) => continue,
                other => panic!("expected the prevented submit to re-render, got {other:?}"),
            }
        };
        assert!(html2.contains("submitted:Go"), "{html2}");
    }

    #[test]
    fn clicking_a_submit_button_without_a_handler_asks_the_app_to_submit() {
        // A LIVE page (has JS) whose <form> has NO `submit` handler: a click on
        // its submit button fires an un-prevented submit, so the app runs the
        // native GET/POST (the event carries the form + submitter nodes). The
        // button's own click listener doesn't preventDefault — it just makes
        // the page live so the button reaches the app as a JsClick.
        let (handle, mut events) = live(
            "<body><form action=\"/go\"><input name=q value=hi>\
             <button type=submit>Go</button></form>\
             <script>document.querySelector('button').addEventListener('click', function () {});</script></body>",
        );
        let Some(PageEvt::Updated { html, .. }) = events.blocking_recv() else {
            panic!("a live form keeps the actor resident");
        };
        let at = html.find("Go").expect("button label");
        let button = html[..at]
            .rfind("x-trust-js:")
            .map(|i| {
                html[i + "x-trust-js:".len()..]
                    .split(':')
                    .next()
                    .unwrap()
                    .parse::<usize>()
                    .unwrap()
            })
            .expect("button marker");
        handle.cmds.blocking_send(PageCmd::Click(button)).unwrap();
        match events.blocking_recv() {
            Some(PageEvt::SubmitForm { .. }) => {}
            other => {
                panic!("unprevented submit-button click should ask app to submit, got {other:?}")
            }
        }
    }

    fn live_node_after(html: &str, marker: &str) -> usize {
        let start = html.find(marker).expect("marker in live html");
        let rest = &html[start..];
        let attr = "data-trust-node=\"";
        let attr_start = rest.find(attr).expect("live node attr") + attr.len();
        let rest = &rest[attr_start..];
        let attr_end = rest.find('"').expect("attr end");
        rest[..attr_end].parse().expect("node id")
    }

    #[test]
    fn live_form_input_sets_dom_and_fires_input_change() {
        let (handle, mut events) = live(
            "<body><form><input name=msg><p id=out></p></form>\
             <script>\
             const msg = document.querySelector('input');\
             const out = document.getElementById('out');\
             const log = [];\
             msg.addEventListener('input', function () { log.push('input:' + msg.value); });\
             msg.addEventListener('change', function () { log.push('change:' + msg.value); out.textContent = log.join('|'); });\
             </script></body>",
        );
        let Some(PageEvt::Updated { html, .. }) = events.blocking_recv() else {
            panic!("live form should keep the actor resident");
        };
        let input = live_node_after(&html, "name=\"msg\"");
        handle
            .cmds
            .blocking_send(PageCmd::SetValue {
                node: input,
                value: String::from("hello"),
                checked: None,
            })
            .unwrap();
        let Some(PageEvt::Updated { html, .. }) = events.blocking_recv() else {
            panic!("form edit should render an update");
        };
        assert!(html.contains("value=\"hello\""), "{html}");
        assert!(
            html.contains("input:hello|change:hello"),
            "input/change fired in order: {html}"
        );
    }

    #[test]
    fn live_form_submit_prevent_default_updates_in_place() {
        let (handle, mut events) = live(
            "<body><form><input name=msg value=hi><button type=submit value=go>Send</button><p id=out></p></form>\
             <script>\
             const form = document.querySelector('form');\
             form.addEventListener('submit', function (event) {\
               event.preventDefault();\
               document.getElementById('out').textContent = 'submit:' + form.querySelector('input').value + ':' + event.submitter.value;\
             });\
             </script></body>",
        );
        let Some(PageEvt::Updated { html, .. }) = events.blocking_recv() else {
            panic!("live form should keep the actor resident");
        };
        let form = live_node_after(&html, "<form");
        let button = live_node_after(&html, "<button");
        handle
            .cmds
            .blocking_send(PageCmd::Submit {
                form,
                submitter: Some(button),
            })
            .unwrap();
        let Some(PageEvt::Updated { html, .. }) = events.blocking_recv() else {
            panic!("prevented submit should update in place");
        };
        assert!(html.contains("submit:hi:go"), "{html}");
    }

    #[test]
    fn live_form_submit_default_falls_back_to_app() {
        let (handle, mut events) = live(
            "<body><form><input name=msg value=hi><button type=submit>Send</button></form><script>document.body.dataset.ready='1';</script></body>",
        );
        let Some(PageEvt::Updated { html, .. }) = events.blocking_recv() else {
            panic!("live form should keep the actor resident");
        };
        let form = live_node_after(&html, "<form");
        let button = live_node_after(&html, "<button");
        handle
            .cmds
            .blocking_send(PageCmd::Submit {
                form,
                submitter: Some(button),
            })
            .unwrap();
        match events.blocking_recv() {
            Some(PageEvt::SubmitDefault) => {}
            other => panic!("unprevented submit should ask app to submit, got {other:?}"),
        }
    }

    #[test]
    fn live_click_toggles_stylesheet_class_visibility() {
        // The CSS step-1 payoff on a living page: a click that flips a
        // class genuinely expands and collapses the panel.
        let (handle, mut events) = live(
            "<head><style>.panel{display:none}.panel.open{display:block}</style></head>\
             <body><button id=b onclick=\"document.getElementById('p')\
             .classList.toggle('open')\">toggle</button>\
             <div id=p class=panel>panel payload</div>\
             <script>void 0;</script></body>",
        );
        let Some(PageEvt::Updated { html, .. }) = events.blocking_recv() else {
            panic!("expected first Updated");
        };
        assert!(!html.contains("panel payload"), "{html}");
        let marker = html
            .split("x-trust-js:")
            .nth(1)
            .and_then(|rest| rest.split(':').next())
            .expect("marker in extraction")
            .parse::<usize>()
            .unwrap();

        handle.cmds.blocking_send(PageCmd::Click(marker)).unwrap();
        let Some(PageEvt::Updated { html, outcome }) = events.blocking_recv() else {
            panic!("expected Updated after click");
        };
        assert!(outcome.errors.is_empty(), "{:?}", outcome.errors);
        assert!(html.contains("panel payload"), "{html}");

        handle.cmds.blocking_send(PageCmd::Click(marker)).unwrap();
        let Some(PageEvt::Updated { html, .. }) = events.blocking_recv() else {
            panic!("expected Updated after second click");
        };
        assert!(!html.contains("panel payload"), "{html}");
    }

    #[test]
    fn a_mutationless_click_emits_nothing() {
        let (handle, mut events) = live(
            "<body><h1 id=n>0</h1><div id=noop></div><div id=real></div><script>\
             document.getElementById('noop').addEventListener('click', function () {});\
             document.getElementById('real').addEventListener('click', function () {\
               document.getElementById('n').textContent = 'changed';\
             });</script></body>",
        );
        let Some(PageEvt::Updated { html, .. }) = events.blocking_recv() else {
            panic!("expected first Updated");
        };
        let id_of = |html: &str, anchor_text: &str| -> usize {
            // Find the marker wrapping the element whose id attr matches.
            let at = html.find(anchor_text).unwrap();
            html[..at]
                .rfind("x-trust-js:")
                .map(|i| {
                    html[i + "x-trust-js:".len()..]
                        .split(':')
                        .next()
                        .unwrap()
                        .parse::<usize>()
                        .unwrap()
                })
                .unwrap()
        };
        let noop = id_of(&html, "id=\"noop\"");
        let real = id_of(&html, "id=\"real\"");

        // Dispatch the no-op first: it acknowledges completion without
        // an Updated render, so the dirty bit still held.
        handle.cmds.blocking_send(PageCmd::Click(noop)).unwrap();
        match events.blocking_recv() {
            Some(PageEvt::Settled) => {}
            other => panic!("no-op click should only settle, got {other:?}"),
        }
        handle.cmds.blocking_send(PageCmd::Click(real)).unwrap();
        let Some(PageEvt::Updated { html, .. }) = events.blocking_recv() else {
            panic!("expected Updated from the mutating click");
        };
        assert!(html.contains("changed"), "{html}");
    }

    #[test]
    fn hover_dispatches_the_pointer_events_sequence() {
        // The Pointer Events transition order on old→new (which absorbed the
        // UI Events mouse section): out (bubbling) → leave (per element,
        // bottom-up to the exclusive common ancestor, NON-bubbling) → over
        // (bubbling) → enter (top-down, non-bubbling) → move; each pointer
        // event paired with its mouse compat twin; relatedTarget = the other
        // element of the pair. Bubbling types log at the document (they must
        // reach it); enter/leave log per element (they must NOT bubble).
        let (out, outcome) = page(
            r##"<body><div id=a><span id=b>b</span><span id=c>c</span></div>
            <div id=out></div><script>
            var log = [];
            function tag(el) { return el === null || el === undefined ? "0" : (el.id || el.localName || "win"); }
            function rec(e) { log.push(e.type + ":" + tag(e.target) + "~" + tag(e.relatedTarget)); }
            var bubbling = ["pointerover", "pointerout", "pointermove", "mouseover", "mouseout", "mousemove"];
            for (var i = 0; i < bubbling.length; i++) document.addEventListener(bubbling[i], rec);
            var edge = ["pointerenter", "pointerleave", "mouseenter", "mouseleave"];
            var els = ["a", "b", "c"];
            for (var j = 0; j < edge.length; j++) {
                for (var k = 0; k < els.length; k++) {
                    document.getElementById(els[k]).addEventListener(edge[j], rec);
                }
            }
            document.addEventListener("mousemove", function (e) { log.push("x" + e.clientX + "y" + e.clientY); });
            __trust.hover(document.getElementById("b").__id, 5, 7);
            __trust.hover(document.getElementById("c").__id, 6, 7);
            __trust.hover(null, 0, 0);
            document.getElementById("out").textContent = log.join(" ");
            </script></body>"##,
        );
        assert!(outcome.errors.is_empty(), "{:?}", outcome.errors);
        let expected = [
            // null → b: over(b), enter a then b (top-down), move(b).
            "pointerover:b~0",
            "mouseover:b~0",
            "pointerenter:a~0",
            "mouseenter:a~0",
            "pointerenter:b~0",
            "mouseenter:b~0",
            "pointermove:b~0",
            "mousemove:b~0",
            "x5y7",
            // b → c (common ancestor a): out(b), leave b ONLY, over(c),
            // enter c ONLY, move(c).
            "pointerout:b~c",
            "mouseout:b~c",
            "pointerleave:b~c",
            "mouseleave:b~c",
            "pointerover:c~b",
            "mouseover:c~b",
            "pointerenter:c~b",
            "mouseenter:c~b",
            "pointermove:c~0",
            "mousemove:c~0",
            "x6y7",
            // c → nothing: out(c), leave bottom-up (c then a; body/html/doc
            // have no listeners registered here).
            "pointerout:c~0",
            "mouseout:c~0",
            "pointerleave:c~0",
            "mouseleave:c~0",
            "pointerleave:a~0",
            "mouseleave:a~0",
        ]
        .join(" ");
        assert!(
            out.contains(&expected),
            "hover sequence mismatch:\n want …{expected}…\n got {out}"
        );
    }

    #[test]
    fn a_hover_only_page_stays_live_and_hover_dispatch_rerenders() {
        // A page whose ONLY listener is a hover type must keep its engine
        // (the auto-Static gate counts hover work), be marked with the
        // DEDICATED data-trust-hover attribute (never data-trust-node — that
        // one gates incremental-layout boundaries), and re-render when a
        // hover handler mutates. A clear and a stale id settle silently.
        let (handle, mut events) = live(
            "<body><h1 id=t>idle</h1><div id=hot>hover me</div><script>\
             document.getElementById('hot').addEventListener('mouseover', function () {\
               document.getElementById('t').textContent = 'hovered';\
             });</script></body>",
        );
        let Some(PageEvt::Updated { html, .. }) = events.blocking_recv() else {
            panic!("hover-only page must stay live (Updated, not Static)");
        };
        let at = html
            .find("data-trust-hover=\"")
            .expect("hover host marked with data-trust-hover");
        let hot: usize = html[at + "data-trust-hover=\"".len()..]
            .split('"')
            .next()
            .unwrap()
            .parse()
            .unwrap();
        let hot_tag = {
            let tag_start = html[..at].rfind('<').unwrap();
            &html[tag_start..html[tag_start..].find('>').unwrap() + tag_start]
        };
        assert!(
            !hot_tag.contains("data-trust-node"),
            "hover host must not carry data-trust-node: {hot_tag}"
        );

        handle
            .cmds
            .blocking_send(PageCmd::Hover {
                node: Some(hot),
                x: 4.0,
                y: 8.0,
            })
            .unwrap();
        let Some(PageEvt::Updated { html, outcome }) = events.blocking_recv() else {
            panic!("mutating hover handler should re-render");
        };
        assert!(outcome.errors.is_empty(), "{:?}", outcome.errors);
        assert!(html.contains("hovered"), "{html}");

        // Clearing hover fires out/leave on the old chain — no listener, no
        // mutation, just a settle.
        handle
            .cmds
            .blocking_send(PageCmd::Hover {
                node: None,
                x: 0.0,
                y: 0.0,
            })
            .unwrap();
        match events.blocking_recv() {
            Some(PageEvt::Settled) => {}
            other => panic!("hover clear should settle, got {other:?}"),
        }
        // A stale node id (detached since the app's snapshot — routine on
        // re-rendering pages) degrades to a hover-clear, never a Trouble.
        handle
            .cmds
            .blocking_send(PageCmd::Hover {
                node: Some(99_999_999),
                x: 0.0,
                y: 0.0,
            })
            .unwrap();
        match events.blocking_recv() {
            Some(PageEvt::Settled) => {}
            other => panic!("stale hover id should settle silently, got {other:?}"),
        }
    }

    #[test]
    fn delegated_hover_reaches_an_ancestor_listener_by_bubbling() {
        // jQuery-delegation shape: the listener sits on a CONTAINER; the
        // committed target is a child. The bubbling mouseover pair (with
        // relatedTarget) is exactly what jQuery's mouseenter shim consumes.
        let (handle, mut events) = live(
            "<body><h1 id=t>idle</h1>\
             <div id=list><span id=kid>row</span></div><script>\
             var kid = document.getElementById('kid');\
             kid.setAttribute('data-kid-id', kid.__id);\
             document.getElementById('list').addEventListener('mouseover', function (e) {\
               document.getElementById('t').textContent = 'saw:' + (e.target.id || '?');\
             });</script></body>",
        );
        let Some(PageEvt::Updated { html, .. }) = events.blocking_recv() else {
            panic!("expected first Updated");
        };
        let at = html.find("data-kid-id=\"").expect("kid id baked");
        let kid: usize = html[at + "data-kid-id=\"".len()..]
            .split('"')
            .next()
            .unwrap()
            .parse()
            .unwrap();
        handle
            .cmds
            .blocking_send(PageCmd::Hover {
                node: Some(kid),
                x: 1.0,
                y: 1.0,
            })
            .unwrap();
        let Some(PageEvt::Updated { html, outcome }) = events.blocking_recv() else {
            panic!("delegated hover should re-render");
        };
        assert!(outcome.errors.is_empty(), "{:?}", outcome.errors);
        assert!(
            html.contains("saw:kid"),
            "delegated listener saw the child target: {html}"
        );
    }

    #[test]
    fn media_play_rejects_not_allowed_without_erroring_the_page() {
        // HTMLMediaElement: we never play inline, so play() reports the
        // spec's "not allowed to play" — a NotAllowedError rejection, the
        // same signal a real browser's blocked autoplay gives. The element
        // stays paused, and an UNCAUGHT play() must not count as a page
        // error (browsers only console-warn) — the rejection is pre-observed.
        let (out, outcome) = page(
            r##"<body><video id=v></video><div id=out></div><script>
            var v = document.getElementById('v');
            v.play().catch(function (e) {
                document.getElementById('out').textContent = 'name:' + e.name + ' paused:' + v.paused;
            });
            document.createElement('video').play(); // uncaught: no page error
            </script></body>"##,
        );
        assert!(outcome.errors.is_empty(), "{:?}", outcome.errors);
        assert!(
            out.contains("name:NotAllowedError paused:true"),
            "play() must reject NotAllowedError: {out}"
        );
    }

    #[test]
    fn a_rejected_play_lets_a_sites_hover_fallback_keep_the_image() {
        // Steam's sale-capsule microtrailer shape: first mouseenter mounts a
        // <video>, adds the image-hiding class, and calls play(); the site's
        // OWN rejection handler removes the class (the autoplay-blocked
        // fallback every hover-preview site carries since Chrome's policy).
        // With the old lying `Promise.resolve()` the class stayed on forever:
        // image hidden, unpaintable video shown, capsule destroyed — and the
        // teardown never ran, so hovering away didn't restore it either.
        let (handle, mut events) = live(
            "<body><div id=cap class=plain><img id=i src=/cap.jpg alt=capsule></div><script>\
             var cap = document.getElementById('cap');\
             cap.addEventListener('mouseenter', function () {\
               cap.className = 'with_microtrailer';\
               var v = document.createElement('video');\
               cap.appendChild(v);\
               v.play().catch(function () { cap.className = 'plain restored'; });\
             });</script></body>",
        );
        let Some(PageEvt::Updated { html, .. }) = events.blocking_recv() else {
            panic!("hover-listener page stays live");
        };
        let at = html
            .find("data-trust-hover=\"")
            .expect("capsule marked as hover host");
        let cap: usize = html[at + "data-trust-hover=\"".len()..]
            .split('"')
            .next()
            .unwrap()
            .parse()
            .unwrap();
        handle
            .cmds
            .blocking_send(PageCmd::Hover {
                node: Some(cap),
                x: 2.0,
                y: 2.0,
            })
            .unwrap();
        let Some(PageEvt::Updated { html, outcome }) = events.blocking_recv() else {
            panic!("the mount + fallback should re-render");
        };
        assert!(outcome.errors.is_empty(), "{:?}", outcome.errors);
        assert!(
            html.contains("plain restored"),
            "the site's rejection fallback must run and restore the class: {html}"
        );
        assert!(
            !html.contains("with_microtrailer"),
            "the image-hiding class must not survive the rejected play: {html}"
        );
    }

    #[test]
    fn render_canonical_strips_non_rendered_attrs() {
        // Two serializations differing ONLY in non-rendered attributes
        // (alt/class/title/aria-*) are the same render — the baked `style`
        // carries every layout effect. (Differing `style`/`src`/text are NOT.)
        let a = r#"<img src="/a.png" alt="Alpha" class="x tw-transition" title="t" aria-label="A" style="width:10px">x"#;
        let b = r#"<img src="/a.png" alt="Beta" class="y tw-active" title="u" aria-label="B" style="width:10px">x"#;
        assert_eq!(render_canonical(a), render_canonical(b));
        // A real change (style / src / text) still differs.
        let c = r#"<img src="/a.png" alt="Alpha" class="x" title="t" style="width:20px">x"#;
        let d = r#"<img src="/b.png" alt="Alpha" class="x" title="t" style="width:10px">y"#;
        assert_ne!(render_canonical(a), render_canonical(c));
        assert_ne!(render_canonical(a), render_canonical(d));
    }

    #[test]
    fn an_alt_only_mutation_does_not_re_render() {
        // A click that changes ONLY a non-rendered attribute — an image's `alt`
        // text, which Twitch rotates a co-streamer's name through every second —
        // must NOT re-render: `render_canonical` drops `alt`, so what we paint is
        // unchanged and the actor SETTLES instead of emitting an Updated (which
        // would re-parse + re-lay-out the whole doc — the CPU spin / 1s freeze).
        let (handle, mut events) = live(
            "<body><img id=av src=\"/a.png\" alt=\"Alpha\"><div id=hit></div><script>\
             document.getElementById('hit').addEventListener('click', function () {\
               document.getElementById('av').setAttribute('alt', 'Beta');\
             });</script></body>",
        );
        let Some(PageEvt::Updated { html, .. }) = events.blocking_recv() else {
            panic!("expected first Updated");
        };
        let at = html.find("id=\"hit\"").expect("hit div present");
        let hit: usize = html[..at]
            .rfind("x-trust-js:")
            .and_then(|i| {
                html[i + "x-trust-js:".len()..]
                    .split(':')
                    .next()?
                    .parse()
                    .ok()
            })
            .expect("hit marker");
        handle.cmds.blocking_send(PageCmd::Click(hit)).unwrap();
        match events.blocking_recv() {
            Some(PageEvt::Settled) => {}
            other => panic!("an alt-only change must only settle, got {other:?}"),
        }
    }

    #[test]
    fn live_anchor_clicks_navigate_unless_prevented() {
        let (handle, mut events) = live(
            "<body><a id=go href=\"../next\">go</a>\
             <a id=stay href=\"/nowhere\">stay</a><script>\
             document.getElementById('go').addEventListener('click', function () {});\
             document.getElementById('stay').addEventListener('click', function (e) {\
               e.preventDefault();\
               document.body.appendChild(document.createTextNode('prevented!'));\
             });</script></body>",
        );
        let Some(PageEvt::Updated { html, .. }) = events.blocking_recv() else {
            panic!("expected first Updated");
        };
        // Both anchors carry rewritten hrefs preserving the original.
        assert!(html.contains("x-trust-js:"), "{html}");
        assert!(html.contains(":../next"), "{html}");
        let id_for = |needle: &str| {
            let at = html.find(needle).unwrap();
            html[..at].rfind("x-trust-js:").map(|i| {
                html[i + "x-trust-js:".len()..]
                    .split(':')
                    .next()
                    .unwrap()
                    .parse::<usize>()
                    .unwrap()
            })
        };
        let go = id_for(">go</a>").unwrap();
        let stay = id_for(">stay</a>").unwrap();

        // preventDefault: the page mutates instead of navigating.
        handle.cmds.blocking_send(PageCmd::Click(stay)).unwrap();
        match events.blocking_recv() {
            Some(PageEvt::Updated { html, .. }) => {
                assert!(html.contains("prevented!"), "{html}")
            }
            other => panic!("expected Updated, got {other:?}"),
        }

        // No prevention: resolved against the page URL.
        handle.cmds.blocking_send(PageCmd::Click(go)).unwrap();
        match events.blocking_recv() {
            Some(PageEvt::Navigate(url)) => {
                assert_eq!(url, "https://example.com/next");
            }
            other => panic!("expected Navigate, got {other:?}"),
        }
    }

